import { PublicCard } from '../../../types';

export const physicsCards: PublicCard[] = [
  { id: 'dc-physics-0001', deck_id: 'deck-physics', sort_order: 1, front: "Newton's First Law", back: "An object at rest stays at rest, and an object in motion stays in motion at constant velocity, unless acted upon by a net external force. Also called the law of inertia." , front_translations: {"es":"Primera Ley de Newton","it":"Prima legge di Newton","de":"Erstes Newtonsches Gesetz","fr":"Première loi de Newton","tr":"Newton'un Birinci Yasası","nl":"Eerste wet van Newton","ru":"Первый закон Ньютона","zh":"牛顿第一定律","pt_BR":"Primeira Lei de Newton","pt_PT":"Primeira Lei de Newton"}, back_translations: {"es":"Un objeto en reposo permanece en reposo, y un objeto en movimiento permanece en movimiento con velocidad constante, a menos que una fuerza externa resultante atue sobre ele. También llamada de ley de la inércia.","it":"Un objet al repos reste al repos, e un objet en mouvement continue à se deplacer à vitesse costante, sauf se una force exterieure nette agit su lui. Egalement chiamatoe loi d'inertie.","de":"Ein ruhender Körper bleibt in Ruhe, und ein bewegter Körper bewegt sich mit konstanter Geschwindigkeit weiter, solange keine resultierende äußere Kraft auf ihn wirkt. Auch als Trägheitsgesetz bekannt.","fr":"Un objet au repos reste au repos, et un objet en mouvement continue à se déplacer à vitesse constante, sauf si une force extérieure nette agit sur lui. Également appelée loi d'inertie.","tr":"Duran bir cisim durmaya devam eder ve hareket eden bir cisim, üzerine net bir dış kuvvet etki etmedikçe sabit hızla hareket etmeye devam eder. Eylemsizlik yasası olarak da bilinir.","nl":"Een object in rust blijft in rust, en een object in beweging blijft bewegen met constante snelheid, tenzij er een nettokracht van buiten op inwerkt. Ook wel de wet van traagheid genoemd.","ru":"Тело, находящееся в покое, остаётся в покое, а тело в движении продолжает двигаться с постоянной скоростью, если на него не действует результирующая внешняя сила. Также называется законом инерции.","zh":"静止的物体保持静止，运动中的物体以恒定速度保持运动，除非有净外力作用于它。也称为惯性定律。","pt_BR":"Um objeto em repouso permanece em repouso, e um objeto em movimento permanece em movimento com velocidade constante, a menos que uma força externa resultante atue sobre ele. Também chamada de lei da inércia.","pt_PT":"Um objeto em repouso permanece em repouso, e um objeto em movimento mantém-se em movimento com velocidade constante, a menos que uma força externa resultante atue sobre ele. Também designada por lei da inércia."}},
  { id: 'dc-physics-0002', deck_id: 'deck-physics', sort_order: 2, front: "Newton's Second Law", back: "F = ma. The net force on an object equals its mass multiplied by its acceleration. The direction of the force is the same as the direction of acceleration." , front_translations: {"es":"Segunda Ley de Newton","it":"Seconda legge di Newton","de":"Zweites Newtonsches Gesetz","fr":"Deuxième loi de Newton","tr":"Newton'un İkinci Yasası","nl":"Tweede wet van Newton","ru":"Второй закон Ньютона","zh":"牛顿第二定律","pt_BR":"Segunda Lei de Newton","pt_PT":"Segunda Lei de Newton"}, back_translations: {"es":"F = ma. La fuerza resultante sobre un objeto es igual a la su masa multiplicada por la su aceleración. La dirección de la fuerza es a misma que a de la aceleración.","it":"F = ma. La force nette su un objet e egale alla sua masse multipliee per il suo accelerazione. La direczione della force e identico à celle dell'accelerazione.","de":"F = ma. Die Nettokraft auf einen Körper ist gleich seiner Masse multipliziert mit seiner Beschleunigung. Die Richtung der Kraft entspricht der Richtung der Beschleunigung.","fr":"F = ma. La force nette sur un objet est égale à sa masse multipliée par son accélération. La direction de la force est identique à celle de l'accélération.","tr":"F = ma. Bir cisim üzerindeki net kuvvet, kütlesi ile ivmesinin çarpımına eşittir. Kuvvetin yönü ivmenin yönüyle aynıdır.","nl":"F = ma. De nettokracht op een object is gelijk aan zijn massa maal zijn versnelling. De richting van de kracht is dezelfde als die van de versnelling.","ru":"F = ma. Результирующая сила, действующая на тело, равна произведению его массы на ускорение. Направление силы совпадает с направлением ускорения.","zh":"F = ma。物体所受的合力等于其质量乘以加速度。力的方向与加速度方向相同。","pt_BR":"F = ma. A força resultante sobre um objeto é igual à sua massa multiplicada pela sua aceleração. A direção da força é a mesma que a da aceleração.","pt_PT":"F = ma. A força resultante sobre um objeto é igual à sua massa multiplicada pela sua aceleração. A direção da força é a mesma que a da aceleração."}},
  { id: 'dc-physics-0003', deck_id: 'deck-physics', sort_order: 3, front: "Newton's Third Law", back: "For every action, there is an equal and opposite reaction. When object A exerts a force on object B, object B exerts an equal force in the opposite direction on object A." , front_translations: {"es":"Tercera Ley de Newton","it":"Terza legge di Newton","de":"Drittes Newtonsches Gesetz","fr":"Troisième loi de Newton","tr":"Newton'un Üçüncü Yasası","nl":"Derde wet van Newton","ru":"Третий закон Ньютона","zh":"牛顿第三定律","pt_BR":"Terceira Lei de Newton","pt_PT":"Terceira Lei de Newton"}, back_translations: {"es":"Para toda acción, hay una reacción igual y oposta. Cuando el objeto A exerce una fuerza sobre el objeto B, el objeto B exerce una fuerza igual en dirección oposta sobre el objeto A.","it":"A ogni aczione correspond una reazione egale e opposee. Lorsque l'objet A exerce una force su l'objet B, l'objet B exerce una force egale en sens oppose su l'objet A.","de":"Zu jeder Wirkung gibt es eine gleich große, entgegengesetzte Reaktion. Wenn Körper A eine Kraft auf Körper B ausübt, übt Körper B eine gleich große Kraft in entgegengesetzter Richtung auf Körper A aus.","fr":"À chaque action correspond une réaction égale et opposée. Lorsque l'objet A exerce une force sur l'objet B, l'objet B exerce une force égale en sens opposé sur l'objet A.","tr":"Her etkiye eşit ve zıt yönde bir tepki vardır. A cismi B cismüne bir kuvvet uyguladığında, B cismi de A cismine eşit büyüklükte ve zıt yönde bir kuvvet uygular.","nl":"Op elke actie volgt een gelijke en tegengestelde reactie. Wanneer object A een kracht uitoefent op object B, oefent object B een gelijke kracht in tegengestelde richting uit op object A.","ru":"На каждое действие существует равное и противоположное противодействие. Когда тело A действует с силой на тело B, тело B действует с равной силой в противоположном направлении на тело A.","zh":"每一个作用力都有一个大小相等、方向相反的反作用力。当A物体对B物体施力时，B物体也对A物体施加方向相反的等大力。","pt_BR":"Para toda ação, há uma reação igual e oposta. Quando o objeto A exerce uma força sobre o objeto B, o objeto B exerce uma força igual em direção oposta sobre o objeto A.","pt_PT":"Para toda ação existe uma reação igual e oposta. Quando o objeto A exerce uma força sobre o objeto B, o objeto B exerce uma força igual em sentido oposto sobre o objeto A."}},
  { id: 'dc-physics-0004', deck_id: 'deck-physics', sort_order: 4, front: "Law of Universal Gravitation", back: "F = Gm₁m₂/r². The gravitational force between two masses is proportional to the product of the masses and inversely proportional to the square of the distance between them." , front_translations: {"es":"Ley de la Gravitación Universal","it":"Legge di la gravitazione universale","de":"Gravitationsgesetz","fr":"Loi de la gravitation universelle","tr":"Evrensel Çekim Yasası","nl":"Wet van de universele zwaartekracht","ru":"Закон всемирного тяготения","zh":"万有引力定律","pt_BR":"Lei da Gravitação Universal","pt_PT":"Lei da Gravitação Universal"}, back_translations: {"es":"F = Gm₁m₂/r². La fuerza gravitacional entre de los massas es proporcional al producto de las massas y inversamente proporcional al cuadrado de la distancia entre elas.","it":"F = Gm₁m₂/r². La force gravitationnelle tra deux masses e proportionnelle al prodotto dei masses e inversement proportionnelle al carre della distanza che i separe.","de":"F = Gm₁m₂/r². Die Gravitationskraft zwischen zwei Massen ist proportional zum Produkt der Massen und umgekehrt proportional zum Quadrat des Abstands zwischen ihnen.","fr":"F = Gm₁m₂/r². La force gravitationnelle entre deux masses est proportionnelle au produit des masses et inversement proportionnelle au carré de la distance qui les sépare.","tr":"F = Gm₁m₂/r². İki kütle arasındaki yerçekimi kuvveti, kütlelerin çarpımıyla orantılı ve aralarındaki mesafenin karesiyle ters orantılıdır.","nl":"F = Gm₁m₂/r². De zwaartekrachtskracht tussen twee massa's is evenredig met het product van de massa's en omgekeerd evenredig met het kwadraat van de afstand ertussen.","ru":"F = Gm₁m₂/r². Сила гравитационного притяжения между двумя массами пропорциональна произведению масс и обратно пропорциональна квадрату расстояния между ними.","zh":"F = Gm₁m₂/r²。两个质量之间的引力与它们质量的乘积成正比，与它们之间距离的平方成反比。","pt_BR":"F = Gm₁m₂/r². A força gravitacional entre duas massas é proporcional ao produto das massas e inversamente proporcional ao quadrado da distância entre elas.","pt_PT":"F = Gm₁m₂/r². A força gravitacional entre duas massas é proporcional ao produto das massas e inversamente proporcional ao quadrado da distância entre elas."}},
  { id: 'dc-physics-0005', deck_id: 'deck-physics', sort_order: 5, front: "Kinematic Equation 1", back: "v = u + at. Final velocity equals initial velocity plus acceleration multiplied by time. Valid for constant acceleration in a straight line." , front_translations: {"es":"Ecuación Cinemática 1","it":"Equatione cinematica 1","de":"Kinematische Gleichung 1","fr":"Équation cinématique 1","tr":"Kinematik Denklem 1","nl":"Kinematische vergelijking 1","ru":"Кинематическое уравнение 1","zh":"运动学方程1","pt_BR":"Equação Cinemática 1","pt_PT":"Equação Cinemática 1"}, back_translations: {"es":"v = u + at. La velocidad final es igual a la velocidad inicial más a aceleración multiplicada por el tiempo. Válida para aceleración constante en línea reta.","it":"v = u + at. La vitesse finale e egale alla vitesse initiale più l'accelerazione multipliee per il temps. Valide per una accelerazione costante en ligne droite.","de":"v = u + at. Die Endgeschwindigkeit ist gleich der Anfangsgeschwindigkeit plus Beschleunigung mal Zeit. Gilt für konstante Beschleunigung auf einer geraden Linie.","fr":"v = u + at. La vitesse finale est égale à la vitesse initiale plus l'accélération multipliée par le temps. Valide pour une accélération constante en ligne droite.","tr":"v = u + at. Son hız, başlangıç hızına ivme çarpı zaman eklenerek bulunur. Düz bir çizgide sabit ivme için geçerlidir.","nl":"v = u + at. De eindsnelheid is gelijk aan de beginsnelheid plus versnelling maal tijd. Geldig voor constante versnelling in een rechte lijn.","ru":"v = u + at. Конечная скорость равна начальной скорости плюс ускорение, умноженное на время. Действительно для постоянного ускорения по прямой линии.","zh":"v = u + at。末速度等于初速度加上加速度乘以时间。适用于直线匀加速运动。","pt_BR":"v = u + at. A velocidade final é igual à velocidade inicial mais a aceleração multiplicada pelo tempo. Válida para aceleração constante em linha reta.","pt_PT":"v = u + at. A velocidade final é igual à velocidade inicial mais a aceleração multiplicada pelo tempo. Válida para aceleração constante em linha reta."}},
  { id: 'dc-physics-0006', deck_id: 'deck-physics', sort_order: 6, front: "Kinematic Equation 2", back: "s = ut + ½at². Displacement equals initial velocity times time plus half of acceleration times time squared. Valid for constant acceleration." , front_translations: {"es":"Ecuación Cinemática 2","it":"Equatione cinematica 2","de":"Kinematische Gleichung 2","fr":"Équation cinématique 2","tr":"Kinematik Denklem 2","nl":"Kinematische vergelijking 2","ru":"Кинематическое уравнение 2","zh":"运动学方程2","pt_BR":"Equação Cinemática 2","pt_PT":"Equação Cinemática 2"}, back_translations: {"es":"s = ut + ½at². El deslocamento es igual a la velocidad inicial veces el tiempo más a metade de la aceleración veces el tiempo al cuadrado. Válida para aceleración constante.","it":"s = ut + ½at². Il deplacement e egal alla vitesse initiale fois il temps più la moitie dell'accelerazione fois il carre del temps. Valide per una accelerazione costante.","de":"s = ut + ½at². Die Verschiebung ist gleich der Anfangsgeschwindigkeit mal Zeit plus der Hälfte der Beschleunigung mal Zeit zum Quadrat. Gilt für konstante Beschleunigung.","fr":"s = ut + ½at². Le déplacement est égal à la vitesse initiale fois le temps plus la moitié de l'accélération fois le carré du temps. Valide pour une accélération constante.","tr":"s = ut + ½at². Yer değiştirme, başlangıç hızı çarpı zaman artı ivmenin yarısı çarpı zamanın karesidir. Sabit ivme için geçerlidir.","nl":"s = ut + ½at². De verplaatsing is gelijk aan beginsnelheid maal tijd plus de helft van versnelling maal tijd kwadraat. Geldig voor constante versnelling.","ru":"s = ut + ½at². Перемещение равно начальной скорости, умноженной на время, плюс половина ускорения, умноженного на квадрат времени. Действительно для постоянного ускорения.","zh":"s = ut + ½at²。位移等于初速度乘以时间加上二分之一加速度乘以时间的平方。适用于匀加速运动。","pt_BR":"s = ut + ½at². O deslocamento é igual à velocidade inicial vezes o tempo mais a metade da aceleração vezes o tempo ao quadrado. Válida para aceleração constante.","pt_PT":"s = ut + ½at². O deslocamento é igual à velocidade inicial vezes o tempo mais metade da aceleração vezes o tempo ao quadrado. Válida para aceleração constante."}},
  { id: 'dc-physics-0007', deck_id: 'deck-physics', sort_order: 7, front: "Kinematic Equation 3", back: "v² = u² + 2as. The square of final velocity equals the square of initial velocity plus twice the product of acceleration and displacement." , front_translations: {"es":"Ecuación Cinemática 3","it":"Equatione cinematica 3","de":"Kinematische Gleichung 3","fr":"Équation cinématique 3","tr":"Kinematik Denklem 3","nl":"Kinematische vergelijking 3","ru":"Кинематическое уравнение 3","zh":"运动学方程3","pt_BR":"Equação Cinemática 3","pt_PT":"Equação Cinemática 3"}, back_translations: {"es":"v² = u² + 2las. El cuadrado de la velocidad final es igual al cuadrado de la velocidad inicial más de los veces el producto de la aceleración y del deslocamento.","it":"v² = u² + 2as. Il carre della vitesse finale e egal al carre della vitesse initiale più deux fois il prodotto dell'accelerazione e del deplacement.","de":"v² = u² + 2as. Das Quadrat der Endgeschwindigkeit ist gleich dem Quadrat der Anfangsgeschwindigkeit plus dem Doppelten des Produkts aus Beschleunigung und Verschiebung.","fr":"v² = u² + 2as. Le carré de la vitesse finale est égal au carré de la vitesse initiale plus deux fois le produit de l'accélération et du déplacement.","tr":"v² = u² + 2as. Son hızın karesi, başlangıç hızının karesi artı ivme ile yer değiştirmenin çarpımının iki katına eşittir.","nl":"v² = u² + 2as. Het kwadraat van de eindsnelheid is gelijk aan het kwadraat van de beginsnelheid plus tweemaal het product van versnelling en verplaatsing.","ru":"v² = u² + 2as. Квадрат конечной скорости равен квадрату начальной скорости плюс удвоенное произведение ускорения и перемещения.","zh":"v² = u² + 2as。末速度的平方等于初速度的平方加上加速度与位移乘积的两倍。","pt_BR":"v² = u² + 2as. O quadrado da velocidade final é igual ao quadrado da velocidade inicial mais duas vezes o produto da aceleração e do deslocamento.","pt_PT":"v² = u² + 2as. O quadrado da velocidade final é igual ao quadrado da velocidade inicial mais duas vezes o produto da aceleração pelo deslocamento."}},
  { id: 'dc-physics-0008', deck_id: 'deck-physics', sort_order: 8, front: "Kinematic Equation 4", back: "s = ½(u + v)t. Displacement equals the average of initial and final velocities multiplied by time. Useful when acceleration is not directly known." , front_translations: {"es":"Ecuación Cinemática 4","it":"Equatione cinematica 4","de":"Kinematische Gleichung 4","fr":"Équation cinématique 4","tr":"Kinematik Denklem 4","nl":"Kinematische vergelijking 4","ru":"Кинематическое уравнение 4","zh":"运动学方程4","pt_BR":"Equação Cinemática 4","pt_PT":"Equação Cinemática 4"}, back_translations: {"es":"s = ½(u + v)t. El deslocamento es igual a la média de las velocidades inicial y final multiplicada por el tiempo. Útil cuando a aceleración no es directamente conocida.","it":"s = ½(u + v)t. Il deplacement e egal alla moyenne dei vitesses initiale e finale multipliee per il temps. Utile quando l'accelerazione n'e directement conosciuta.","de":"s = ½(u + v)t. Die Verschiebung ist gleich dem Durchschnitt der Anfangs- und Endgeschwindigkeiten multipliziert mit der Zeit. Nützlich, wenn die Beschleunigung nicht direkt bekannt ist.","fr":"s = ½(u + v)t. Le déplacement est égal à la moyenne des vitesses initiale et finale multipliée par le temps. Utile lorsque l'accélération n'est pas directement connue.","tr":"s = ½(u + v)t. Yer değiştirme, başlangıç ve son hızların ortalamasının zamanla çarpımına eşittir. İvmenin doğrudan bilinmediği durumlarda kullanışlıdır.","nl":"s = ½(u + v)t. De verplaatsing is gelijk aan het gemiddelde van begin- en eindsnelheid maal tijd. Handig wanneer de versnelling niet direct bekend is.","ru":"s = ½(u + v)t. Перемещение равно среднему значению начальной и конечной скоростей, умноженному на время. Полезно, когда ускорение неизвестно напрямую.","zh":"s = ½(u + v)t。位移等于初速度与末速度平均值乘以时间。在加速度未知时很有用。","pt_BR":"s = ½(u + v)t. O deslocamento é igual à média das velocidades inicial e final multiplicada pelo tempo. Útil quando a aceleração não é diretamente conhecida.","pt_PT":"s = ½(u + v)t. O deslocamento é igual à média das velocidades inicial e final multiplicada pelo tempo. Útil quando a aceleração não é diretamente conhecida."}},
  { id: 'dc-physics-0009', deck_id: 'deck-physics', sort_order: 9, front: "Kinetic Energy", back: "KE = ½mv². The energy of motion equals half the mass times the velocity squared. Doubling velocity quadruples kinetic energy." , front_translations: {"es":"Energía Cinética","it":"Energia cinetica","de":"Kinetische Energie","fr":"Énergie cinétique","tr":"Kinetik Enerji","nl":"Kinetische energie","ru":"Кинетическая энергия","zh":"动能","pt_BR":"Energia Cinética","pt_PT":"Energia Cinética"}, back_translations: {"es":"KE = ½mv². La energía de movimiento es igual a la metade de la masa multiplicada por el cuadrado de la velocidad. Dobrar a velocidad quadruplica a energía cinética.","it":"KE = ½mv². L'energia di mouvement e egale alla moitie della masse multipliee per il carre della vitesse. Doubler la vitesse quadruple l'energia cinetico.","de":"KE = ½mv². Die Bewegungsenergie ist gleich der halben Masse mal dem Quadrat der Geschwindigkeit. Bei Verdopplung der Geschwindigkeit vervierfacht sich die kinetische Energie.","fr":"KE = ½mv². L'énergie de mouvement est égale à la moitié de la masse multipliée par le carré de la vitesse. Doubler la vitesse quadruple l'énergie cinétique.","tr":"KE = ½mv². Hareket enerjisi, kütlenin yarısı çarpı hızın karesidir. Hızı iki katına çıkarmak kinetik enerjiyi dört katına çıkarır.","nl":"KE = ½mv². De bewegingsenergie is gelijk aan de helft van de massa maal het kwadraat van de snelheid. De snelheid verdubbelen verviervoudigt de kinetische energie.","ru":"KE = ½mv². Энергия движения равна половине массы, умноженной на квадрат скорости. Удвоение скорости увеличивает кинетическую энергию в четыре раза.","zh":"KE = ½mv²。动能等于质量的一半乘以速度的平方。速度翻倍则动能变为四倍。","pt_BR":"KE = ½mv². A energia de movimento é igual à metade da massa multiplicada pelo quadrado da velocidade. Dobrar a velocidade quadruplica a energia cinética.","pt_PT":"KE = ½mv². A energia de movimento é igual a metade da massa multiplicada pelo quadrado da velocidade. Duplicar a velocidade quadruplica a energia cinética."}},
  { id: 'dc-physics-0010', deck_id: 'deck-physics', sort_order: 10, front: "Gravitational Potential Energy", back: "PE = mgh. Gravitational potential energy equals mass times gravitational acceleration times height. It depends on the reference level chosen for h = 0." , front_translations: {"es":"Energía Potencial Gravitacional","it":"Energie potenziale gravitazionale","de":"Gravitationspotenzielle Energie","fr":"Énergie potentielle gravitationnelle","tr":"Yerçekimi Potansiyel Enerjisi","nl":"Gravitationele potentiële energie","ru":"Гравитационная потенциальная энергия","zh":"重力势能","pt_BR":"Energia Potencial Gravitacional","pt_PT":"Energia Potencial Gravitacional"}, back_translations: {"es":"PE = mgh. La energía potencial gravitacional es igual a la masa veces a aceleración gravitacional veces a altura. Depende del nivel de referencia escolhido para h = 0.","it":"PE = mgh. L'energia potenziale gravitationnelle e egale alla masse fois l'accelerazione gravitationnelle fois la hautore. Elle depend del niveau di referenza choisi per h = 0.","de":"PE = mgh. Die Gravitationspotenzialenergie ist gleich Masse mal Erdbeschleunigung mal Höhe. Sie hängt vom gewählten Referenzniveau für h = 0 ab.","fr":"PE = mgh. L'énergie potentielle gravitationnelle est égale à la masse fois l'accélération gravitationnelle fois la hauteur. Elle dépend du niveau de référence choisi pour h = 0.","tr":"PE = mgh. Yerçekimi potansiyel enerjisi, kütle çarpı yerçekimi ivmesi çarpı yüksekliğe eşittir. h = 0 için seçilen referans seviyesine bağlıdır.","nl":"PE = mgh. Gravitationele potentiële energie is gelijk aan massa maal zwaartekrachtsversnelling maal hoogte. Het hangt af van het gekozen referentieniveau voor h = 0.","ru":"PE = mgh. Гравитационная потенциальная энергия равна массе, умноженной на ускорение свободного падения и высоту. Зависит от выбранного нулевого уровня отсчёта высоты.","zh":"PE = mgh。重力势能等于质量乘以重力加速度乘以高度。它取决于所选择的h = 0的参考平面。","pt_BR":"PE = mgh. A energia potencial gravitacional é igual à massa vezes a aceleração gravitacional vezes a altura. Depende do nível de referência escolhido para h = 0.","pt_PT":"PE = mgh. A energia potencial gravitacional é igual à massa vezes a aceleração gravitacional vezes a altura. Depende do nível de referência escolhido para h = 0."}},
  { id: 'dc-physics-0011', deck_id: 'deck-physics', sort_order: 11, front: "Work-Energy Theorem", back: "W = ΔKE = Fd·cosθ. The net work done on an object equals its change in kinetic energy. Work is positive when force and displacement are in the same direction." , front_translations: {"es":"Teorema Trabajo-Energía","it":"Teorema lavoro-energia","de":"Arbeit-Energie-Theorem","fr":"Théorème travail-énergie","tr":"İş-Enerji Teoremi","nl":"Arbeid-energiestelling","ru":"Теорема о работе и кинетической энергии","zh":"功能定理","pt_BR":"Teorema Trabalho-Energia","pt_PT":"Teorema Trabalho-Energia"}, back_translations: {"es":"W = ΔKE = Fd·cosθ. El trabajo total realizado sobre un objeto es igual a la variación de la su energía cinética. El trabajo es positivo cuando a fuerza y el deslocamento tienen a misma dirección.","it":"W = ΔKE = Fd·cosθ. Il travail net effectue su un objet e egal alla variazione di il suo energia cinetico. Il travail e positif quando la force e il deplacement sono in il stesso sens.","de":"W = ΔKE = Fd·cosθ. Die an einem Körper geleistete Nettoarbeit ist gleich der Änderung seiner kinetischen Energie. Arbeit ist positiv, wenn Kraft und Verschiebung in dieselbe Richtung zeigen.","fr":"W = ΔKE = Fd·cosθ. Le travail net effectué sur un objet est égal à la variation de son énergie cinétique. Le travail est positif quand la force et le déplacement sont dans le même sens.","tr":"W = ΔKE = Fd·cosθ. Bir cisim üzerinde yapılan net iş, kinetik enerjisindeki değişime eşittir. Kuvvet ve yer değiştirme aynı yöndeyse iş pozitiftir.","nl":"W = ΔKE = Fd·cosθ. De netto arbeid verricht op een object is gelijk aan de verandering in kinetische energie. Arbeid is positief wanneer kracht en verplaatsing in dezelfde richting zijn.","ru":"W = ΔKE = Fd·cosθ. Суммарная работа, совершённая над телом, равна изменению его кинетической энергии. Работа положительна, когда сила и перемещение направлены в одну сторону.","zh":"W = ΔKE = Fd·cosθ。对物体做的合功等于其动能的变化。当力与位移方向相同时，功为正值。","pt_BR":"W = ΔKE = Fd·cosθ. O trabalho total realizado sobre um objeto é igual à variação da sua energia cinética. O trabalho é positivo quando a força e o deslocamento têm a mesma direção.","pt_PT":"W = ΔKE = Fd·cosθ. O trabalho total realizado sobre um objeto é igual à variação da sua energia cinética. O trabalho é positivo quando a força e o deslocamento têm a mesma direção."}},
  { id: 'dc-physics-0012', deck_id: 'deck-physics', sort_order: 12, front: "Conservation of Energy", back: "In an isolated system, total mechanical energy (KE + PE) remains constant. Energy cannot be created or destroyed, only transformed from one form to another." , front_translations: {"es":"Conservación de Energía","it":"Conservazione dell'energia","de":"Energieerhaltungssatz","fr":"Conservation de l'énergie","tr":"Enerjinin Korunumu","nl":"Behoud van energie","ru":"Закон сохранения энергии","zh":"能量守恒定律","pt_BR":"Conservação de Energia","pt_PT":"Conservação de Energia"}, back_translations: {"es":"En un sistema isolado, a energía mecánica total (KE + PE) permanece constante. La energía no puede ser creada o destruída, solo transformada de una forma para outra.","it":"In un sistema isole, l'energia mecanico totale (KE + PE) reste costante. L'energia non può etre ni creee ni detruite, seulement transformee d'una forme à una autre.","de":"In einem isolierten System bleibt die mechanische Gesamtenergie (KE + PE) konstant. Energie kann weder erzeugt noch vernichtet, sondern nur von einer Form in eine andere umgewandelt werden.","fr":"Dans un système isolé, l'énergie mécanique totale (KE + PE) reste constante. L'énergie ne peut être ni créée ni détruite, seulement transformée d'une forme à une autre.","tr":"İzole bir sistemde, toplam mekanik enerji (KE + PE) sabit kalır. Enerji yaratılamaz veya yok edilemez, yalnızca bir formdan diğerine dönüştürülebilir.","nl":"In een geïsoleerd systeem blijft de totale mechanische energie (KE + PE) constant. Energie kan niet worden gecreëerd of vernietigd, alleen omgezet van de ene naar de andere vorm.","ru":"В изолированной системе полная механическая энергия (KE + PE) остаётся постоянной. Энергия не может быть создана или уничтожена, только преобразована из одной формы в другую.","zh":"在孤立系统中，总机械能（KE + PE）保持不变。能量不能被创造或消灭，只能从一种形式转换为另一种形式。","pt_BR":"Em um sistema isolado, a energia mecânica total (KE + PE) permanece constante. A energia não pode ser criada ou destruída, apenas transformada de uma forma para outra.","pt_PT":"Num sistema isolado, a energia mecânica total (KE + PE) permanece constante. A energia não pode ser criada nem destruída, apenas transformada de uma forma para outra."}},
  { id: 'dc-physics-0013', deck_id: 'deck-physics', sort_order: 13, front: "Power", back: "P = W/t = Fv. Power is the rate of doing work or transferring energy. One watt equals one joule per second. Also expressed as force times velocity." , front_translations: {"es":"Potencia","it":"Puissanza","de":"Leistung","fr":"Puissance","tr":"Güç","nl":"Vermogen","ru":"Мощность","zh":"功率","pt_BR":"Potência","pt_PT":"Potência"}, back_translations: {"es":"P = W/t = Fv. Potencia es a taxa de realización de trabajo o transferencia de energía. Un watt equivale a un joule por según. También expressa como fuerza veces velocidad.","it":"P = W/t = Fv. La puissanza e il taux di travail o di transfert d'energia. Un watt equivaut à un joule per seconde. Aussi exprimee come force fois vitesse.","de":"P = W/t = Fv. Leistung ist die Rate der Arbeitsverrichtung oder Energieübertragung. Ein Watt entspricht einem Joule pro Sekunde. Auch als Kraft mal Geschwindigkeit ausgedrückt.","fr":"P = W/t = Fv. La puissance est le taux de travail ou de transfert d'énergie. Un watt équivaut à un joule par seconde. Aussi exprimée comme force fois vitesse.","tr":"P = W/t = Fv. Güç, iş yapma veya enerji aktarma hızıdır. Bir watt, saniyede bir joule'e eşittir. Kuvvet çarpı hız olarak da ifade edilir.","nl":"P = W/t = Fv. Vermogen is de snelheid waarmee arbeid wordt verricht of energie wordt overgedragen. Één watt is gelijk aan één joule per seconde. Ook uitgedrukt als kracht maal snelheid.","ru":"P = W/t = Fv. Мощность — это скорость совершения работы или передачи энергии. Один ватт равен одному джоулю в секунду. Также выражается как сила, умноженная на скорость.","zh":"P = W/t = Fv。功率是做功或传递能量的速率。一瓦特等于每秒一焦耳。也可表示为力乘以速度。","pt_BR":"P = W/t = Fv. Potência é a taxa de realização de trabalho ou transferência de energia. Um watt equivale a um joule por segundo. Também expressa como força vezes velocidade.","pt_PT":"P = W/t = Fv. Potência é a taxa de realização de trabalho ou transferência de energia. Um watt equivale a um joule por segundo. Também expressa como força vezes velocidade."}},
  { id: 'dc-physics-0014', deck_id: 'deck-physics', sort_order: 14, front: "Momentum", back: "p = mv. Momentum is the product of an object's mass and velocity. It is a vector quantity. The SI unit is kg·m/s." , front_translations: {"es":"Momento Linear","it":"Quantità di moto","de":"Impuls (Bewegungsgröße)","fr":"Quantité de mouvement","tr":"Momentum","nl":"Impuls (hoeveelheid van beweging)","ru":"Импульс (количество движения)","zh":"动量","pt_BR":"Momento Linear","pt_PT":"Quantidade de Movimento"}, back_translations: {"es":"p = mv. El momento linear es el producto de la masa por la velocidad de un objeto. Es una grandeza vetorial. La unidad SI es kg·m/s.","it":"p = mv. La quantite di mouvement e il prodotto della masse e della vitesse di un objet. C'e una grandore vectorielle. L'unite SI e kg·m/s.","de":"p = mv. Der Impuls ist das Produkt aus Masse und Geschwindigkeit eines Körpers. Es ist eine vektorielle Größe. Die SI-Einheit ist kg·m/s.","fr":"p = mv. La quantité de mouvement est le produit de la masse et de la vitesse d'un objet. C'est une grandeur vectorielle. L'unité SI est kg·m/s.","tr":"p = mv. Momentum, bir cismin kütlesi ile hızının çarpımıdır. Vektörel bir büyüklüktür. SI birimi kg·m/s'dir.","nl":"p = mv. Impuls is het product van de massa en snelheid van een object. Het is een vectorgrootheid. De SI-eenheid is kg·m/s.","ru":"p = mv. Импульс тела — произведение его массы на скорость. Является векторной величиной. Единица СИ — кг·м/с.","zh":"p = mv。动量是物体质量与速度的乘积。它是一个矢量。SI单位为kg·m/s。","pt_BR":"p = mv. O momento linear é o produto da massa pela velocidade de um objeto. É uma grandeza vetorial. A unidade SI é kg·m/s.","pt_PT":"p = mv. A quantidade de movimento é o produto da massa pela velocidade de um objeto. É uma grandeza vetorial. A unidade SI é kg·m/s."}},
  { id: 'dc-physics-0015', deck_id: 'deck-physics', sort_order: 15, front: "Conservation of Momentum", back: "In the absence of external forces, the total momentum of a system remains constant. m₁v₁ + m₂v₂ = m₁v₁' + m₂v₂'. Applies to all collisions." , front_translations: {"es":"Conservación del Momento Linear","it":"Conservazione della quantità di moto","de":"Impulserhaltungssatz","fr":"Conservation de la quantité de mouvement","tr":"Momentumun Korunumu","nl":"Behoud van impuls","ru":"Закон сохранения импульса","zh":"动量守恒定律","pt_BR":"Conservação do Momento Linear","pt_PT":"Conservação da Quantidade de Movimento"}, back_translations: {"es":"Na ausencia de fuerzas externas, el momento linear total de un sistema permanece constante. m₁v₁ + m₂v₂ = m₁v₁' + m₂v₂'. Se aplica a todas las colisões.","it":"En l'absenza di forces exterieures, la quantite di mouvement totale di un sistema reste costante. m₁v₁ + m₂v₂ = m₁v₁' + m₂v₂'. S'applico à tutte i collisions.","de":"In Abwesenheit äußerer Kräfte bleibt der Gesamtimpuls eines Systems konstant. m₁v₁ + m₂v₂ = m₁v₁' + m₂v₂'. Gilt für alle Kollisionen.","fr":"En l'absence de forces extérieures, la quantité de mouvement totale d'un système reste constante. m₁v₁ + m₂v₂ = m₁v₁' + m₂v₂'. S'applique à toutes les collisions.","tr":"Dış kuvvetlerin yokluğunda, bir sistemin toplam momentumu sabit kalır. m₁v₁ + m₂v₂ = m₁v₁' + m₂v₂'. Tüm çarpışmalara uygulanır.","nl":"Bij afwezigheid van externe krachten blijft de totale impuls van een systeem constant. m₁v₁ + m₂v₂ = m₁v₁' + m₂v₂'. Geldt voor alle botsingen.","ru":"При отсутствии внешних сил полный импульс системы остаётся постоянным. m₁v₁ + m₂v₂ = m₁v₁' + m₂v₂'. Применяется ко всем столкновениям.","zh":"在没有外力的情况下，系统的总动量保持不变。m₁v₁ + m₂v₂ = m₁v₁' + m₂v₂'。适用于所有碰撞。","pt_BR":"Na ausência de forças externas, o momento linear total de um sistema permanece constante. m₁v₁ + m₂v₂ = m₁v₁' + m₂v₂'. Aplica-se a todas as colisões.","pt_PT":"Na ausência de forças externas, a quantidade de movimento total de um sistema permanece constante. m₁v₁ + m₂v₂ = m₁v₁' + m₂v₂'. Aplica-se a todas as colisões."}},
  { id: 'dc-physics-0016', deck_id: 'deck-physics', sort_order: 16, front: "Impulse", back: "J = FΔt = Δp. Impulse equals force times time and equals the change in momentum. Explains why extending collision time reduces force (e.g., air bags)." , front_translations: {"es":"Impulso","it":"Impulso","de":"Kraftstoß","fr":"Impulsion de force","tr":"İmpuls","nl":"Impuls (stoot)","ru":"Импульс силы","zh":"冲量","pt_BR":"Impulso","pt_PT":"Impulso"}, back_translations: {"es":"J = FΔt = Δp. El impulso es igual a la fuerza veces el tiempo y igual a la variación del momento linear. Explica por que aumentar el tiempo de colisão reduce a fuerza (ex.: airbags).","it":"J = FΔt = Δp. L'impulsion e egale alla force fois il temps e equivaut alla variazione di quantite di mouvement. Explico pourquoi prolonger la duree d'una collision reduit la force (ex. : airbags).","de":"J = FΔt = Δp. Der Kraftstoß ist gleich Kraft mal Zeit und entspricht der Impulsänderung. Erklärt, warum eine längere Kollisionszeit die Kraft reduziert (z.B. Airbags).","fr":"J = FΔt = Δp. L'impulsion est égale à la force fois le temps et équivaut à la variation de quantité de mouvement. Explique pourquoi prolonger la durée d'une collision réduit la force (ex. : airbags).","tr":"J = FΔt = Δp. İmpuls, kuvvet çarpı zamana eşit olup momentum değişimine eşittir. Çarpışma süresini uzatmanın kuvveti neden azalttığını açıklar (ör. hava yastıkları).","nl":"J = FΔt = Δp. Impuls is gelijk aan kracht maal tijd en gelijk aan de verandering in impuls. Verklaart waarom het verlengen van de botstijd de kracht vermindert (bijv. airbags).","ru":"J = FΔt = Δp. Импульс силы равен силе, умноженной на время, и равен изменению количества движения. Объясняет, почему увеличение времени столкновения уменьшает силу (например, подушки безопасности).","zh":"J = FΔt = Δp。冲量等于力乘以时间，也等于动量的变化。这解释了为什么延长碰撞时间可以减小力（如安全气囊）。","pt_BR":"J = FΔt = Δp. O impulso é igual à força vezes o tempo e igual à variação do momento linear. Explica por que aumentar o tempo de colisão reduz a força (ex.: airbags).","pt_PT":"J = FΔt = Δp. O impulso é igual à força vezes o tempo e igual à variação da quantidade de movimento. Explica por que prolongar o tempo de colisão reduz a força (ex.: airbags)."}},
  { id: 'dc-physics-0017', deck_id: 'deck-physics', sort_order: 17, front: "Elastic Collision", back: "A collision in which both momentum and kinetic energy are conserved. Objects bounce off each other without permanent deformation or generation of heat." , front_translations: {"es":"Colisão Elástica","it":"Collisione elastico","de":"Elastischer Stoß","fr":"Collision élastique","tr":"Elastik Çarpışma","nl":"Elastische botsing","ru":"Упругий удар","zh":"弹性碰撞","pt_BR":"Colisão Elástica","pt_PT":"Colisão Elástica"}, back_translations: {"es":"Una colisão en la qual tanto el momento linear quanto a energía cinética son conservados. Los objetos ricocheteiam sin deformación permanente o geración de calor.","it":"Una collision in laquelle la quantite di mouvement e l'energia cinetico sono tutte deux conservees. I objets rebondissent senza deformazione permanente ni generazione di calore.","de":"Ein Stoß, bei dem sowohl Impuls als auch kinetische Energie erhalten bleiben. Die Körper prallen voneinander ab, ohne dauerhafte Verformung oder Wärmeentwicklung.","fr":"Une collision dans laquelle la quantité de mouvement et l'énergie cinétique sont toutes deux conservées. Les objets rebondissent sans déformation permanente ni génération de chaleur.","tr":"Hem momentumun hem de kinetik enerjinin korunduğu bir çarpışma. Cisimler kalıcı deformasyon veya ısı üretimi olmaksızın birbirinden geri seker.","nl":"Een botsing waarbij zowel impuls als kinetische energie behouden blijven. Objecten stuiteren van elkaar af zonder permanente vervorming of warmteontwikkeling.","ru":"Столкновение, при котором сохраняются как импульс, так и кинетическая энергия. Тела отскакивают друг от друга без постоянной деформации или выделения тепла.","zh":"动量和动能都守恒的碰撞。物体相互弹开，没有永久变形或热量产生。","pt_BR":"Uma colisão na qual tanto o momento linear quanto a energia cinética são conservados. Os objetos ricocheteiam sem deformação permanente ou geração de calor.","pt_PT":"Uma colisão na qual tanto a quantidade de movimento como a energia cinética são conservadas. Os objetos ricocheteiam sem deformação permanente ou geração de calor."}},
  { id: 'dc-physics-0018', deck_id: 'deck-physics', sort_order: 18, front: "Inelastic Collision", back: "A collision in which momentum is conserved but kinetic energy is not. Some energy is converted to heat, sound, or deformation. In a perfectly inelastic collision, objects stick together." , front_translations: {"es":"Colisão Inelástica","it":"Collisione inelastico","de":"Unelastischer Stoß","fr":"Collision inélastique","tr":"Esnek Olmayan Çarpışma","nl":"Inelastische botsing","ru":"Неупругий удар","zh":"非弹性碰撞","pt_BR":"Colisão Inelástica","pt_PT":"Colisão Inelástica"}, back_translations: {"es":"Una colisão en la qual el momento linear es conservado, pero a energía cinética no. Alguma energía es convertida en calor, sonido o deformación. En una colisão perfeitamente inelástica, los objetos ficam juntos.","it":"Una collision in laquelle la quantite di mouvement e conservee, ma l'energia cinetico. Una partie dell'energia e convertie en calore, il suo o deformazione. In una collision parfaitement inelastico, i objets restent colles ensemble.","de":"Ein Stoß, bei dem der Impuls erhalten bleibt, nicht aber die kinetische Energie. Ein Teil der Energie wird in Wärme, Schall oder Verformung umgewandelt. Bei einem vollkommen unelastischen Stoß bleiben die Körper zusammen.","fr":"Une collision dans laquelle la quantité de mouvement est conservée, mais pas l'énergie cinétique. Une partie de l'énergie est convertie en chaleur, son ou déformation. Dans une collision parfaitement inélastique, les objets restent collés ensemble.","tr":"Momentumun korunduğu ancak kinetik enerjinin korunmadığı bir çarpışma. Bir miktar enerji ısı, ses veya deformasyona dönüşür. Tam esnek olmayan çarpışmada cisimler birbirine yapışır.","nl":"Een botsing waarbij impuls behouden blijft maar kinetische energie niet. Enige energie wordt omgezet in warmte, geluid of vervorming. Bij een volkomen inelastische botsing blijven objecten samenkleven.","ru":"Столкновение, при котором импульс сохраняется, а кинетическая энергия — нет. Часть энергии преобразуется в тепло, звук или деформацию. При абсолютно неупругом ударе тела остаются вместе.","zh":"动量守恒但动能不守恒的碰撞。部分能量转化为热、声或变形。在完全非弹性碰撞中，物体粘在一起。","pt_BR":"Uma colisão na qual o momento linear é conservado, mas a energia cinética não. Alguma energia é convertida em calor, som ou deformação. Em uma colisão perfeitamente inelástica, os objetos ficam juntos.","pt_PT":"Uma colisão na qual a quantidade de movimento é conservada, mas a energia cinética não. Alguma energia é convertida em calor, som ou deformação. Numa colisão perfeitamente inelástica, os objetos ficam unidos."}},
  { id: 'dc-physics-0019', deck_id: 'deck-physics', sort_order: 19, front: "Centripetal Acceleration", back: "a_c = v²/r. An object moving in a circle has centripetal acceleration directed toward the center. It changes the direction of velocity but not its magnitude." , front_translations: {"es":"Aceleración Centrípeta","it":"Acceleratione centripete","de":"Zentripetalbeschleunigung","fr":"Accélération centripète","tr":"Merkezcil İvme","nl":"Centripetale versnelling","ru":"Центростремительное ускорение","zh":"向心加速度","pt_BR":"Aceleração Centrípeta","pt_PT":"Aceleração Centrípeta"}, back_translations: {"es":"a_c = v²/r. Un objeto en movimiento circular tiene aceleración centrípeta direcionada para el centro. Ela muda a dirección de la velocidad, pero no su magnitude.","it":"a_c = v²/r. Un objet se deplazant en cercle ha una accelerazione centripete dirigee verso il centre. Elle modifie la direczione della vitesse, ma la sua valore.","de":"a_c = v²/r. Ein Körper, der sich in einem Kreis bewegt, hat eine Zentripetalbeschleunigung, die zum Mittelpunkt zeigt. Sie ändert die Richtung der Geschwindigkeit, nicht ihre Größe.","fr":"a_c = v²/r. Un objet se déplaçant en cercle a une accélération centripète dirigée vers le centre. Elle modifie la direction de la vitesse, mais pas sa valeur.","tr":"a_c = v²/r. Daire boyunca hareket eden bir cismin merkeze doğru yönelen merkezcil ivmesi vardır. Hızın yönünü değiştirir, büyüklüğünü değil.","nl":"a_c = v²/r. Een object dat in een cirkel beweegt, heeft centripetale versnelling gericht naar het middelpunt. Het verandert de richting van de snelheid, maar niet de grootte ervan.","ru":"a_c = v²/r. Тело, движущееся по окружности, испытывает центростремительное ускорение, направленное к центру. Оно изменяет направление скорости, но не её величину.","zh":"a_c = v²/r。做圆周运动的物体具有指向圆心的向心加速度。它改变速度的方向，但不改变其大小。","pt_BR":"a_c = v²/r. Um objeto em movimento circular tem aceleração centrípeta direcionada para o centro. Ela muda a direção da velocidade, mas não sua magnitude.","pt_PT":"a_c = v²/r. Um objeto em movimento circular tem aceleração centrípeta direcionada para o centro. Ela altera a direção da velocidade, mas não a sua magnitude."}},
  { id: 'dc-physics-0020', deck_id: 'deck-physics', sort_order: 20, front: "Centripetal Force", back: "F_c = mv²/r. The net inward force required to keep an object moving in a circular path. It is not a new type of force but the net result of other forces (gravity, tension, friction)." , front_translations: {"es":"Fuerza Centrípeta","it":"Forza centripeta","de":"Zentripetalkraft","fr":"Force centripète","tr":"Merkezcil Kuvvet","nl":"Centripetale kracht","ru":"Центростремительная сила","zh":"向心力","pt_BR":"Força Centrípeta","pt_PT":"Força Centrípeta"}, back_translations: {"es":"F_c = mv²/r. La fuerza líquida direcionada para dentro necesaria para mantener un objeto en trajetória circular. No es un nuevo tipo de fuerza, pero el resultado líquido de outras fuerzas (gravidad, tensão, atrito).","it":"F_c = mv²/r. La force nette verso l'interiore necessario per maintenir un objet su una trajectoire circulaire. Ce n'e un nuovo type di force, ma il resultat net d'autres forces (gravite, tension, frottement).","de":"F_c = mv²/r. Die nach innen gerichtete Nettokraft, die erforderlich ist, um einen Körper auf einer Kreisbahn zu halten. Es ist keine neue Kraftart, sondern das Nettoergebnis anderer Kräfte (Schwerkraft, Spannung, Reibung).","fr":"F_c = mv²/r. La force nette vers l'intérieur nécessaire pour maintenir un objet sur une trajectoire circulaire. Ce n'est pas un nouveau type de force, mais le résultat net d'autres forces (gravité, tension, frottement).","tr":"F_c = mv²/r. Bir cismi dairesel yörüngede tutmak için gereken net içe doğru kuvvet. Yeni bir kuvvet türü değil, diğer kuvvetlerin (yerçekimi, gerilim, sürtünme) net sonucudur.","nl":"F_c = mv²/r. De netto naar binnen gerichte kracht die nodig is om een object in een cirkelvormige baan te houden. Het is geen nieuw type kracht, maar het nettoresultaat van andere krachten (zwaartekracht, spanning, wrijving).","ru":"F_c = mv²/r. Результирующая направленная к центру сила, необходимая для удержания тела на круговой орбите. Это не новый вид силы, а суммарный результат других сил (гравитации, натяжения, трения).","zh":"F_c = mv²/r。使物体做圆周运动所需的净向心力。它不是一种新的力，而是其他力（重力、张力、摩擦力）的合力。","pt_BR":"F_c = mv²/r. A força líquida direcionada para dentro necessária para manter um objeto em trajetória circular. Não é um novo tipo de força, mas o resultado líquido de outras forças (gravidade, tensão, atrito).","pt_PT":"F_c = mv²/r. A força resultante dirigida para dentro necessária para manter um objeto em trajetória circular. Não é um novo tipo de força, mas o resultado líquido de outras forças (gravidade, tensão, atrito)."}},
  { id: 'dc-physics-0021', deck_id: 'deck-physics', sort_order: 21, front: "Torque", back: "τ = rF·sinθ. Torque is the rotational equivalent of force, equal to the lever arm times the force component perpendicular to it. SI unit is N·m." , front_translations: {"es":"Torque","it":"Coppia (momento torcente)","de":"Drehmoment","fr":"Couple (moment de force)","tr":"Tork","nl":"Koppel (moment van kracht)","ru":"Момент силы (крутящий момент)","zh":"力矩（扭矩）","pt_BR":"Torque","pt_PT":"Binário (Momento de Força)"}, back_translations: {"es":"τ = rF·sinθ. El torque es el equivalente rotacional de la fuerza, igual al brazo de alavanca veces el componente de la fuerza perpendicular a ele. La unidad SI es N·m.","it":"τ = rF·sinθ. Il couple e l'equivalent rotatif della force, egal al bras di levier fois la composante di force perpendiculaire à celui-ci. L'unite SI e il N·m.","de":"τ = rF·sinθ. Das Drehmoment ist das rotatorische Äquivalent der Kraft, gleich dem Hebelarm mal der senkrechten Kraftkomponente. SI-Einheit ist N·m.","fr":"τ = rF·sinθ. Le couple est l'équivalent rotatif de la force, égal au bras de levier fois la composante de force perpendiculaire à celui-ci. L'unité SI est le N·m.","tr":"τ = rF·sinθ. Tork, kuvvetin dönel eşdeğeridir; kol uzunluğu çarpı kola dik kuvvet bileşenine eşittir. SI birimi N·m'dir.","nl":"τ = rF·sinθ. Koppel is het rotationele equivalent van kracht, gelijk aan de hefboomarm maal de loodrechte krachtcomponent. SI-eenheid is N·m.","ru":"τ = rF·sinθ. Момент силы — это вращательный аналог силы, равный плечу, умноженному на перпендикулярную составляющую силы. Единица СИ — Н·м.","zh":"τ = rF·sinθ。力矩是力的旋转等效量，等于力臂乘以垂直于力臂的力分量。SI单位为N·m。","pt_BR":"τ = rF·sinθ. O torque é o equivalente rotacional da força, igual ao braço de alavanca vezes o componente da força perpendicular a ele. A unidade SI é N·m.","pt_PT":"τ = rF·sinθ. O binário é o equivalente rotacional da força, igual ao braço da alavanca vezes a componente da força perpendicular a ele. A unidade SI é N·m."}},
  { id: 'dc-physics-0022', deck_id: 'deck-physics', sort_order: 22, front: "Angular Momentum", back: "L = Iω = mvr. Angular momentum of a rotating body equals moment of inertia times angular velocity. Conserved in the absence of external torques." , front_translations: {"es":"Momento Angular","it":"Momento angolare","de":"Drehimpuls","fr":"Moment cinétique (moment angulaire)","tr":"Açısal Momentum","nl":"Impulsmoment (hoekmomentum)","ru":"Момент импульса (угловой момент)","zh":"角动量","pt_BR":"Momento Angular","pt_PT":"Momento Angular"}, back_translations: {"es":"L = Iω = mvr. El momento angular de un cuerpo en rotación es igual al momento de inércia veces a velocidad angular. Conservado en la ausencia de torques externos.","it":"L = Iω = mvr. Il moment cinetico di un corps en rotazione e egal al moment d'inertie fois la vitesse angulaire. Conserve en l'absenza di couples exteriori.","de":"L = Iω = mvr. Der Drehimpuls eines rotierenden Körpers ist gleich dem Trägheitsmoment mal der Winkelgeschwindigkeit. Er bleibt in Abwesenheit äußerer Drehmomente erhalten.","fr":"L = Iω = mvr. Le moment cinétique d'un corps en rotation est égal au moment d'inertie fois la vitesse angulaire. Conservé en l'absence de couples extérieurs.","tr":"L = Iω = mvr. Dönen bir cismin açısal momentumu, eylemsizlik momenti çarpı açısal hıza eşittir. Dış torkların yokluğunda korunur.","nl":"L = Iω = mvr. Het impulsmoment van een roterend lichaam is gelijk aan het traagheidsmoment maal de hoeksnelheid. Behouden bij afwezigheid van externe koppels.","ru":"L = Iω = mvr. Момент импульса вращающегося тела равен моменту инерции, умноженному на угловую скорость. Сохраняется при отсутствии внешних моментов сил.","zh":"L = Iω = mvr。旋转体的角动量等于转动惯量乘以角速度。在没有外力矩的情况下守恒。","pt_BR":"L = Iω = mvr. O momento angular de um corpo em rotação é igual ao momento de inércia vezes a velocidade angular. Conservado na ausência de torques externos.","pt_PT":"L = Iω = mvr. O momento angular de um corpo em rotação é igual ao momento de inércia vezes a velocidade angular. Conservado na ausência de binários externos."}},
  { id: 'dc-physics-0023', deck_id: 'deck-physics', sort_order: 23, front: "Moment of Inertia", back: "I = Σmr². The rotational analog of mass; measures an object's resistance to changes in rotational motion. Depends on mass distribution relative to the rotation axis." , front_translations: {"es":"Momento de Inércia","it":"Momento d'inerzia","de":"Trägheitsmoment","fr":"Moment d'inertie","tr":"Eylemsizlik Momenti","nl":"Traagheidsmoment","ru":"Момент инерции","zh":"转动惯量","pt_BR":"Momento de Inércia","pt_PT":"Momento de Inércia"}, back_translations: {"es":"I = Σmr². El análogo rotacional de la masa; mide a resistencia de un objeto a cambios en el movimiento rotacional. Depende de la distribución de masa en relación con el eixo de rotación.","it":"I = Σmr². L'analogue rotationnel della masse ; mesure la resistanza di un objet ai changements di il suo mouvement di rotazione. Depend della repartizione della masse per rapport all'axe di rotazione.","de":"I = Σmr². Das rotatorische Analogon der Masse; misst den Widerstand eines Körpers gegen Änderungen seiner Rotationsbewegung. Hängt von der Massenverteilung relativ zur Rotationsachse ab.","fr":"I = Σmr². L'analogue rotationnel de la masse ; mesure la résistance d'un objet aux changements de son mouvement de rotation. Dépend de la répartition de la masse par rapport à l'axe de rotation.","tr":"I = Σmr². Kütlenin dönel karşılığı; bir cismin dönme hareketindeki değişikliklere gösterdiği direnci ölçer. Dönme eksenine göre kütle dağılımına bağlıdır.","nl":"I = Σmr². Het rotationele analogon van massa; meet de weerstand van een object tegen veranderingen in roterende beweging. Hangt af van de massaverdeling ten opzichte van de rotatie-as.","ru":"I = Σmr². Вращательный аналог массы; измеряет сопротивление тела изменениям вращательного движения. Зависит от распределения масс относительно оси вращения.","zh":"I = Σmr²。质量的旋转类比；衡量物体对旋转运动变化的抵抗。取决于相对于转轴的质量分布。","pt_BR":"I = Σmr². O análogo rotacional da massa; mede a resistência de um objeto a mudanças no movimento rotacional. Depende da distribuição de massa em relação ao eixo de rotação.","pt_PT":"I = Σmr². O análogo rotacional da massa; mede a resistência de um objeto a alterações no movimento de rotação. Depende da distribuição de massa relativamente ao eixo de rotação."}},
  { id: 'dc-physics-0024', deck_id: 'deck-physics', sort_order: 24, front: "Hooke's Law", back: "F = -kx. The restoring force of a spring is proportional to its displacement from equilibrium and directed opposite to the displacement. k is the spring constant in N/m." , front_translations: {"es":"Ley de Hooke","it":"Legge di Hooke","de":"Hookesches Gesetz","fr":"Loi de Hooke","tr":"Hooke Yasası","nl":"Wet van Hooke","ru":"Закон Гука","zh":"胡克定律","pt_BR":"Lei de Hooke","pt_PT":"Lei de Hooke"}, back_translations: {"es":"F = -kx. La fuerza restauradora de una mola es proporcional al su deslocamento a partir de la posición de equilíbrio y direcionada opostamente al deslocamento. k es a constante elástica en N/m.","it":"F = -kx. La force di rappel di un ressort e proportionnelle al suo deplacement per rapport all'equilibrio e dirigee en sens oppose al deplacement. k e la costante di raidore en N/m.","de":"F = -kx. Die Rückstellkraft einer Feder ist proportional zur Auslenkung aus der Gleichgewichtslage und entgegengesetzt zur Auslenkungsrichtung. k ist die Federkonstante in N/m.","fr":"F = -kx. La force de rappel d'un ressort est proportionnelle à son déplacement par rapport à l'équilibre et dirigée en sens opposé au déplacement. k est la constante de raideur en N/m.","tr":"F = -kx. Bir yayın geri yükleme kuvveti, denge konumundan olan yer değiştirmeyle orantılı ve yer değiştirmenin tersi yönündedir. k, N/m cinsinden yay sabitidir.","nl":"F = -kx. De hersterkracht van een veer is evenredig met de uitwijking uit de evenwichtspositie en gericht tegengesteld aan de uitwijking. k is de veerconstante in N/m.","ru":"F = -kx. Сила упругости пружины пропорциональна смещению из положения равновесия и направлена противоположно смещению. k — коэффициент жёсткости пружины в Н/м.","zh":"F = -kx。弹簧的恢复力与其偏离平衡位置的位移成正比，方向与位移相反。k是弹簧常数，单位为N/m。","pt_BR":"F = -kx. A força restauradora de uma mola é proporcional ao seu deslocamento a partir da posição de equilíbrio e direcionada opostamente ao deslocamento. k é a constante elástica em N/m.","pt_PT":"F = -kx. A força restauradora de uma mola é proporcional ao seu deslocamento a partir da posição de equilíbrio e dirigida em sentido oposto ao deslocamento. k é a constante elástica em N/m."}},
  { id: 'dc-physics-0025', deck_id: 'deck-physics', sort_order: 25, front: "Simple Harmonic Motion Period (Spring)", back: "T = 2π√(m/k). The period of oscillation of a mass on a spring depends on the mass and the spring constant, independent of amplitude for small oscillations." , front_translations: {"es":"Período del Movimiento Harmonico Simples (Mola)","it":"Periode del movimento harmonico simple (ressort)","de":"Periode der einfachen harmonischen Schwingung (Feder)","fr":"Période du mouvement harmonique simple (ressort)","tr":"Basit Harmonik Hareket Periyodu (Yay)","nl":"Periode van eenvoudige harmonische beweging (veer)","ru":"Период простых гармонических колебаний (пружина)","zh":"简谐运动周期（弹簧）","pt_BR":"Período do Movimento Harmônico Simples (Mola)","pt_PT":"Período do Movimento Harmónico Simples (Mola)"}, back_translations: {"es":"T = 2π√(m/k). El período de oscilación de una masa en una mola depende de la masa y de la constante elástica, independentemente de la amplitude para pequeñas oscilaciones.","it":"T = 2π√(m/k). La periode d'oscillazione d'una masse su un ressort depend della masse e della costante di raidore, independamment dell'amplitude per di petites oscillazioni.","de":"T = 2π√(m/k). Die Schwingungsdauer einer Masse an einer Feder hängt von der Masse und der Federkonstante ab, unabhängig von der Amplitude bei kleinen Schwingungen.","fr":"T = 2π√(m/k). La période d'oscillation d'une masse sur un ressort dépend de la masse et de la constante de raideur, indépendamment de l'amplitude pour de petites oscillations.","tr":"T = 2π√(m/k). Bir yay üzerindeki kütlenin salınım periyodu, kütle ve yay sabitine bağlıdır; küçük salınımlar için genlikten bağımsızdır.","nl":"T = 2π√(m/k). De trillingstijd van een massa aan een veer hangt af van de massa en de veerconstante, onafhankelijk van de amplitude voor kleine trillingen.","ru":"T = 2π√(m/k). Период колебаний груза на пружине зависит от массы и жёсткости пружины, независимо от амплитуды при малых колебаниях.","zh":"T = 2π√(m/k)。弹簧上质量的振荡周期取决于质量和弹簧常数，与小振幅无关。","pt_BR":"T = 2π√(m/k). O período de oscilação de uma massa em uma mola depende da massa e da constante elástica, independentemente da amplitude para pequenas oscilações.","pt_PT":"T = 2π√(m/k). O período de oscilação de uma massa numa mola depende da massa e da constante elástica, independentemente da amplitude para pequenas oscilações."}},
  { id: 'dc-physics-0026', deck_id: 'deck-physics', sort_order: 26, front: "Simple Pendulum Period", back: "T = 2π√(L/g). The period of a simple pendulum depends only on its length and gravitational acceleration, not on the mass of the bob or amplitude (for small angles)." , front_translations: {"es":"Período del Pendulo Simples","it":"Periode d'un pendule simple","de":"Periode eines einfachen Pendels","fr":"Période d'un pendule simple","tr":"Basit Sarkaç Periyodu","nl":"Periode van een eenvoudig slinger","ru":"Период простого маятника","zh":"单摆周期","pt_BR":"Período do Pêndulo Simples","pt_PT":"Período do Pêndulo Simples"}, back_translations: {"es":"T = 2π√(L/g). El período de un pendulo simples depende solo del su comprimento y de la aceleración gravitacional, no de la masa del pendulo o de la amplitude (para ángulos pequeños).","it":"T = 2π√(L/g). La periode di un pendule simple depend uniquement della sua longuore e dell'accelerazione gravitationnelle, della masse del pendule ni dell'amplitude (per i petits angles).","de":"T = 2π√(L/g). Die Periode eines einfachen Pendels hängt nur von seiner Länge und der Gravitationsbeschleunigung ab, nicht von der Masse des Pendelkörpers oder der Amplitude (bei kleinen Winkeln).","fr":"T = 2π√(L/g). La période d'un pendule simple dépend uniquement de sa longueur et de l'accélération gravitationnelle, pas de la masse du pendule ni de l'amplitude (pour les petits angles).","tr":"T = 2π√(L/g). Basit bir sarkaç periyodu yalnızca uzunluğuna ve yer çekimi ivmesine bağlıdır; sarkaç kütlesine veya genliğine bağlı değildir (küçük açılar için).","nl":"T = 2π√(L/g). De periode van een eenvoudig slinger hangt alleen af van de lengte en de zwaartekrachtsversnelling, niet van de massa van het gewicht of de amplitude (voor kleine hoeken).","ru":"T = 2π√(L/g). Период простого маятника зависит только от его длины и ускорения свободного падения, но не от массы груза или амплитуды (при малых углах).","zh":"T = 2π√(L/g)。单摆的周期只取决于摆长和重力加速度，与摆球质量或摆幅无关（适用于小角度）。","pt_BR":"T = 2π√(L/g). O período de um pêndulo simples depende apenas do seu comprimento e da aceleração gravitacional, não da massa do pêndulo ou da amplitude (para ângulos pequenos).","pt_PT":"T = 2π√(L/g). O período de um pêndulo simples depende apenas do seu comprimento e da aceleração gravitacional, não da massa do pêndulo ou da amplitude (para ângulos pequenos)."}},
  { id: 'dc-physics-0027', deck_id: 'deck-physics', sort_order: 27, front: "Ohm's Law", back: "V = IR. The voltage across a conductor equals the current through it multiplied by its resistance. Doubling voltage doubles current if resistance is constant." , front_translations: {"es":"Ley de Ohm","it":"Legge di Ohm","de":"Ohmsches Gesetz","fr":"Loi d'Ohm","tr":"Ohm Yasası","nl":"Wet van Ohm","ru":"Закон Ома","zh":"欧姆定律","pt_BR":"Lei de Ohm","pt_PT":"Lei de Ohm"}, back_translations: {"es":"V = IR. La tensão en un condutor es igual a la corrente que flui por ele multiplicada por la su resistencia. Dobrar a tensão dobra a corrente se a resistencia for constante.","it":"V = IR. La tension ai bornes di un conductore e egale al courant che il traverse multiplie per la sua resistanza. Doubler la tension double il courant se la resistanza e costante.","de":"V = IR. Die Spannung an einem Leiter ist gleich dem durch ihn fließenden Strom multipliziert mit seinem Widerstand. Eine Verdoppelung der Spannung verdoppelt den Strom, wenn der Widerstand konstant bleibt.","fr":"V = IR. La tension aux bornes d'un conducteur est égale au courant qui le traverse multiplié par sa résistance. Doubler la tension double le courant si la résistance est constante.","tr":"V = IR. Bir iletkenin uçları arasındaki gerilim, içinden geçen akım ile direncinin çarpımına eşittir. Direnç sabit ise gerilimi iki katına çıkarmak akımı da iki katına çıkarır.","nl":"V = IR. De spanning over een geleider is gelijk aan de stroom die erdoor loopt vermenigvuldigd met de weerstand. Het verdubbelen van de spanning verdubbelt de stroom als de weerstand constant is.","ru":"V = IR. Напряжение на проводнике равно силе тока через него, умноженной на его сопротивление. При удвоении напряжения ток удваивается, если сопротивление постоянно.","zh":"V = IR。导体两端的电压等于流过它的电流乘以其电阻。若电阻不变，电压加倍则电流加倍。","pt_BR":"V = IR. A tensão em um condutor é igual à corrente que flui por ele multiplicada pela sua resistência. Dobrar a tensão dobra a corrente se a resistência for constante.","pt_PT":"V = IR. A tensão num condutor é igual à corrente que flui nele multiplicada pela sua resistência. Duplicar a tensão duplica a corrente se a resistência for constante."}},
  { id: 'dc-physics-0028', deck_id: 'deck-physics', sort_order: 28, front: "Electric Power", back: "P = IV = I²R = V²/R. Electrical power dissipated in a resistor equals current times voltage. Equivalent forms can be derived using Ohm's Law." , front_translations: {"es":"Potencia Eléctrica","it":"Puissanza elettrico","de":"Elektrische Leistung","fr":"Puissance électrique","tr":"Elektrik Gücü","nl":"Elektrisch vermogen","ru":"Электрическая мощность","zh":"电功率","pt_BR":"Potência Elétrica","pt_PT":"Potência Elétrica"}, back_translations: {"es":"P = IV = I²R = V²/R. La potencia eléctrica dissipada en un resistor es igual a la corrente veces a tensão. Formas equivalentes pueden ser derivadas usando a Ley de Ohm.","it":"P = IV = I²R = V²/R. La puissanza electrico dissipee in una resistanza e egale al courant multiplie per la tension. Dei formes equivalentes possono etre derivees à partir della loi d'Ohm.","de":"P = IV = I²R = V²/R. Die in einem Widerstand dissipierte elektrische Leistung ist gleich Strom mal Spannung. Äquivalente Formen lassen sich mit dem Ohmschen Gesetz ableiten.","fr":"P = IV = I²R = V²/R. La puissance électrique dissipée dans une résistance est égale au courant multiplié par la tension. Des formes équivalentes peuvent être dérivées à partir de la loi d'Ohm.","tr":"P = IV = I²R = V²/R. Bir dirençte harcanan elektrik gücü akım ile gerilimin çarpımına eşittir. Eşdeğer ifadeler Ohm yasası kullanılarak türetilebilir.","nl":"P = IV = I²R = V²/R. Het elektrisch vermogen dat in een weerstand wordt gedissipeerd, is gelijk aan stroom maal spanning. Equivalente vormen kunnen worden afgeleid met de wet van Ohm.","ru":"P = IV = I²R = V²/R. Электрическая мощность, рассеиваемая в резисторе, равна произведению тока на напряжение. Эквивалентные формы получаются с помощью закона Ома.","zh":"P = IV = I²R = V²/R。电阻上消耗的电功率等于电流乘以电压。等效形式可由欧姆定律推导得出。","pt_BR":"P = IV = I²R = V²/R. A potência elétrica dissipada em um resistor é igual à corrente vezes a tensão. Formas equivalentes podem ser derivadas usando a Lei de Ohm.","pt_PT":"P = IV = I²R = V²/R. A potência elétrica dissipada num resistor é igual à corrente vezes a tensão. Formas equivalentes podem ser derivadas usando a Lei de Ohm."}},
  { id: 'dc-physics-0029', deck_id: 'deck-physics', sort_order: 29, front: "Coulomb's Law", back: "F = kq₁q₂/r². The electrostatic force between two point charges is proportional to the product of the charges and inversely proportional to the square of the distance. k ≈ 8.99×10⁹ N·m²/C²." , front_translations: {"es":"Ley de Coulomb","it":"Legge di Coulomb","de":"Coulombsches Gesetz","fr":"Loi de Coulomb","tr":"Coulomb Yasası","nl":"Wet van Coulomb","ru":"Закон Кулона","zh":"库仑定律","pt_BR":"Lei de Coulomb","pt_PT":"Lei de Coulomb"}, back_translations: {"es":"F = kq₁q₂/r². La fuerza eletrostática entre de los cargas pontuais es proporcional al producto de las cargas y inversamente proporcional al cuadrado de la distancia. k ≈ 8,99×10⁹ N·m²/C².","it":"F = kq₁q₂/r². La force electrostatico tra deux charges ponctuelles e proportionnelle al prodotto dei charges e inversement proportionnelle al carre della distanza. k ≈ 8,99×10⁹ N·m²/C².","de":"F = kq₁q₂/r². Die elektrostatische Kraft zwischen zwei Punktladungen ist proportional zum Produkt der Ladungen und umgekehrt proportional zum Quadrat des Abstands. k ≈ 8,99×10⁹ N·m²/C².","fr":"F = kq₁q₂/r². La force électrostatique entre deux charges ponctuelles est proportionnelle au produit des charges et inversement proportionnelle au carré de la distance. k ≈ 8,99×10⁹ N·m²/C².","tr":"F = kq₁q₂/r². İki nokta yük arasındaki elektrostatik kuvvet, yüklerin çarpımıyla orantılı ve aralarındaki mesafenin karesiyle ters orantılıdır. k ≈ 8,99×10⁹ N·m²/C².","nl":"F = kq₁q₂/r². De elektrostatische kracht tussen twee puntladingen is evenredig met het product van de ladingen en omgekeerd evenredig met het kwadraat van de afstand. k ≈ 8,99×10⁹ N·m²/C².","ru":"F = kq₁q₂/r². Электростатическая сила между двумя точечными зарядами пропорциональна произведению зарядов и обратно пропорциональна квадрату расстояния. k ≈ 8,99×10⁹ Н·м²/Кл².","zh":"F = kq₁q₂/r²。两个点电荷之间的静电力与电荷量之积成正比，与距离的平方成反比。k ≈ 8.99×10⁹ N·m²/C²。","pt_BR":"F = kq₁q₂/r². A força eletrostática entre duas cargas pontuais é proporcional ao produto das cargas e inversamente proporcional ao quadrado da distância. k ≈ 8,99×10⁹ N·m²/C².","pt_PT":"F = kq₁q₂/r². A força eletrostática entre duas cargas pontuais é proporcional ao produto das cargas e inversamente proporcional ao quadrado da distância. k ≈ 8,99×10⁹ N·m²/C²."}},
  { id: 'dc-physics-0030', deck_id: 'deck-physics', sort_order: 30, front: "Electric Field", back: "E = F/q = kQ/r². The electric field at a point is the force per unit positive test charge placed at that point. It points away from positive charges and toward negative charges." , front_translations: {"es":"Campo Eléctrico","it":"Campo elettrico","de":"Elektrisches Feld","fr":"Champ électrique","tr":"Elektrik Alanı","nl":"Elektrisch veld","ru":"Электрическое поле","zh":"电场","pt_BR":"Campo Elétrico","pt_PT":"Campo Elétrico"}, back_translations: {"es":"Y = F/q = kQ/r². El campo eléctrico en un punto es a fuerza por unidad de carga de prueba positiva colocada nesse punto. Aponta para longe de cargas positivas y en dirección a cargas negativas.","it":"E = F/q = kQ/r². Il champ electrico en un point e la force per unite di charge test positive placee en questo point. Il pointe en s'eloignant dei charges positives e verso i charges negatives.","de":"E = F/q = kQ/r². Das elektrische Feld an einem Punkt ist die Kraft pro positiver Probeladung an diesem Punkt. Es zeigt von positiven Ladungen weg und zu negativen Ladungen hin.","fr":"E = F/q = kQ/r². Le champ électrique en un point est la force par unité de charge test positive placée en ce point. Il pointe en s'éloignant des charges positives et vers les charges négatives.","tr":"E = F/q = kQ/r². Bir noktadaki elektrik alanı, o noktaya yerleştirilen birim pozitif test yüküne etki eden kuvvettir. Pozitif yüklerden uzağa, negatif yüklere doğru yönelir.","nl":"E = F/q = kQ/r². Het elektrisch veld op een punt is de kracht per eenheid positieve testlading op dat punt. Het wijst weg van positieve ladingen en naar negatieve ladingen.","ru":"E = F/q = kQ/r². Электрическое поле в точке — это сила, действующая на единичный положительный пробный заряд в этой точке. Поле направлено от положительных зарядов и к отрицательным.","zh":"E = F/q = kQ/r²。某点的电场是放置在该点的单位正试验电荷所受的力。电场从正电荷指向负电荷。","pt_BR":"E = F/q = kQ/r². O campo elétrico em um ponto é a força por unidade de carga de teste positiva colocada nesse ponto. Aponta para longe de cargas positivas e em direção a cargas negativas.","pt_PT":"E = F/q = kQ/r². O campo elétrico num ponto é a força por unidade de carga de teste positiva colocada nesse ponto. Aponta para longe de cargas positivas e em direção a cargas negativas."}},
  { id: 'dc-physics-0031', deck_id: 'deck-physics', sort_order: 31, front: "Electric Potential Energy", back: "U = kq₁q₂/r. Potential energy stored in a pair of point charges. Positive when charges have the same sign (repulsive), negative when opposite (attractive)." , front_translations: {"es":"Energía Potencial Eléctrica","it":"Energie potenziale elettrico","de":"Elektrische potentielle Energie","fr":"Énergie potentielle électrique","tr":"Elektrik Potansiyel Enerjisi","nl":"Elektrische potentiële energie","ru":"Электрическая потенциальная энергия","zh":"电势能","pt_BR":"Energia Potencial Elétrica","pt_PT":"Energia Potencial Elétrica"}, back_translations: {"es":"U = kq₁q₂/r. Energía potencial almacenada en un par de cargas pontuais. Positiva cuando las cargas tienen el mismo señal (repulsiva), negativa cuando opostas (atrativa).","it":"U = kq₁q₂/r. Energie potenziale stockee in una paire di charges ponctuelles. Positive quando i charges hanno il stesso signe (repulsif), negative quando elles sono opposees (attractif).","de":"U = kq₁q₂/r. In einem Paar von Punktladungen gespeicherte potentielle Energie. Positiv, wenn die Ladungen das gleiche Vorzeichen haben (abstoßend), negativ bei entgegengesetzten Vorzeichen (anziehend).","fr":"U = kq₁q₂/r. Énergie potentielle stockée dans une paire de charges ponctuelles. Positive quand les charges ont le même signe (répulsif), négative quand elles sont opposées (attractif).","tr":"U = kq₁q₂/r. Bir çift nokta yükte depolanan potansiyel enerji. Yükler aynı işaretliyse pozitif (itici), zıt işaretliyse negatif (çekici).","nl":"U = kq₁q₂/r. Potentiële energie opgeslagen in een paar puntladingen. Positief wanneer ladingen hetzelfde teken hebben (afstotend), negatief wanneer tegengesteld (aantrekkend).","ru":"U = kq₁q₂/r. Потенциальная энергия, хранящаяся в паре точечных зарядов. Положительная, если заряды одного знака (отталкивание), отрицательная — противоположного (притяжение).","zh":"U = kq₁q₂/r。存储在一对点电荷中的势能。当电荷符号相同时为正（排斥），符号相反时为负（吸引）。","pt_BR":"U = kq₁q₂/r. Energia potencial armazenada em um par de cargas pontuais. Positiva quando as cargas têm o mesmo sinal (repulsiva), negativa quando opostas (atrativa).","pt_PT":"U = kq₁q₂/r. Energia potencial armazenada num par de cargas pontuais. Positiva quando as cargas têm o mesmo sinal (repulsiva), negativa quando opostas (atrativa)."}},
  { id: 'dc-physics-0032', deck_id: 'deck-physics', sort_order: 32, front: "Electric Potential (Voltage)", back: "V = kQ/r = U/q. Electric potential is the potential energy per unit charge. Measured in volts (V = J/C). Scalar quantity unlike electric field." , front_translations: {"es":"Potencial Eléctrico (Tensão)","it":"Potenziale elettrico (tensione)","de":"Elektrisches Potential (Spannung)","fr":"Potentiel électrique (Tension)","tr":"Elektrik Potansiyeli (Gerilim)","nl":"Elektrisch potentiaal (Spanning)","ru":"Электрический потенциал (Напряжение)","zh":"电势（电压）","pt_BR":"Potencial Elétrico (Tensão)","pt_PT":"Potencial Elétrico (Tensão)"}, back_translations: {"es":"V = kQ/r = U/q. El potencial eléctrico es a energía potencial por unidad de carga. Medido en volts (V = J/C). Grandeza escalar, al contrário del campo eléctrico.","it":"V = kQ/r = U/q. Il potentiel electrico e l'energia potenziale per unite di charge. Mesure en volts (V = J/C). Grandore scalaire, contrairement al champ electrico.","de":"V = kQ/r = U/q. Das elektrische Potential ist die potentielle Energie pro Ladungseinheit. Gemessen in Volt (V = J/C). Skalargröße, im Gegensatz zum elektrischen Feld.","fr":"V = kQ/r = U/q. Le potentiel électrique est l'énergie potentielle par unité de charge. Mesuré en volts (V = J/C). Grandeur scalaire, contrairement au champ électrique.","tr":"V = kQ/r = U/q. Elektrik potansiyeli, birim yük başına düşen potansiyel enerjidir. Volt cinsinden ölçülür (V = J/C). Elektrik alanının aksine skaler bir büyüklüktür.","nl":"V = kQ/r = U/q. Elektrisch potentiaal is de potentiële energie per eenheidslading. Gemeten in volt (V = J/C). Scalaire grootheid in tegenstelling tot het elektrisch veld.","ru":"V = kQ/r = U/q. Электрический потенциал — это потенциальная энергия на единицу заряда. Измеряется в вольтах (В = Дж/Кл). Скалярная величина, в отличие от электрического поля.","zh":"V = kQ/r = U/q。电势是单位电荷的势能。以伏特为单位（V = J/C）。与电场不同，电势是标量。","pt_BR":"V = kQ/r = U/q. O potencial elétrico é a energia potencial por unidade de carga. Medido em volts (V = J/C). Grandeza escalar, ao contrário do campo elétrico.","pt_PT":"V = kQ/r = U/q. O potencial elétrico é a energia potencial por unidade de carga. Medido em volts (V = J/C). Grandeza escalar, ao contrário do campo elétrico."}},
  { id: 'dc-physics-0033', deck_id: 'deck-physics', sort_order: 33, front: "Capacitance", back: "C = Q/V. Capacitance is the ratio of charge stored to voltage across a capacitor. SI unit is the farad (F). Energy stored: U = ½CV²." , front_translations: {"es":"Capacitancia","it":"Capacità elettrica","de":"Kapazität","fr":"Capacité électrique","tr":"Elektrik Kapasitansı","nl":"Capaciteit","ru":"Электрическая ёмкость","zh":"电容","pt_BR":"Capacitância","pt_PT":"Capacitância"}, back_translations: {"es":"C = Q/V. La capacitancia es a razão de la carga almacenada por la tensão en un capacitor. La unidad SI es el farad (F). Energía almacenada: U = ½CV².","it":"C = Q/V. La capacite e il rapport della charge stockee alla tension ai bornes di un condensatore. L'unite SI e il farad (F). Energie stockee : U = ½CV².","de":"C = Q/V. Die Kapazität ist das Verhältnis der gespeicherten Ladung zur Spannung an einem Kondensator. SI-Einheit ist das Farad (F). Gespeicherte Energie: U = ½CV².","fr":"C = Q/V. La capacité est le rapport de la charge stockée à la tension aux bornes d'un condensateur. L'unité SI est le farad (F). Énergie stockée : U = ½CV².","tr":"C = Q/V. Kapasitans, bir kondansatörde depolanan yükün gerilime oranıdır. SI birimi farad'dır (F). Depolanan enerji: U = ½CV².","nl":"C = Q/V. Capaciteit is de verhouding van opgeslagen lading tot spanning over een condensator. De SI-eenheid is de farad (F). Opgeslagen energie: U = ½CV².","ru":"C = Q/V. Ёмкость — это отношение заряда, хранящегося на конденсаторе, к напряжению на нём. Единица СИ — фарад (Ф). Запасённая энергия: U = ½CV².","zh":"C = Q/V。电容是电容器上存储的电荷与两端电压之比。SI单位为法拉（F）。存储能量：U = ½CV²。","pt_BR":"C = Q/V. A capacitância é a razão da carga armazenada pela tensão em um capacitor. A unidade SI é o farad (F). Energia armazenada: U = ½CV².","pt_PT":"C = Q/V. A capacitância é a razão da carga armazenada pela tensão num condensador. A unidade SI é o farad (F). Energia armazenada: U = ½CV²."}},
  { id: 'dc-physics-0034', deck_id: 'deck-physics', sort_order: 34, front: "Resistors in Series", back: "R_total = R₁ + R₂ + R₃ + ... Total resistance is the sum of individual resistances. Current is the same through all resistors; voltage divides among them." , front_translations: {"es":"Resistores en Série","it":"Resistanze en serie","de":"Widerstände in Reihenschaltung","fr":"Résistances en série","tr":"Seri Bağlı Dirençler","nl":"Weerstanden in serie","ru":"Резисторы в последовательном соединении","zh":"串联电阻","pt_BR":"Resistores em Série","pt_PT":"Resistores em Série"}, back_translations: {"es":"R_total = R₁ + R₂ + R₃ + ... La resistencia total es a suma de las resistencias individuais. La corrente es a misma en todos los resistores; a tensão se divide entre eles.","it":"R_total = R₁ + R₂ + R₃ + ... La resistanza totale e la somme dei resistanze individuelles. Il courant e il stesso in tutte i resistanze ; la tension se repartit tra elles.","de":"R_gesamt = R₁ + R₂ + R₃ + ... Der Gesamtwiderstand ist die Summe der Einzelwiderstände. Der Strom ist durch alle Widerstände gleich; die Spannung verteilt sich auf sie.","fr":"R_total = R₁ + R₂ + R₃ + ... La résistance totale est la somme des résistances individuelles. Le courant est le même dans toutes les résistances ; la tension se répartit entre elles.","tr":"R_toplam = R₁ + R₂ + R₃ + ... Toplam direnç, bireysel dirençlerin toplamıdır. Akım tüm dirençlerden aynı geçer; gerilim aralarında paylaşılır.","nl":"R_totaal = R₁ + R₂ + R₃ + ... De totale weerstand is de som van de individuele weerstanden. De stroom is gelijk door alle weerstanden; de spanning verdeelt zich over hen.","ru":"R_общ = R₁ + R₂ + R₃ + ... Суммарное сопротивление равно сумме отдельных сопротивлений. Ток одинаков через все резисторы; напряжение распределяется между ними.","zh":"R_总 = R₁ + R₂ + R₃ + ...。总电阻是各电阻之和。所有电阻中的电流相同；电压分配在各电阻上。","pt_BR":"R_total = R₁ + R₂ + R₃ + ... A resistência total é a soma das resistências individuais. A corrente é a mesma em todos os resistores; a tensão se divide entre eles.","pt_PT":"R_total = R₁ + R₂ + R₃ + ... A resistência total é a soma das resistências individuais. A corrente é a mesma em todos os resistores; a tensão divide-se entre eles."}},
  { id: 'dc-physics-0035', deck_id: 'deck-physics', sort_order: 35, front: "Resistors in Parallel", back: "1/R_total = 1/R₁ + 1/R₂ + ... Total resistance is less than any individual resistance. Voltage is the same across all resistors; current divides among them." , front_translations: {"es":"Resistores en Paralelo","it":"Resistanze en parallele","de":"Widerstände in Parallelschaltung","fr":"Résistances en parallèle","tr":"Paralel Bağlı Dirençler","nl":"Weerstanden in parallel","ru":"Резисторы в параллельном соединении","zh":"并联电阻","pt_BR":"Resistores em Paralelo","pt_PT":"Resistores em Paralelo"}, back_translations: {"es":"1/R_total = 1/R₁ + 1/R₂ + ... La resistencia total es menor del que cualquier resistencia individual. La tensão es a misma en todos los resistores; a corrente se divide entre eles.","it":"1/R_total = 1/R₁ + 1/R₂ + ... La resistanza totale e inferieure à n'importe quelle resistanza individuelle. La tension e la stesso ai bornes di tutte i resistanze ; il courant se repartit tra elles.","de":"1/R_gesamt = 1/R₁ + 1/R₂ + ... Der Gesamtwiderstand ist kleiner als jeder einzelne Widerstand. Die Spannung ist an allen Widerständen gleich; der Strom verteilt sich auf sie.","fr":"1/R_total = 1/R₁ + 1/R₂ + ... La résistance totale est inférieure à n'importe quelle résistance individuelle. La tension est la même aux bornes de toutes les résistances ; le courant se répartit entre elles.","tr":"1/R_toplam = 1/R₁ + 1/R₂ + ... Toplam direnç, herhangi bir bireysel dirençten küçüktür. Gerilim tüm dirençlerde aynıdır; akım aralarında paylaşılır.","nl":"1/R_totaal = 1/R₁ + 1/R₂ + ... De totale weerstand is kleiner dan elke individuele weerstand. De spanning is gelijk over alle weerstanden; de stroom verdeelt zich over hen.","ru":"1/R_общ = 1/R₁ + 1/R₂ + ... Суммарное сопротивление меньше любого отдельного. Напряжение одинаково на всех резисторах; ток распределяется между ними.","zh":"1/R_总 = 1/R₁ + 1/R₂ + ...。总电阻小于任何单个电阻。所有电阻两端的电压相同；电流分配在各电阻中。","pt_BR":"1/R_total = 1/R₁ + 1/R₂ + ... A resistência total é menor do que qualquer resistência individual. A tensão é a mesma em todos os resistores; a corrente se divide entre eles.","pt_PT":"1/R_total = 1/R₁ + 1/R₂ + ... A resistência total é menor do que qualquer resistência individual. A tensão é a mesma em todos os resistores; a corrente divide-se entre eles."}},
  { id: 'dc-physics-0036', deck_id: 'deck-physics', sort_order: 36, front: "Kirchhoff's Current Law (KCL)", back: "The sum of all currents entering a node equals the sum of all currents leaving it. Based on conservation of charge: no charge accumulates at a junction." , front_translations: {"es":"Ley de Kirchhoff para Correntes (LKC)","it":"Loi dei nœuds di Kirchhoff (LNK)","de":"Kirchhoffsches Stromgesetz (KSG)","fr":"Loi des nœuds de Kirchhoff (LNK)","tr":"Kirchhoff'un Akım Yasası (KAY)","nl":"Wet van Kirchhoff voor stromen (KSW)","ru":"Первый закон Кирхгофа (ПЗК)","zh":"基尔霍夫电流定律（KCL）","pt_BR":"Lei de Kirchhoff para Correntes (LKC)","pt_PT":"Lei de Kirchhoff para as Correntes (LKC)"}, back_translations: {"es":"La suma de todas las correntes que entram en un nó es igual a la suma de todas las correntes que saem de él. Se basa en la conservación de carga: ninguna carga se acumula en una junción.","it":"La somme di tutti i courants entrant in un nœud e egale alla somme di tutti i courants che en sortent. Base su la conservazione della charge : aucune charge non s'accumule en un nœud.","de":"Die Summe aller in einen Knoten einfließenden Ströme ist gleich der Summe aller abfließenden Ströme. Basiert auf der Ladungserhaltung: An einem Knotenpunkt sammelt sich keine Ladung an.","fr":"La somme de tous les courants entrant dans un nœud est égale à la somme de tous les courants qui en sortent. Basé sur la conservation de la charge : aucune charge ne s'accumule en un nœud.","tr":"Bir düğüme giren tüm akımların toplamı, düğümden çıkan tüm akımların toplamına eşittir. Yük korunumuna dayanır: bir düğümde yük birikmez.","nl":"De som van alle stromen die een knooppunt binnenkomen, is gelijk aan de som van alle stromen die het verlaten. Gebaseerd op ladingsbehoud: er hoopt zich geen lading op in een knooppunt.","ru":"Сумма всех токов, входящих в узел, равна сумме всех токов, выходящих из него. Основан на законе сохранения заряда: заряд не накапливается в узле.","zh":"流入节点的所有电流之和等于流出节点的所有电流之和。基于电荷守恒：节点处不积累电荷。","pt_BR":"A soma de todas as correntes que entram em um nó é igual à soma de todas as correntes que saem dele. Baseia-se na conservação de carga: nenhuma carga se acumula em uma junção.","pt_PT":"A soma de todas as correntes que entram num nó é igual à soma de todas as correntes que saem dele. Baseia-se na conservação de carga: nenhuma carga se acumula numa junção."}},
  { id: 'dc-physics-0037', deck_id: 'deck-physics', sort_order: 37, front: "Kirchhoff's Voltage Law (KVL)", back: "The sum of all voltage drops around any closed loop in a circuit equals zero. Based on conservation of energy: energy gained from sources equals energy lost in resistors." , front_translations: {"es":"Ley de Kirchhoff para Tensões (LKT)","it":"Loi dei mailles di Kirchhoff (LMK)","de":"Kirchhoffsches Spannungsgesetz (KSG)","fr":"Loi des mailles de Kirchhoff (LMK)","tr":"Kirchhoff'un Gerilim Yasası (KGY)","nl":"Wet van Kirchhoff voor spanningen (KSW)","ru":"Второй закон Кирхгофа (ВЗК)","zh":"基尔霍夫电压定律（KVL）","pt_BR":"Lei de Kirchhoff para Tensões (LKT)","pt_PT":"Lei de Kirchhoff para as Tensões (LKT)"}, back_translations: {"es":"La suma de todas las caídas de tensão en cualquier malha fechada de un circuito es igual a zero. Se basa en la conservación de energía: a energía ganha en las fontes es igual a la energía perdida en los resistores.","it":"La somme di tutte i chutes di tension in tutta boucle fermee di un circuit e egale à zero. Base su la conservazione dell'energia : l'energia gagnee per i sources e egale all'energia perdue in i resistanze.","de":"Die Summe aller Spannungsabfälle in einer geschlossenen Masche eines Stromkreises ist gleich null. Basiert auf der Energieerhaltung: Die von Quellen gewonnene Energie ist gleich der in Widerständen verlorenen Energie.","fr":"La somme de toutes les chutes de tension dans toute boucle fermée d'un circuit est égale à zéro. Basé sur la conservation de l'énergie : l'énergie gagnée par les sources est égale à l'énergie perdue dans les résistances.","tr":"Bir devredeki herhangi bir kapalı döngü boyunca tüm gerilim düşümlerinin toplamı sıfıra eşittir. Enerji korunumuna dayanır: kaynaklardan alınan enerji, dirençlerde harcanan enerjiye eşittir.","nl":"De som van alle spanningsdalingen in een willekeurige gesloten lus van een circuit is gelijk aan nul. Gebaseerd op energiebehoud: energie gewonnen door bronnen is gelijk aan energie verloren in weerstanden.","ru":"Сумма всех падений напряжения в любом замкнутом контуре цепи равна нулю. Основан на законе сохранения энергии: энергия, полученная от источников, равна энергии, потерянной в резисторах.","zh":"电路中任意闭合回路中所有电压降之和等于零。基于能量守恒：电源提供的能量等于电阻上消耗的能量。","pt_BR":"A soma de todas as quedas de tensão em qualquer malha fechada de um circuito é igual a zero. Baseia-se na conservação de energia: a energia ganha nas fontes é igual à energia perdida nos resistores.","pt_PT":"A soma de todas as quedas de tensão em qualquer malha fechada de um circuito é igual a zero. Baseia-se na conservação de energia: a energia ganha nas fontes é igual à energia perdida nos resistores."}},
  { id: 'dc-physics-0038', deck_id: 'deck-physics', sort_order: 38, front: "Magnetic Force on a Moving Charge", back: "F = qv × B = qvB·sinθ. The magnetic force on a moving charge is perpendicular to both velocity and field. It does no work on the charge." , front_translations: {"es":"Fuerza Magnética sobre una Carga en Movimiento","it":"Force magnetico su unha charge en movimento","de":"Magnetische Kraft auf eine bewegte Ladung","fr":"Force magnétique sur une charge en mouvement","tr":"Hareketli Bir Yüke Etkiyen Manyetik Kuvvet","nl":"Magnetische kracht op een bewegende lading","ru":"Магнитная сила, действующая на движущийся заряд","zh":"运动电荷所受的磁力","pt_BR":"Força Magnética sobre uma Carga em Movimento","pt_PT":"Força Magnética sobre uma Carga em Movimento"}, back_translations: {"es":"F = qv × B = qvB·sinθ. La fuerza magnética sobre una carga en movimiento es perpendicular tanto a la velocidad quanto al campo. Ela no realiza trabajo sobre a carga.","it":"F = qv × B = qvB·sinθ. La force magnetico su una charge en mouvement e perpendiculaire allo stesso tempo alla vitesse e al champ. Elle non fait aucun travail su la charge.","de":"F = qv × B = qvB·sinθ. Die magnetische Kraft auf eine bewegte Ladung ist senkrecht sowohl zur Geschwindigkeit als auch zum Feld. Sie verrichtet keine Arbeit an der Ladung.","fr":"F = qv × B = qvB·sinθ. La force magnétique sur une charge en mouvement est perpendiculaire à la fois à la vitesse et au champ. Elle ne fait aucun travail sur la charge.","tr":"F = qv × B = qvB·sinθ. Hareketli bir yüke etki eden manyetik kuvvet, hem hıza hem de alana diktir. Yük üzerinde iş yapmaz.","nl":"F = qv × B = qvB·sinθ. De magnetische kracht op een bewegende lading staat loodrecht op zowel de snelheid als het veld. Het verricht geen arbeid op de lading.","ru":"F = qv × B = qvB·sinθ. Магнитная сила на движущийся заряд перпендикулярна как скорости, так и полю. Она не совершает работы над зарядом.","zh":"F = qv × B = qvB·sinθ。运动电荷所受的磁力垂直于速度和磁场两者。磁力对电荷不做功。","pt_BR":"F = qv × B = qvB·sinθ. A força magnética sobre uma carga em movimento é perpendicular tanto à velocidade quanto ao campo. Ela não realiza trabalho sobre a carga.","pt_PT":"F = qv × B = qvB·sinθ. A força magnética sobre uma carga em movimento é perpendicular tanto à velocidade como ao campo. Não realiza trabalho sobre a carga."}},
  { id: 'dc-physics-0039', deck_id: 'deck-physics', sort_order: 39, front: "Magnetic Force on a Current-Carrying Wire", back: "F = IL × B = BIL·sinθ. A current-carrying wire in a magnetic field experiences a force. Direction given by the right-hand rule or F = IL × B." , front_translations: {"es":"Fuerza Magnética sobre un Fio Condutor de Corrente","it":"Force magnetico su un fil parcouru per un corrente","de":"Magnetische Kraft auf einen stromdurchflossenen Leiter","fr":"Force magnétique sur un fil parcouru par un courant","tr":"Akım Taşıyan Bir Tele Etkiyen Manyetik Kuvvet","nl":"Magnetische kracht op een stroomvoerende draad","ru":"Магнитная сила, действующая на проводник с током","zh":"通电导线所受的磁力","pt_BR":"Força Magnética sobre um Fio Condutor de Corrente","pt_PT":"Força Magnética sobre um Fio Condutor de Corrente"}, back_translations: {"es":"F = IL × B = BIL·sinθ. Un fio condutor de corrente en un campo magnético experimenta una fuerza. La dirección es dada por la regra de la mano direita o F = IL × B.","it":"F = IL × B = BIL·sinθ. Un fil parcouru per un courant in un champ magnetico subit una force. La direczione e donnee per la regle della main droite o F = IL × B.","de":"F = IL × B = BIL·sinθ. Ein stromdurchflossener Leiter in einem Magnetfeld erfährt eine Kraft. Die Richtung ergibt sich aus der Rechten-Hand-Regel oder F = IL × B.","fr":"F = IL × B = BIL·sinθ. Un fil parcouru par un courant dans un champ magnétique subit une force. La direction est donnée par la règle de la main droite ou F = IL × B.","tr":"F = IL × B = BIL·sinθ. Manyetik alan içindeki akım taşıyan bir tel kuvvete maruz kalır. Yön, sağ el kuralıyla veya F = IL × B ile belirlenir.","nl":"F = IL × B = BIL·sinθ. Een stroomvoerende draad in een magnetisch veld ondervindt een kracht. Richting gegeven door de rechterhandregel of F = IL × B.","ru":"F = IL × B = BIL·sinθ. Проводник с током в магнитном поле испытывает силу. Направление определяется правилом правой руки или F = IL × B.","zh":"F = IL × B = BIL·sinθ。磁场中通电导线受到安培力。方向由右手定则或 F = IL × B 确定。","pt_BR":"F = IL × B = BIL·sinθ. Um fio condutor de corrente em um campo magnético experimenta uma força. A direção é dada pela regra da mão direita ou F = IL × B.","pt_PT":"F = IL × B = BIL·sinθ. Um fio condutor de corrente num campo magnético experimenta uma força. A direção é dada pela regra da mão direita ou F = IL × B."}},
  { id: 'dc-physics-0040', deck_id: 'deck-physics', sort_order: 40, front: "Faraday's Law of Electromagnetic Induction", back: "EMF = -dΦ/dt. The induced electromotive force in a loop equals the negative rate of change of magnetic flux through the loop. Basis of generators and transformers." , front_translations: {"es":"Ley de Faraday de la Indución Eletromagnética","it":"Legge di Faraday dell'inductione electromagnetico","de":"Faradaysches Gesetz der elektromagnetischen Induktion","fr":"Loi de Faraday de l'induction électromagnétique","tr":"Faraday'ın Elektromanyetik İndüksiyon Yasası","nl":"Wet van Faraday voor elektromagnetische inductie","ru":"Закон электромагнитной индукции Фарадея","zh":"法拉第电磁感应定律","pt_BR":"Lei de Faraday da Indução Eletromagnética","pt_PT":"Lei de Faraday da Indução Eletromagnética"}, back_translations: {"es":"EMF = -dΦ/dt. La fuerza eletromotriz induzida en una malha es igual a la taxa negativa de variación del flujo magnético a través de la malha. Base de geradores y transformadores.","it":"EMF = -dΦ/dt. La force electromotrice induite in una boucle e egale alla vitesse di variazione negative del flux magnetico attraverso la boucle. Base dei generatori e dei transformatori.","de":"EMF = -dΦ/dt. Die induzierte elektromotorische Kraft in einer Schleife ist gleich der negativen zeitlichen Änderungsrate des magnetischen Flusses durch die Schleife. Grundlage von Generatoren und Transformatoren.","fr":"EMF = -dΦ/dt. La force électromotrice induite dans une boucle est égale à la vitesse de variation négative du flux magnétique à travers la boucle. Base des générateurs et des transformateurs.","tr":"EMF = -dΦ/dt. Bir halkada indüklenen elektromotor kuvveti, halka içinden geçen manyetik akının değişim hızının negatifine eşittir. Jeneratör ve transformatörlerin temelidir.","nl":"EMF = -dΦ/dt. De geïnduceerde elektromotorische kracht in een lus is gelijk aan de negatieve veranderingssnelheid van de magnetische flux door de lus. Basis van generatoren en transformatoren.","ru":"ЭДС = -dΦ/dt. Индуцируемая электродвижущая сила в контуре равна отрицательной скорости изменения магнитного потока через контур. Основа генераторов и трансформаторов.","zh":"EMF = -dΦ/dt。回路中的感应电动势等于穿过回路的磁通量变化率的负值。这是发电机和变压器的工作基础。","pt_BR":"EMF = -dΦ/dt. A força eletromotriz induzida em uma malha é igual à taxa negativa de variação do fluxo magnético através da malha. Base de geradores e transformadores.","pt_PT":"EMF = -dΦ/dt. A força eletromotriz induzida numa malha é igual à taxa negativa de variação do fluxo magnético através da malha. Base de geradores e transformadores."}},
  { id: 'dc-physics-0041', deck_id: 'deck-physics', sort_order: 41, front: "Lenz's Law", back: "The direction of an induced current is such that it opposes the change in magnetic flux that caused it. A consequence of energy conservation; consistent with Faraday's Law." , front_translations: {"es":"Ley de Lenz","it":"Legge di Lenz","de":"Lenzsche Regel","fr":"Loi de Lenz","tr":"Lenz Yasası","nl":"Wet van Lenz","ru":"Правило Ленца","zh":"楞次定律","pt_BR":"Lei de Lenz","pt_PT":"Lei de Lenz"}, back_translations: {"es":"La dirección de una corrente induzida es tal que ela se opõe a la variación del flujo magnético que a causou. Una consecuencia de la conservación de energía; consistente con a Ley de Faraday.","it":"La direczione di un courant induit e telle che elle s'oppose al changement di flux magnetico che l'ha cause. Una consequenza della conservazione dell'energia ; coherente con la loi di Faraday.","de":"Die Richtung eines induzierten Stroms ist so gerichtet, dass er der Änderung des magnetischen Flusses, die ihn verursacht hat, entgegenwirkt. Eine Konsequenz der Energieerhaltung; konsistent mit dem Faradayschen Gesetz.","fr":"La direction d'un courant induit est telle qu'elle s'oppose au changement de flux magnétique qui l'a causé. Une conséquence de la conservation de l'énergie ; cohérente avec la loi de Faraday.","tr":"İndüklenen akımın yönü, onu oluşturan manyetik akı değişimine karşı koyacak şekildedir. Enerji korunumunun bir sonucudur; Faraday yasasıyla tutarlıdır.","nl":"De richting van een geïnduceerde stroom is zodanig dat deze de verandering in magnetische flux die deze heeft veroorzaakt, tegengaat. Een gevolg van energiebehoud; consistent met de wet van Faraday.","ru":"Направление индуцированного тока таково, что он противодействует изменению магнитного потока, вызвавшему его. Следствие закона сохранения энергии; согласуется с законом Фарадея.","zh":"感应电流的方向使其产生的磁场阻碍引起感应的磁通量变化。这是能量守恒的必然结果，与法拉第定律一致。","pt_BR":"A direção de uma corrente induzida é tal que ela se opõe à variação do fluxo magnético que a causou. Uma consequência da conservação de energia; consistente com a Lei de Faraday.","pt_PT":"A direção de uma corrente induzida é tal que ela se opõe à variação do fluxo magnético que a causou. Uma consequência da conservação de energia; consistente com a Lei de Faraday."}},
  { id: 'dc-physics-0042', deck_id: 'deck-physics', sort_order: 42, front: "Wave Speed", back: "v = fλ. Wave speed equals frequency times wavelength. For electromagnetic waves in a vacuum, v = c ≈ 3×10⁸ m/s regardless of frequency." , front_translations: {"es":"Velocidad de Onda","it":"Velocita dei ondas","de":"Wellengeschwindigkeit","fr":"Vitesse des ondes","tr":"Dalga Hızı","nl":"Golfsnelheid","ru":"Скорость волны","zh":"波速","pt_BR":"Velocidade de Onda","pt_PT":"Velocidade de Onda"}, back_translations: {"es":"v = fλ. La velocidad de onda es igual a la frecuencia veces el comprimento de onda. Para ondas eletromagnéticas en el vácuo, v = c ≈ 3×10⁸ m/s, independentemente de la frecuencia.","it":"v = fλ. La vitesse d'una onde e egale alla frequenza fois la longuore d'onde. Per i ondes electromagnetici in il vide, v = c ≈ 3×10⁸ m/s quelle che soit la frequenza.","de":"v = fλ. Die Wellengeschwindigkeit ist gleich Frequenz mal Wellenlänge. Für elektromagnetische Wellen im Vakuum gilt v = c ≈ 3×10⁸ m/s, unabhängig von der Frequenz.","fr":"v = fλ. La vitesse d'une onde est égale à la fréquence fois la longueur d'onde. Pour les ondes électromagnétiques dans le vide, v = c ≈ 3×10⁸ m/s quelle que soit la fréquence.","tr":"v = fλ. Dalga hızı, frekans ile dalga boyunun çarpımına eşittir. Vakuumdaki elektromanyetik dalgalar için, frekanstan bağımsız olarak v = c ≈ 3×10⁸ m/s'dir.","nl":"v = fλ. Golfsnelheid is gelijk aan frequentie maal golflengte. Voor elektromagnetische golven in een vacuum geldt v = c ≈ 3×10⁸ m/s, ongeacht de frequentie.","ru":"v = fλ. Скорость волны равна произведению частоты на длину волны. Для электромагнитных волн в вакууме v = c ≈ 3×10⁸ м/с независимо от частоты.","zh":"v = fλ。波速等于频率乘以波长。在真空中，电磁波的波速 v = c ≈ 3×10⁸ m/s，与频率无关。","pt_BR":"v = fλ. A velocidade de onda é igual à frequência vezes o comprimento de onda. Para ondas eletromagnéticas no vácuo, v = c ≈ 3×10⁸ m/s, independentemente da frequência.","pt_PT":"v = fλ. A velocidade de onda é igual à frequência vezes o comprimento de onda. Para ondas eletromagnéticas no vácuo, v = c ≈ 3×10⁸ m/s, independentemente da frequência."}},
  { id: 'dc-physics-0043', deck_id: 'deck-physics', sort_order: 43, front: "Wave Period and Frequency", back: "T = 1/f. The period of a wave is the reciprocal of its frequency. Period is the time for one complete oscillation; frequency is the number of oscillations per second (Hz)." , front_translations: {"es":"Período y Frecuencia de Onda","it":"Periode e frequenza d'une onda","de":"Wellenperiode und Frequenz","fr":"Période et fréquence d'une onde","tr":"Dalga Periyodu ve Frekansı","nl":"Golfperiode en frequentie","ru":"Период и частота волны","zh":"波的周期与频率","pt_BR":"Período e Frequência de Onda","pt_PT":"Período e Frequência de Onda"}, back_translations: {"es":"T = 1/f. El período de una onda es el recíproco de la su frecuencia. El período es el tiempo para una oscilación completa; a frecuencia es el número de oscilaciones por según (Hz).","it":"T = 1/f. La periode d'una onde e l'inverse della sua frequenza. La periode e il temps per una oscillazione complete ; la frequenza e il nombre d'oscillazioni per seconde (Hz).","de":"T = 1/f. Die Periode einer Welle ist der Kehrwert ihrer Frequenz. Die Periode ist die Zeit für eine vollständige Schwingung; die Frequenz ist die Anzahl der Schwingungen pro Sekunde (Hz).","fr":"T = 1/f. La période d'une onde est l'inverse de sa fréquence. La période est le temps pour une oscillation complète ; la fréquence est le nombre d'oscillations par seconde (Hz).","tr":"T = 1/f. Bir dalganın periyodu, frekansının tersidir. Periyot, bir tam salınım için geçen süredir; frekans ise saniyedeki salınım sayısıdır (Hz).","nl":"T = 1/f. De periode van een golf is het omgekeerde van de frequentie. Periode is de tijd voor één volledige oscillatie; frequentie is het aantal oscillaties per seconde (Hz).","ru":"T = 1/f. Период волны — величина, обратная частоте. Период — время одного полного колебания; частота — число колебаний в секунду (Гц).","zh":"T = 1/f。波的周期是其频率的倒数。周期是完成一次完整振荡所需的时间；频率是每秒振荡的次数（Hz）。","pt_BR":"T = 1/f. O período de uma onda é o recíproco da sua frequência. O período é o tempo para uma oscilação completa; a frequência é o número de oscilações por segundo (Hz).","pt_PT":"T = 1/f. O período de uma onda é o recíproco da sua frequência. O período é o tempo para uma oscilação completa; a frequência é o número de oscilações por segundo (Hz)."}},
  { id: 'dc-physics-0044', deck_id: 'deck-physics', sort_order: 44, front: "Snell's Law", back: "n₁sinθ₁ = n₂sinθ₂. Describes refraction of light at an interface between two media. Light bends toward the normal when entering a denser medium (higher n)." , front_translations: {"es":"Ley de Snell","it":"Legge di Snell","de":"Snellsches Gesetz","fr":"Loi de Snell-Descartes","tr":"Snell Yasası","nl":"Wet van Snellius","ru":"Закон Снеллиуса","zh":"斯涅尔定律","pt_BR":"Lei de Snell","pt_PT":"Lei de Snell"}, back_translations: {"es":"n₁sinθ₁ = n₂sinθ₂. Descreve a refración de la luz en una interfaz entre de los medios. La luz dobra en dirección a la normal al entrar en un medio más denso (n mayor).","it":"n₁sinθ₁ = n₂sinθ₂. Decrit la refraczione della luce all'interface tra deux milieux. La luce se courbe verso la normale en entrant in un milieu più dense (n più eleve).","de":"n₁sinθ₁ = n₂sinθ₂. Beschreibt die Brechung von Licht an der Grenzfläche zwischen zwei Medien. Licht bricht zur Normalen hin, wenn es in ein dichteres Medium (höheres n) eintritt.","fr":"n₁sinθ₁ = n₂sinθ₂. Décrit la réfraction de la lumière à l'interface entre deux milieux. La lumière se courbe vers la normale en entrant dans un milieu plus dense (n plus élevé).","tr":"n₁sinθ₁ = n₂sinθ₂. İki ortam arasındaki ara yüzeyde ışığın kırılmasını tanımlar. Işık, daha yoğun bir ortama (daha yüksek n) girerken normala doğru kırılır.","nl":"n₁sinθ₁ = n₂sinθ₂. Beschrijft de breking van licht aan een grensvlak tussen twee media. Licht buigt naar de normaal wanneer het een dichter medium (hogere n) binnenkomt.","ru":"n₁sinθ₁ = n₂sinθ₂. Описывает преломление света на границе раздела двух сред. Свет отклоняется к нормали при переходе в более плотную среду (большее n).","zh":"n₁sinθ₁ = n₂sinθ₂。描述光在两种介质界面处的折射。光进入折射率更大的介质时向法线方向弯折。","pt_BR":"n₁sinθ₁ = n₂sinθ₂. Descreve a refração da luz numa interface entre dois meios. A luz dobra em direção à normal ao entrar num meio mais denso (n maior).","pt_PT":"n₁sinθ₁ = n₂sinθ₂. Descreve a refração da luz numa interface entre dois meios. A luz dobra em direção à normal ao entrar num meio mais denso (n maior)."}},
  { id: 'dc-physics-0045', deck_id: 'deck-physics', sort_order: 45, front: "Index of Refraction", back: "n = c/v. The index of refraction of a medium equals the speed of light in vacuum divided by the speed in the medium. Higher n means slower light and more bending." , front_translations: {"es":"Índice de Refración","it":"Indice di refractione","de":"Brechungsindex","fr":"Indice de réfraction","tr":"Kırılma İndisi","nl":"Brekingsindex","ru":"Показатель преломления","zh":"折射率","pt_BR":"Índice de Refração","pt_PT":"Índice de Refração"}, back_translations: {"es":"n = c/v. El índice de refración de un medio es igual a la velocidad de la luz en el vácuo dividida por la velocidad en el medio. Mayor n significa luz más lenta y mayor desvio.","it":"n = c/v. L'indice di refraczione di un milieu e egal alla vitesse della luce in il vide divisee per la vitesse in il milieu. Un n più eleve signifie una luce più lente e una più grande deviazione.","de":"n = c/v. Der Brechungsindex eines Mediums ist gleich der Lichtgeschwindigkeit im Vakuum dividiert durch die Geschwindigkeit im Medium. Ein höherer n-Wert bedeutet langsameres Licht und stärkere Brechung.","fr":"n = c/v. L'indice de réfraction d'un milieu est égal à la vitesse de la lumière dans le vide divisée par la vitesse dans le milieu. Un n plus élevé signifie une lumière plus lente et une plus grande déviation.","tr":"n = c/v. Bir ortamın kırılma indisi, vakuumdaki ışık hızının o ortamdaki ışık hızına bölünmesiyle elde edilir. Daha yüksek n, daha yavaş ışık ve daha fazla kırılma anlamına gelir.","nl":"n = c/v. De brekingsindex van een medium is gelijk aan de lichtsnelheid in vacuüm gedeeld door de snelheid in het medium. Hogere n betekent langzamer licht en meer buiging.","ru":"n = c/v. Показатель преломления среды равен скорости света в вакууме, делённой на скорость в среде. Большее n означает более медленный свет и большее преломление.","zh":"n = c/v。介质的折射率等于真空中的光速除以该介质中的光速。折射率越大，光速越慢，弯折越大。","pt_BR":"n = c/v. O índice de refração de um meio é igual à velocidade da luz no vácuo dividida pela velocidade no meio. Maior n significa luz mais lenta e maior desvio.","pt_PT":"n = c/v. O índice de refração de um meio é igual à velocidade da luz no vácuo dividida pela velocidade no meio. Maior n significa luz mais lenta e maior desvio."}},
  { id: 'dc-physics-0046', deck_id: 'deck-physics', sort_order: 46, front: "Thin Lens Equation", back: "1/f = 1/do + 1/di. Relates focal length, object distance, and image distance for a thin lens. Positive f is converging; negative f is diverging." , front_translations: {"es":"Ecuación de la Lente Delgada","it":"Equatione dei lentilles minces","de":"Dünne-Linsen-Gleichung","fr":"Équation des lentilles minces","tr":"İnce Mercek Denklemi","nl":"Dunne lens vergelijking","ru":"Формула тонкой линзы","zh":"薄透镜方程","pt_BR":"Equação da Lente Delgada","pt_PT":"Equação da Lente Delgada"}, back_translations: {"es":"1/f = 1/del + 1/di. Relaciona distancia focal, distancia del objeto y distancia de la imaje para una lente delgada. f positivo es convergente; f negativo es divergente.","it":"1/f = 1/do + 1/di. Relie la distanza focale, la distanza objet e la distanza image per una lentille mince. f positif e convergent ; f negatif e divergent.","de":"1/f = 1/do + 1/di. Beschreibt die Beziehung zwischen Brennweite, Gegenstandsweite und Bildweite einer dünnen Linse. Positives f ist Sammellinse; negatives f ist Zerstreuungslinse.","fr":"1/f = 1/do + 1/di. Relie la distance focale, la distance objet et la distance image pour une lentille mince. f positif est convergent ; f négatif est divergent.","tr":"1/f = 1/do + 1/di. İnce bir mercek için odak uzaklığı, cisim mesafesi ve görüntü mesafesi arasındaki ilişkiyi verir. Pozitif f yakınsak, negatif f ıraksaktır.","nl":"1/f = 1/do + 1/di. Relateert brandpuntsafstand, voorwerpsafstand en beeldafstand voor een dunne lens. Positieve f is convergerend; negatieve f is divergerend.","ru":"1/f = 1/do + 1/di. Связывает фокусное расстояние, расстояние до предмета и расстояние до изображения для тонкой линзы. Положительное f — собирающая линза; отрицательное f — рассеивающая.","zh":"1/f = 1/do + 1/di。描述薄透镜的焦距、物距和像距之间的关系。正焦距为会聚透镜，负焦距为发散透镜。","pt_BR":"1/f = 1/do + 1/di. Relaciona distância focal, distância do objeto e distância da imagem para uma lente delgada. f positivo é convergente; f negativo é divergente.","pt_PT":"1/f = 1/do + 1/di. Relaciona distância focal, distância do objeto e distância da imagem para uma lente delgada. f positivo é convergente; f negativo é divergente."}},
  { id: 'dc-physics-0047', deck_id: 'deck-physics', sort_order: 47, front: "Magnification (Optics)", back: "m = -di/do = hi/ho. Magnification is the ratio of image height to object height. Negative magnification indicates an inverted image. |m| > 1 means the image is larger." , front_translations: {"es":"Ampliación (Óptica)","it":"Grossosissemento (Optico)","de":"Vergrößerung (Optik)","fr":"Grossissement (Optique)","tr":"Büyütme (Optik)","nl":"Vergroting (Optiek)","ru":"Увеличение (Оптика)","zh":"放大率（光学）","pt_BR":"Ampliação (Óptica)","pt_PT":"Ampliação (Óptica)"}, back_translations: {"es":"m = -di/del = hi/ho. La ampliación es a razão de la altura de la imaje por la altura del objeto. Ampliación negativa indica una imaje invertida. |m| > 1 significa que a imaje es mayor.","it":"m = -di/do = hi/ho. Il grossissement e il rapport della hautore dell'image alla hautore dell'objet. Un grossissement negatif indico una image inversee. |m| > 1 signifie che l'image e più grande.","de":"m = -di/do = hi/ho. Die Vergrößerung ist das Verhältnis der Bildhöhe zur Gegenstandshöhe. Eine negative Vergrößerung bedeutet ein umgekehrtes Bild. |m| > 1 bedeutet, dass das Bild größer ist.","fr":"m = -di/do = hi/ho. Le grossissement est le rapport de la hauteur de l'image à la hauteur de l'objet. Un grossissement négatif indique une image inversée. |m| > 1 signifie que l'image est plus grande.","tr":"m = -di/do = hi/ho. Büyütme, görüntü yüksekliğinin cisim yüksekliğine oranıdır. Negatif büyütme, ters çevrilmiş bir görüntü anlamına gelir. |m| > 1 görüntünün daha büyük olduğunu gösterir.","nl":"m = -di/do = hi/ho. Vergroting is de verhouding van de beeldhoogte tot de voorwerpshoogte. Negatieve vergroting geeft een omgekeerd beeld aan. |m| > 1 betekent dat het beeld groter is.","ru":"m = -di/do = hi/ho. Увеличение — это отношение высоты изображения к высоте предмета. Отрицательное увеличение означает перевёрнутое изображение. |m| > 1 означает, что изображение больше.","zh":"m = -di/do = hi/ho。放大率是像高与物高之比。负放大率表示倒立的像。|m| > 1 表示像比物大。","pt_BR":"m = -di/do = hi/ho. A ampliação é a razão da altura da imagem pela altura do objeto. Ampliação negativa indica uma imagem invertida. |m| > 1 significa que a imagem é maior.","pt_PT":"m = -di/do = hi/ho. A ampliação é a razão da altura da imagem pela altura do objeto. Ampliação negativa indica uma imagem invertida. |m| > 1 significa que a imagem é maior."}},
  { id: 'dc-physics-0048', deck_id: 'deck-physics', sort_order: 48, front: "Total Internal Reflection", back: "Occurs when light travels from a denser to a less dense medium at an angle greater than the critical angle θ_c = arcsin(n₂/n₁). Basis of fiber optics." , front_translations: {"es":"Reflexão Interna Total","it":"Reflexione totalee interne","de":"Totalreflexion","fr":"Réflexion totale interne","tr":"Tam İç Yansıma","nl":"Totale interne reflectie","ru":"Полное внутреннее отражение","zh":"全内反射","pt_BR":"Reflexão Interna Total","pt_PT":"Reflexão Interna Total"}, back_translations: {"es":"Ocurre cuando a luz viaja de un medio más denso para un menos denso en un ángulo mayor que el ángulo crítico θ_c = arcsin(n₂/n₁). Base de la fibra óptica.","it":"Se prodotto quando la luce passe di un milieu più dense à un milieu meno dense à un angle superiore all'angle critico θ_c = arcsin(n₂/n₁). Base della fibre optico.","de":"Tritt auf, wenn Licht von einem dichteren in ein weniger dichtes Medium unter einem Winkel größer als dem kritischen Winkel θ_c = arcsin(n₂/n₁) einfällt. Grundlage der Glasfasertechnik.","fr":"Se produit lorsque la lumière passe d'un milieu plus dense à un milieu moins dense à un angle supérieur à l'angle critique θ_c = arcsin(n₂/n₁). Base de la fibre optique.","tr":"Işık, kritik açı θ_c = arcsin(n₂/n₁)'den daha büyük bir açıyla daha yoğun bir ortamdan daha az yoğun bir ortama geçtiğinde meydana gelir. Fiber optiğin temelidir.","nl":"Treedt op wanneer licht van een dichter naar een minder dicht medium reist onder een hoek groter dan de kritieke hoek θ_c = arcsin(n₂/n₁). Basis van glasvezel.","ru":"Возникает, когда свет переходит из более плотной среды в менее плотную под углом, превышающим критический угол θ_c = arcsin(n₂/n₁). Основа волоконной оптики.","zh":"当光从较密介质进入较疏介质且入射角大于临界角 θ_c = arcsin(n₂/n₁) 时发生。这是光纤通信的基础。","pt_BR":"Ocorre quando a luz viaja de um meio mais denso para um menos denso em um ângulo maior que o ângulo crítico θ_c = arcsin(n₂/n₁). Base da fibra óptica.","pt_PT":"Ocorre quando a luz viaja de um meio mais denso para um menos denso num ângulo maior que o ângulo crítico θ_c = arcsin(n₂/n₁). Base da fibra ótica."}},
  { id: 'dc-physics-0049', deck_id: 'deck-physics', sort_order: 49, front: "Double-Slit Interference", back: "Constructive interference: dsinθ = mλ; destructive: dsinθ = (m+½)λ. Young's double-slit experiment demonstrated the wave nature of light through interference patterns." , front_translations: {"es":"Interferencia de Dupla Fenda","it":"Interferenza à double fente","de":"Doppelspaltinterferenz","fr":"Interférence à double fente","tr":"Çift Yarık Girişimi","nl":"Dubbelspeetinterferentie","ru":"Интерференция на двойной щели","zh":"双缝干涉","pt_BR":"Interferência de Dupla Fenda","pt_PT":"Interferência de Dupla Fenda"}, back_translations: {"es":"Interferencia construtiva: dsinθ = mλ; destrutiva: dsinθ = (m+½)λ. El experimento de dupla fenda de Young demonstrou a natureza ondulatória de la luz por medio de padrões de interferencia.","it":"Interferenza constructive : dsinθ = mλ ; destructive : dsinθ = (m+½)λ. L'experienza della double fente di Young ha demontre la nature ondulatoire della luce attraverso dei franges d'interferenza.","de":"Konstruktive Interferenz: dsinθ = mλ; destruktive: dsinθ = (m+½)λ. Das Doppelspaltexperiment von Young zeigte den Wellencharakter des Lichts durch Interferenzmuster.","fr":"Interférence constructive : dsinθ = mλ ; destructive : dsinθ = (m+½)λ. L'expérience de la double fente de Young a démontré la nature ondulatoire de la lumière à travers des franges d'interférence.","tr":"Yapıcı girişim: dsinθ = mλ; yıkıcı: dsinθ = (m+½)λ. Young'ın çift yarık deneyi, girişim desenleri aracılığıyla ışığın dalga niteliğini kanıtladı.","nl":"Constructieve interferentie: dsinθ = mλ; destructief: dsinθ = (m+½)λ. Young's dubbelspeetexperiment demonstreerde de golfaard van licht door interferentiepatronen.","ru":"Конструктивная интерференция: dsinθ = mλ; деструктивная: dsinθ = (m+½)λ. Опыт Юнга с двойной щелью продемонстрировал волновую природу света через интерференционные полосы.","zh":"相长干涉：dsinθ = mλ；相消干涉：dsinθ = (m+½)λ。杨氏双缝实验通过干涉条纹证明了光的波动性。","pt_BR":"Interferência construtiva: dsinθ = mλ; destrutiva: dsinθ = (m+½)λ. O experimento de dupla fenda de Young demonstrou a natureza ondulatória da luz por meio de padrões de interferência.","pt_PT":"Interferência construtiva: dsinθ = mλ; destrutiva: dsinθ = (m+½)λ. A experiência de dupla fenda de Young demonstrou a natureza ondulatória da luz através de padrões de interferência."}},
  { id: 'dc-physics-0050', deck_id: 'deck-physics', sort_order: 50, front: "Doppler Effect", back: "f' = f(v ± v_obs)/(v ∓ v_src). Observed frequency changes when source or observer is moving. Moving toward each other increases observed frequency; moving apart decreases it." , front_translations: {"es":"Efecto Doppler","it":"Effetto Doppler","de":"Dopplereffekt","fr":"Effet Doppler","tr":"Doppler Etkisi","nl":"Doppler-effect","ru":"Эффект Доплера","zh":"多普勒效应","pt_BR":"Efeito Doppler","pt_PT":"Efeito Doppler"}, back_translations: {"es":"f' = f(v ± v_obs)/(v ∓ v_src). La frecuencia observada muda cuando a fonte o el observador está en movimiento. Aproximar-se un del outro aumenta a frecuencia observada; afastar-se a disminuye.","it":"f' = f(v ± v_obs)/(v ∓ v_src). La frequenza observee change quando la source o l'observatore e en mouvement. Se rapprocher l'un dell'autre augmente la frequenza observee ; s'eloigner la diminue.","de":"f' = f(v ± v_obs)/(v ∓ v_src). Die beobachtete Frequenz ändert sich, wenn sich Quelle oder Beobachter bewegen. Wenn sie sich aufeinander zubewegen, steigt die beobachtete Frequenz; wenn sie sich voneinander entfernen, sinkt sie.","fr":"f' = f(v ± v_obs)/(v ∓ v_src). La fréquence observée change lorsque la source ou l'observateur est en mouvement. Se rapprocher l'un de l'autre augmente la fréquence observée ; s'éloigner la diminue.","tr":"f' = f(v ± v_obs)/(v ∓ v_src). Kaynak veya gözlemci hareket ettiğinde gözlemlenen frekans değişir. Birbirine yaklaşmak gözlemlenen frekansı artırır; uzaklaşmak azaltır.","nl":"f' = f(v ± v_obs)/(v ∓ v_src). De waargenomen frequentie verandert wanneer de bron of waarnemer beweegt. Naar elkaar toe bewegen verhoogt de waargenomen frequentie; van elkaar af bewegen verlaagt deze.","ru":"f' = f(v ± v_obs)/(v ∓ v_src). Наблюдаемая частота меняется при движении источника или наблюдателя. Сближение увеличивает наблюдаемую частоту; удаление уменьшает её.","zh":"f' = f(v ± v_obs)/(v ∓ v_src)。当声源或观察者运动时，观测到的频率会改变。相互靠近时频率增大，相互远离时频率减小。","pt_BR":"f' = f(v ± v_obs)/(v ∓ v_src). A frequência observada muda quando a fonte ou o observador está em movimento. Aproximar-se um do outro aumenta a frequência observada; afastar-se a diminui.","pt_PT":"f' = f(v ± v_obs)/(v ∓ v_src). A frequência observada muda quando a fonte ou o observador está em movimento. Aproximarem-se um do outro aumenta a frequência observada; afastarem-se diminui-a."}},
  { id: 'dc-physics-0051', deck_id: 'deck-physics', sort_order: 51, front: "Sound Intensity Level", back: "β = 10·log(I/I₀) dB, where I₀ = 10⁻¹² W/m². Sound level in decibels. Every 10 dB increase represents a tenfold increase in intensity." , front_translations: {"es":"Nivel de Intensidad Sonora","it":"Niveau d'intensite sonore","de":"Schallintensitätspegel","fr":"Niveau d'intensité sonore","tr":"Ses Şiddeti Düzeyi","nl":"Geluidsintensiteitsniveau","ru":"Уровень интенсивности звука","zh":"声强级","pt_BR":"Nível de Intensidade Sonora","pt_PT":"Nível de Intensidade Sonora"}, back_translations: {"es":"β = 10·log(I/I₀) dB, donde I₀ = 10⁻¹² W/m². Nivel sonoro en decibéis. Cada aumento de 10 dB representa un aumento de diez veces en la intensidad.","it":"β = 10·log(I/I₀) dB, où I₀ = 10⁻¹² W/m². Niveau sonore en decibels. Chaque augmentazione di 10 dB represente una multiplicazione per dix dell'intensite.","de":"β = 10·log(I/I₀) dB, wobei I₀ = 10⁻¹² W/m². Schallpegel in Dezibel. Jede Erhöhung um 10 dB entspricht einer zehnfachen Zunahme der Intensität.","fr":"β = 10·log(I/I₀) dB, où I₀ = 10⁻¹² W/m². Niveau sonore en décibels. Chaque augmentation de 10 dB représente une multiplication par dix de l'intensité.","tr":"β = 10·log(I/I₀) dB, burada I₀ = 10⁻¹² W/m². Desibel cinsinden ses düzeyi. Her 10 dB artış, yoğunlukta on kat artışı temsil eder.","nl":"β = 10·log(I/I₀) dB, waarbij I₀ = 10⁻¹² W/m². Geluidsniveau in decibel. Elke toename van 10 dB vertegenwoordigt een tienvoudige toename in intensiteit.","ru":"β = 10·log(I/I₀) дБ, где I₀ = 10⁻¹² Вт/м². Уровень звука в децибелах. Каждое увеличение на 10 дБ означает десятикратное увеличение интенсивности.","zh":"β = 10·log(I/I₀) dB，其中 I₀ = 10⁻¹² W/m²。以分贝表示的声级。每增加 10 dB 代表强度增加十倍。","pt_BR":"β = 10·log(I/I₀) dB, onde I₀ = 10⁻¹² W/m². Nível sonoro em decibéis. Cada aumento de 10 dB representa um aumento de dez vezes na intensidade.","pt_PT":"β = 10·log(I/I₀) dB, onde I₀ = 10⁻¹² W/m². Nível sonoro em decibéis. Cada aumento de 10 dB representa um aumento de dez vezes na intensidade."}},
  { id: 'dc-physics-0052', deck_id: 'deck-physics', sort_order: 52, front: "Standing Waves (String)", back: "λ_n = 2L/n, f_n = nv/(2L) for n = 1,2,3,... Harmonics on a fixed string. The fundamental (n=1) has wavelength 2L; overtones are integer multiples of the fundamental frequency." , front_translations: {"es":"Ondas Estacionárias (Corda)","it":"Ondes stationenaires (corde)","de":"Stehende Wellen (Saite)","fr":"Ondes stationnaires (corde)","tr":"Duran Dalgalar (Telli)","nl":"Staande golven (snaar)","ru":"Стоячие волны (струна)","zh":"驻波（弦）","pt_BR":"Ondas Estacionárias (Corda)","pt_PT":"Ondas Estacionárias (Corda)"}, back_translations: {"es":"λ_n = 2L/n, f_n = nv/(2L) para n = 1,2,3,... Harmonicos en una corda fixa. El fundamental (n=1) tiene comprimento de onda 2L; los sobretons son múltiplos interos de la frecuencia fundamental.","it":"λ_n = 2L/n, f_n = nv/(2L) per n = 1,2,3,... Harmonici su una corde fixe. Il fondamental (n=1) ha una longuore d'onde 2L ; i harmonici sono dei multiples entiers della frequenza fondamentale.","de":"λ_n = 2L/n, f_n = nv/(2L) für n = 1,2,3,... Harmonische auf einer eingespannten Saite. Die Grundschwingung (n=1) hat die Wellenlänge 2L; Obertöne sind ganzzahlige Vielfache der Grundfrequenz.","fr":"λ_n = 2L/n, f_n = nv/(2L) pour n = 1,2,3,... Harmoniques sur une corde fixe. Le fondamental (n=1) a une longueur d'onde 2L ; les harmoniques sont des multiples entiers de la fréquence fondamentale.","tr":"λ_n = 2L/n, f_n = nv/(2L), n = 1,2,3,... için sabit bir telde harmonikler. Temel (n=1) dalga boyu 2L'dir; üst tonlar temel frekansın tam sayı katlarıdır.","nl":"λ_n = 2L/n, f_n = nv/(2L) voor n = 1,2,3,... Harmonischen op een vastgeklemde snaar. De grondtoon (n=1) heeft golflengte 2L; boventonen zijn gehele veelvouden van de grondfrequentie.","ru":"λ_n = 2L/n, f_n = nv/(2L) при n = 1,2,3,... Гармоники на закреплённой струне. Основной тон (n=1) имеет длину волны 2L; обертоны являются целочисленными кратными основной частоты.","zh":"λ_n = 2L/n，f_n = nv/(2L)，其中 n = 1,2,3,... 固定弦上的谐波。基频（n=1）波长为 2L；泛音是基频的整数倍。","pt_BR":"λ_n = 2L/n, f_n = nv/(2L) para n = 1,2,3,... Harmônicos em uma corda fixa. O fundamental (n=1) tem comprimento de onda 2L; os sobretons são múltiplos inteiros da frequência fundamental.","pt_PT":"λ_n = 2L/n, f_n = nv/(2L) para n = 1,2,3,... Harmónicos numa corda fixa. O fundamental (n=1) tem comprimento de onda 2L; os harmónicos são múltiplos inteiros da frequência fundamental."}},
  { id: 'dc-physics-0053', deck_id: 'deck-physics', sort_order: 53, front: "Zeroth Law of Thermodynamics", back: "If two systems are each in thermal equilibrium with a third system, they are in thermal equilibrium with each other. This defines temperature as a fundamental property." , front_translations: {"es":"Ley Zero de la Termodinamica","it":"Loi zero di la thermodynamico","de":"Nullter Hauptsatz der Thermodynamik","fr":"Loi zéro de la thermodynamique","tr":"Termodinamiğin Sıfırıncı Yasası","nl":"Nulde hoofdwet van de thermodynamica","ru":"Нулевое начало термодинамики","zh":"热力学第零定律","pt_BR":"Lei Zero da Termodinâmica","pt_PT":"Lei Zero da Termodinâmica"}, back_translations: {"es":"Se de los sistemas están cada un en equilíbrio térmico con un tercero sistema, eles están en equilíbrio térmico entre si. Isso define a temperatura como una propiedad fundamental.","it":"Si deux sistemi sono chacun en equilibrio thermico con un terzo sistema, ils sono en equilibrio thermico l'un con l'autre. Cela definit la temperature come una propriete fondamentale.","de":"Wenn zwei Systeme jeweils im thermischen Gleichgewicht mit einem dritten System sind, befinden sie sich auch im thermischen Gleichgewicht miteinander. Dies definiert die Temperatur als fundamentale Eigenschaft.","fr":"Si deux systèmes sont chacun en équilibre thermique avec un troisième système, ils sont en équilibre thermique l'un avec l'autre. Cela définit la température comme une propriété fondamentale.","tr":"İki sistem her biri üçüncü bir sistemle ısıl dengede ise, birbirleriyle de ısıl dengededir. Bu, sıcaklığı temel bir özellik olarak tanımlar.","nl":"Als twee systemen elk in thermisch evenwicht zijn met een derde systeem, zijn ze in thermisch evenwicht met elkaar. Dit definieert temperatuur als een fundamentele eigenschap.","ru":"Если два системы каждая находятся в тепловом равновесии с третьей системой, то они находятся в тепловом равновесии друг с другом. Это определяет температуру как фундаментальное свойство.","zh":"如果两个系统各自与第三个系统处于热平衡，则它们彼此也处于热平衡。这将温度定义为一种基本属性。","pt_BR":"Se dois sistemas estão cada um em equilíbrio térmico com um terceiro sistema, eles estão em equilíbrio térmico entre si. Isso define a temperatura como uma propriedade fundamental.","pt_PT":"Se dois sistemas estão cada um em equilíbrio térmico com um terceiro sistema, estão em equilíbrio térmico entre si. Isto define a temperatura como uma propriedade fundamental."}},
  { id: 'dc-physics-0054', deck_id: 'deck-physics', sort_order: 54, front: "First Law of Thermodynamics", back: "ΔU = Q - W. The change in internal energy of a system equals the heat added to it minus the work done by it. A statement of conservation of energy." , front_translations: {"es":"Primera Ley de la Termodinamica","it":"Premier principio di la thermodynamico","de":"Erster Hauptsatz der Thermodynamik","fr":"Premier principe de la thermodynamique","tr":"Termodinamiğin Birinci Yasası","nl":"Eerste hoofdwet van de thermodynamica","ru":"Первое начало термодинамики","zh":"热力学第一定律","pt_BR":"Primeira Lei da Termodinâmica","pt_PT":"Primeira Lei da Termodinâmica"}, back_translations: {"es":"ΔU = Q - W. La variación de la energía interna de un sistema es igual al calor adicionado a ele menos el trabajo realizado por ele. Una declaración de la conservación de energía.","it":"ΔU = Q - W. La variazione dell'energia interne di un sistema e egale alla calore che lui e fournie meno il travail effectue per celui-ci. C'e l'enonce della conservazione dell'energia.","de":"ΔU = Q - W. Die Änderung der inneren Energie eines Systems ist gleich der zugeführten Wärme minus der vom System verrichteten Arbeit. Eine Aussage zur Energieerhaltung.","fr":"ΔU = Q - W. La variation de l'énergie interne d'un système est égale à la chaleur qui lui est fournie moins le travail effectué par celui-ci. C'est l'énoncé de la conservation de l'énergie.","tr":"ΔU = Q - W. Bir sistemin iç enerjisindeki değişim, ona eklenen ısı eksi sistem tarafından yapılan iş'e eşittir. Enerjinin korunumunun bir ifadesidir.","nl":"ΔU = Q - W. De verandering in interne energie van een systeem is gelijk aan de toegevoegde warmte minus de door het systeem verrichte arbeid. Een uitdrukking van energiebehoud.","ru":"ΔU = Q - W. Изменение внутренней энергии системы равно теплоте, переданной ей, минус работа, совершённая ею. Это формулировка закона сохранения энергии.","zh":"ΔU = Q - W。系统内能的变化等于传入的热量减去系统做的功。这是能量守恒的表述。","pt_BR":"ΔU = Q - W. A variação da energia interna de um sistema é igual ao calor adicionado a ele menos o trabalho realizado por ele. Uma declaração da conservação de energia.","pt_PT":"ΔU = Q - W. A variação da energia interna de um sistema é igual ao calor adicionado a ele menos o trabalho realizado por ele. Uma declaração da conservação de energia."}},
  { id: 'dc-physics-0055', deck_id: 'deck-physics', sort_order: 55, front: "Second Law of Thermodynamics", back: "The total entropy of an isolated system always increases or remains the same over time. Heat flows spontaneously from hot to cold; no engine is 100% efficient." , front_translations: {"es":"Segunda Ley de la Termodinamica","it":"Seconda principio di la thermodynamico","de":"Zweiter Hauptsatz der Thermodynamik","fr":"Deuxième principe de la thermodynamique","tr":"Termodinamiğin İkinci Yasası","nl":"Tweede hoofdwet van de thermodynamica","ru":"Второе начало термодинамики","zh":"热力学第二定律","pt_BR":"Segunda Lei da Termodinâmica","pt_PT":"Segunda Lei da Termodinâmica"}, back_translations: {"es":"La entropia total de un sistema isolado siempre aumenta o permanece a misma a lo ancho del tiempo. El calor flui espontaneamente del quente para el frio; ningún motor es 100% eficiente.","it":"L'entropie totale di un sistema isole augmente toujours o reste la stesso al fil del temps. La calore s'ecoule spontanement del chaud verso il froid ; aucun motore n'e efficace à 100 %.","de":"Die Gesamtentropie eines isolierten Systems nimmt über die Zeit immer zu oder bleibt gleich. Wärme fließt spontan von heiß nach kalt; keine Maschine ist zu 100 % effizient.","fr":"L'entropie totale d'un système isolé augmente toujours ou reste la même au fil du temps. La chaleur s'écoule spontanément du chaud vers le froid ; aucun moteur n'est efficace à 100 %.","tr":"İzole bir sistemin toplam entropisi zaman içinde daima artar veya aynı kalır. Isı kendiliğinden sıcaktan soğuğa akar; hiçbir motor %100 verimli değildir.","nl":"De totale entropie van een geïsoleerd systeem neemt altijd toe of blijft gelijk in de tijd. Warmte stroomt spontaan van warm naar koud; geen enkele motor is 100% efficiënt.","ru":"Полная энтропия изолированной системы всегда возрастает или остаётся неизменной со временем. Тепло самопроизвольно течёт от горячего к холодному; ни один двигатель не является 100% эффективным.","zh":"孤立系统的总熵随时间总是增加或保持不变。热量自发地从热处流向冷处；没有发动机能达到100%的效率。","pt_BR":"A entropia total de um sistema isolado sempre aumenta ou permanece a mesma ao longo do tempo. O calor flui espontaneamente do quente para o frio; nenhum motor é 100% eficiente.","pt_PT":"A entropia total de um sistema isolado aumenta sempre ou permanece igual ao longo do tempo. O calor flui espontaneamente do quente para o frio; nenhum motor é 100% eficiente."}},
  { id: 'dc-physics-0056', deck_id: 'deck-physics', sort_order: 56, front: "Third Law of Thermodynamics", back: "As temperature approaches absolute zero (0 K), the entropy of a perfect crystal approaches zero. It is impossible to reach absolute zero in a finite number of steps." , front_translations: {"es":"Tercera Ley de la Termodinamica","it":"Terza principio di la thermodynamico","de":"Dritter Hauptsatz der Thermodynamik","fr":"Troisième principe de la thermodynamique","tr":"Termodinamiğin Üçüncü Yasası","nl":"Derde hoofdwet van de thermodynamica","ru":"Третье начало термодинамики","zh":"热力学第三定律","pt_BR":"Terceira Lei da Termodinâmica","pt_PT":"Terceira Lei da Termodinâmica"}, back_translations: {"es":"À medida que a temperatura se aproxima del zero absoluto (0 K), a entropia de un cristal perfeito se aproxima de zero. Es impossible atingir el zero absoluto en un número finito de etapas.","it":"Lorsque la temperature approche del zero absolu (0 K), l'entropie di un cristal parfait tend verso zero. Il e impossible d'atteindre il zero absolu en un nombre fini d'etapes.","de":"Wenn sich die Temperatur dem absoluten Nullpunkt (0 K) nähert, strebt die Entropie eines perfekten Kristalls gegen null. Es ist unmöglich, den absoluten Nullpunkt in einer endlichen Anzahl von Schritten zu erreichen.","fr":"Lorsque la température approche du zéro absolu (0 K), l'entropie d'un cristal parfait tend vers zéro. Il est impossible d'atteindre le zéro absolu en un nombre fini d'étapes.","tr":"Sıcaklık mutlak sıfıra (0 K) yaklaştıkça, mükemmel bir kristalin entropisi sıfıra yaklaşır. Mutlak sıfıra sonlu sayıda adımda ulaşmak imkânsızdır.","nl":"Naarmate de temperatuur het absolute nulpunt (0 K) nadert, nadert de entropie van een perfect kristal nul. Het is onmogelijk om het absolute nulpunt in een eindig aantal stappen te bereiken.","ru":"По мере приближения температуры к абсолютному нулю (0 K) энтропия идеального кристалла стремится к нулю. Достичь абсолютного нуля за конечное число шагов невозможно.","zh":"当温度趋近于绝对零度（0 K）时，完美晶体的熵趋近于零。在有限步骤内达到绝对零度是不可能的。","pt_BR":"À medida que a temperatura se aproxima do zero absoluto (0 K), a entropia de um cristal perfeito se aproxima de zero. É impossível atingir o zero absoluto em um número finito de etapas.","pt_PT":"À medida que a temperatura se aproxima do zero absoluto (0 K), a entropia de um cristal perfeito tende para zero. É impossível atingir o zero absoluto num número finito de etapas."}},
  { id: 'dc-physics-0057', deck_id: 'deck-physics', sort_order: 57, front: "Ideal Gas Law", back: "PV = nRT. Pressure times volume equals moles times the ideal gas constant times temperature (in Kelvin). R = 8.314 J/(mol·K). Assumes no intermolecular forces." , front_translations: {"es":"Ley de los Gases Ideais","it":"Legge dei gas ideali","de":"Ideales Gasgesetz","fr":"Loi des gaz parfaits","tr":"İdeal Gaz Yasası","nl":"Ideale gaswet","ru":"Уравнение состояния идеального газа","zh":"理想气体定律","pt_BR":"Lei dos Gases Ideais","pt_PT":"Lei dos Gases Ideais"}, back_translations: {"es":"PV = nRT. Presión veces volumen es igual al número de moles veces a constante de los gases ideais veces a temperatura (en Kelvin). R = 8,314 J/(mol·K). Assume ausencia de fuerzas intermoleculares.","it":"PV = nRT. La pression multipliee per il volume e egale al nombre di moles multiplie per la costante dei gaz parfaits multipliee per la temperature (en Kelvin). R = 8,314 J/(mol·K). Suppose l'absenza di forces intermoleculaires.","de":"PV = nRT. Druck mal Volumen gleich Mol mal ideale Gaskonstante mal Temperatur (in Kelvin). R = 8,314 J/(mol·K). Setzt keine intermolekularen Kräfte voraus.","fr":"PV = nRT. La pression multipliée par le volume est égale au nombre de moles multiplié par la constante des gaz parfaits multipliée par la température (en Kelvin). R = 8,314 J/(mol·K). Suppose l'absence de forces intermoléculaires.","tr":"PV = nRT. Basınç çarpı hacim, mol sayısı çarpı ideal gaz sabiti çarpı sıcaklığa (Kelvin cinsinden) eşittir. R = 8,314 J/(mol·K). Moleküller arası kuvvet olmadığını varsayar.","nl":"PV = nRT. Druk maal volume is gelijk aan mol maal de ideale gasconstante maal temperatuur (in Kelvin). R = 8,314 J/(mol·K). Gaat uit van geen intermoleculaire krachten.","ru":"PV = nRT. Давление, умноженное на объём, равно количеству молей, умноженному на универсальную газовую постоянную и на температуру (в Кельвинах). R = 8,314 Дж/(моль·К). Предполагает отсутствие межмолекулярных сил.","zh":"PV = nRT。压强乘以体积等于摩尔数乘以理想气体常数乘以温度（开尔文）。R = 8.314 J/(mol·K)。假设无分子间作用力。","pt_BR":"PV = nRT. Pressão vezes volume é igual ao número de moles vezes a constante dos gases ideais vezes a temperatura (em Kelvin). R = 8,314 J/(mol·K). Assume ausência de forças intermoleculares.","pt_PT":"PV = nRT. Pressão vezes volume é igual ao número de moles vezes a constante dos gases ideais vezes a temperatura (em Kelvin). R = 8,314 J/(mol·K). Assume ausência de forças intermoleculares."}},
  { id: 'dc-physics-0058', deck_id: 'deck-physics', sort_order: 58, front: "Boyle's Law", back: "P₁V₁ = P₂V₂ at constant temperature and amount. Pressure and volume of an ideal gas are inversely proportional at constant temperature." , front_translations: {"es":"Ley de Boyle","it":"Legge di Boyle","de":"Boyle'sches Gesetz","fr":"Loi de Boyle","tr":"Boyle Yasası","nl":"Wet van Boyle","ru":"Закон Бойля","zh":"玻意耳定律","pt_BR":"Lei de Boyle","pt_PT":"Lei de Boyle"}, back_translations: {"es":"P₁V₁ = P₂V₂ a temperatura y cantidad constantes. La presión y el volumen de un gas ideal son inversamente proporcionais a temperatura constante.","it":"P₁V₁ = P₂V₂ à temperature e quantite constantes. La pression e il volume di un gaz ideal sono inversement proportionnels à temperature costante.","de":"P₁V₁ = P₂V₂ bei konstanter Temperatur und Stoffmenge. Druck und Volumen eines idealen Gases sind bei konstanter Temperatur umgekehrt proportional.","fr":"P₁V₁ = P₂V₂ à température et quantité constantes. La pression et le volume d'un gaz idéal sont inversement proportionnels à température constante.","tr":"P₁V₁ = P₂V₂, sabit sıcaklık ve miktar için. İdeal bir gazın basıncı ve hacmi, sabit sıcaklıkta ters orantılıdır.","nl":"P₁V₁ = P₂V₂ bij constante temperatuur en hoeveelheid. Druk en volume van een ideaal gas zijn omgekeerd evenredig bij constante temperatuur.","ru":"P₁V₁ = P₂V₂ при постоянной температуре и количестве вещества. Давление и объём идеального газа обратно пропорциональны при постоянной температуре.","zh":"在恒温和恒量条件下，P₁V₁ = P₂V₂。理想气体的压强和体积在恒温条件下成反比。","pt_BR":"P₁V₁ = P₂V₂ a temperatura e quantidade constantes. A pressão e o volume de um gás ideal são inversamente proporcionais a temperatura constante.","pt_PT":"P₁V₁ = P₂V₂ a temperatura e quantidade constantes. A pressão e o volume de um gás ideal são inversamente proporcionais a temperatura constante."}},
  { id: 'dc-physics-0059', deck_id: 'deck-physics', sort_order: 59, front: "Charles's Law", back: "V₁/T₁ = V₂/T₂ at constant pressure and amount. Volume of an ideal gas is directly proportional to its absolute temperature at constant pressure." , front_translations: {"es":"Ley de Charles","it":"Legge di Charles","de":"Gesetz von Charles","fr":"Loi de Charles","tr":"Charles Yasası","nl":"Wet van Charles","ru":"Закон Шарля","zh":"查理定律","pt_BR":"Lei de Charles","pt_PT":"Lei de Charles"}, back_translations: {"es":"V₁/T₁ = V₂/T₂ a presión y cantidad constantes. El volumen de un gas ideal es directamente proporcional a la su temperatura absoluta a presión constante.","it":"V₁/T₁ = V₂/T₂ à pression e quantite constantes. Il volume di un gaz ideal e directement proportionnel alla sua temperature absolue à pression costante.","de":"V₁/T₁ = V₂/T₂ bei konstantem Druck und konstanter Stoffmenge. Das Volumen eines idealen Gases ist bei konstantem Druck direkt proportional zu seiner absoluten Temperatur.","fr":"V₁/T₁ = V₂/T₂ à pression et quantité constantes. Le volume d'un gaz idéal est directement proportionnel à sa température absolue à pression constante.","tr":"V₁/T₁ = V₂/T₂, sabit basınç ve miktar için. İdeal bir gazın hacmi, sabit basınçta mutlak sıcaklığıyla doğru orantılıdır.","nl":"V₁/T₁ = V₂/T₂ bij constante druk en hoeveelheid. Het volume van een ideaal gas is rechtevenredig met zijn absolute temperatuur bij constante druk.","ru":"V₁/T₁ = V₂/T₂ при постоянном давлении и количестве вещества. Объём идеального газа прямо пропорционален его абсолютной температуре при постоянном давлении.","zh":"在恒压和恒量条件下，V₁/T₁ = V₂/T₂。理想气体的体积在恒压条件下与其绝对温度成正比。","pt_BR":"V₁/T₁ = V₂/T₂ a pressão e quantidade constantes. O volume de um gás ideal é diretamente proporcional à sua temperatura absoluta a pressão constante.","pt_PT":"V₁/T₁ = V₂/T₂ a pressão e quantidade constantes. O volume de um gás ideal é diretamente proporcional à sua temperatura absoluta a pressão constante."}},
  { id: 'dc-physics-0060', deck_id: 'deck-physics', sort_order: 60, front: "Gay-Lussac's Law", back: "P₁/T₁ = P₂/T₂ at constant volume and amount. Pressure of an ideal gas is directly proportional to its absolute temperature at constant volume." , front_translations: {"es":"Ley de Gay-Lussac","it":"Legge di Gay-Lussac","de":"Gesetz von Gay-Lussac","fr":"Loi de Gay-Lussac","tr":"Gay-Lussac Yasası","nl":"Wet van Gay-Lussac","ru":"Закон Гей-Люссака","zh":"盖-吕萨克定律","pt_BR":"Lei de Gay-Lussac","pt_PT":"Lei de Gay-Lussac"}, back_translations: {"es":"P₁/T₁ = P₂/T₂ a volumen y cantidad constantes. La presión de un gas ideal es directamente proporcional a la su temperatura absoluta a volumen constante.","it":"P₁/T₁ = P₂/T₂ à volume e quantite constants. La pression di un gaz ideal e directement proportionnelle alla sua temperature absolue à volume constant.","de":"P₁/T₁ = P₂/T₂ bei konstantem Volumen und konstanter Stoffmenge. Der Druck eines idealen Gases ist bei konstantem Volumen direkt proportional zu seiner absoluten Temperatur.","fr":"P₁/T₁ = P₂/T₂ à volume et quantité constants. La pression d'un gaz idéal est directement proportionnelle à sa température absolue à volume constant.","tr":"P₁/T₁ = P₂/T₂, sabit hacim ve miktar için. İdeal bir gazın basıncı, sabit hacimde mutlak sıcaklığıyla doğru orantılıdır.","nl":"P₁/T₁ = P₂/T₂ bij constant volume en hoeveelheid. De druk van een ideaal gas is rechtevenredig met zijn absolute temperatuur bij constant volume.","ru":"P₁/T₁ = P₂/T₂ при постоянном объёме и количестве вещества. Давление идеального газа прямо пропорционально его абсолютной температуре при постоянном объёме.","zh":"在恒容和恒量条件下，P₁/T₁ = P₂/T₂。理想气体的压强在恒容条件下与其绝对温度成正比。","pt_BR":"P₁/T₁ = P₂/T₂ a volume e quantidade constantes. A pressão de um gás ideal é diretamente proporcional à sua temperatura absoluta a volume constante.","pt_PT":"P₁/T₁ = P₂/T₂ a volume e quantidade constantes. A pressão de um gás ideal é diretamente proporcional à sua temperatura absoluta a volume constante."}},
  { id: 'dc-physics-0061', deck_id: 'deck-physics', sort_order: 61, front: "Thermal Expansion", back: "ΔL = αL₀ΔT. Linear expansion of a solid is proportional to the original length and the temperature change. α is the coefficient of linear expansion (1/°C)." , front_translations: {"es":"Expansão Térmica","it":"Dilatazione termica","de":"Wärmeausdehnung","fr":"Dilatation thermique","tr":"Isıl Genleşme","nl":"Warmte-uitzetting","ru":"Тепловое расширение","zh":"热膨胀","pt_BR":"Expansão Térmica","pt_PT":"Expansão Térmica"}, back_translations: {"es":"ΔL = αL₀ΔT. La expansão linear de un sólido es proporcional al comprimento original y a la variación de temperatura. α es el coeficiente de expansão linear (1/°C).","it":"ΔL = αL₀ΔT. La dilatazione lineaire di un solide e proportionnelle alla longuore initiale e alla variazione di temperature. α e il coefficient di dilatazione lineaire (1/°C).","de":"ΔL = αL₀ΔT. Die lineare Ausdehnung eines Festkörpers ist proportional zur ursprünglichen Länge und zur Temperaturänderung. α ist der lineare Ausdehnungskoeffizient (1/°C).","fr":"ΔL = αL₀ΔT. La dilatation linéaire d'un solide est proportionnelle à la longueur initiale et à la variation de température. α est le coefficient de dilatation linéaire (1/°C).","tr":"ΔL = αL₀ΔT. Bir katının doğrusal genleşmesi, orijinal uzunluk ve sıcaklık değişimiyle orantılıdır. α, doğrusal genleşme katsayısıdır (1/°C).","nl":"ΔL = αL₀ΔT. Lineaire uitzetting van een vaste stof is evenredig met de oorspronkelijke lengte en de temperatuurverandering. α is de coëfficiënt van lineaire uitzetting (1/°C).","ru":"ΔL = αL₀ΔT. Линейное расширение твёрдого тела пропорционально начальной длине и изменению температуры. α — коэффициент линейного расширения (1/°C).","zh":"ΔL = αL₀ΔT。固体的线膨胀与原始长度和温度变化成正比。α 是线膨胀系数（1/°C）。","pt_BR":"ΔL = αL₀ΔT. A expansão linear de um sólido é proporcional ao comprimento original e à variação de temperatura. α é o coeficiente de expansão linear (1/°C).","pt_PT":"ΔL = αL₀ΔT. A expansão linear de um sólido é proporcional ao comprimento original e à variação de temperatura. α é o coeficiente de expansão linear (1/°C)."}},
  { id: 'dc-physics-0062', deck_id: 'deck-physics', sort_order: 62, front: "Heat Conduction", back: "Q/t = kA(ΔT/d). Rate of heat flow by conduction equals thermal conductivity times area times temperature gradient. Metals are good conductors; insulators have low k." , front_translations: {"es":"Condución de Calor","it":"Conductione termico","de":"Wärmeleitung","fr":"Conduction thermique","tr":"Isı İletimi","nl":"Warmtegeleiding","ru":"Теплопроводность","zh":"热传导","pt_BR":"Condução de Calor","pt_PT":"Condução de Calor"}, back_translations: {"es":"Q/t = kA(ΔT/d). La taxa de flujo de calor por condución es igual a la condutividad térmica veces a área veces el gradiente de temperatura. Metais son bons condutores; isolantes tienen k bajo.","it":"Q/t = kA(ΔT/d). Il taux di flux di calore per conduczione e egal alla conductivite thermico fois l'aire fois il gradient di temperature. I metaux sono di bons conductori ; i isolants hanno un faible k.","de":"Q/t = kA(ΔT/d). Die Wärmeströmungsrate durch Leitung ist gleich der Wärmeleitfähigkeit mal der Fläche mal dem Temperaturgradienten. Metalle sind gute Leiter; Isolatoren haben ein niedriges k.","fr":"Q/t = kA(ΔT/d). Le taux de flux de chaleur par conduction est égal à la conductivité thermique fois l'aire fois le gradient de température. Les métaux sont de bons conducteurs ; les isolants ont un faible k.","tr":"Q/t = kA(ΔT/d). İletimle ısı akış hızı, ısıl iletkenlik çarpı alan çarpı sıcaklık gradyanına eşittir. Metaller iyi iletkendir; yalıtkanların k değeri düşüktür.","nl":"Q/t = kA(ΔT/d). De warmtestroomsnelheid door geleiding is gelijk aan thermische geleidbaarheid maal oppervlak maal temperatuurgradiënt. Metalen zijn goede geleiders; isolatoren hebben een lage k.","ru":"Q/t = kA(ΔT/d). Скорость теплового потока при теплопроводности равна теплопроводности, умноженной на площадь и температурный градиент. Металлы хорошо проводят тепло; изоляторы имеют низкое k.","zh":"Q/t = kA(ΔT/d)。热传导的热流速率等于热导率乘以面积乘以温度梯度。金属是良导体；绝热材料的 k 值低。","pt_BR":"Q/t = kA(ΔT/d). A taxa de fluxo de calor por condução é igual à condutividade térmica vezes a área vezes o gradiente de temperatura. Metais são bons condutores; isolantes têm k baixo.","pt_PT":"Q/t = kA(ΔT/d). A taxa de fluxo de calor por condução é igual à condutividade térmica vezes a área vezes o gradiente de temperatura. Os metais são bons condutores; os isoladores têm k baixo."}},
  { id: 'dc-physics-0063', deck_id: 'deck-physics', sort_order: 63, front: "Specific Heat Capacity", back: "Q = mcΔT. Heat absorbed or released equals mass times specific heat capacity times temperature change. Water has a high specific heat (4186 J/kg·K), making it excellent for thermal regulation." , front_translations: {"es":"Calor Específico","it":"Capacità termica specifica","de":"Spezifische Wärmekapazität","fr":"Capacité thermique massique","tr":"Özgül Isı Kapasitesi","nl":"Soortelijke warmtecapaciteit","ru":"Удельная теплоёмкость","zh":"比热容","pt_BR":"Calor Específico","pt_PT":"Calor Específico"}, back_translations: {"es":"Q = mcΔT. El calor absorbido o liberado es igual a la masa veces el calor específico veces a variación de temperatura. La agua tiene alto calor específico (4186 J/kg·K), tornando-a excelente para regulación térmica.","it":"Q = mcΔT. La calore absorbee o liberee e egale alla masse fois la capacite thermico massico fois la variazione di temperature. L'eau ha una grande capacite thermico (4186 J/kg·K), questo che la rend excellente per la regulazione thermico.","de":"Q = mcΔT. Die aufgenommene oder abgegebene Wärme ist gleich Masse mal spezifische Wärmekapazität mal Temperaturänderung. Wasser hat eine hohe spezifische Wärme (4186 J/kg·K), was es ideal für die Wärmeregulierung macht.","fr":"Q = mcΔT. La chaleur absorbée ou libérée est égale à la masse fois la capacité thermique massique fois la variation de température. L'eau a une grande capacité thermique (4186 J/kg·K), ce qui la rend excellente pour la régulation thermique.","tr":"Q = mcΔT. Emilen veya salınan ısı, kütle çarpı özgül ısı kapasitesi çarpı sıcaklık değişimine eşittir. Su yüksek özgül ısıya (4186 J/kg·K) sahiptir; bu onu ısıl düzenleme için mükemmel kılar.","nl":"Q = mcΔT. Geabsorbeerde of vrijgekomen warmte is gelijk aan massa maal soortelijke warmtecapaciteit maal temperatuurverandering. Water heeft een hoge soortelijke warmte (4186 J/kg·K), waardoor het uitstekend is voor warmteregulering.","ru":"Q = mcΔT. Поглощённая или отданная теплота равна массе, умноженной на удельную теплоёмкость и изменение температуры. Вода имеет высокую удельную теплоёмкость (4186 Дж/кг·К), что делает её превосходным терморегулятором.","zh":"Q = mcΔT。吸收或释放的热量等于质量乘以比热容乘以温度变化。水具有高比热容（4186 J/kg·K），使其非常适合热调节。","pt_BR":"Q = mcΔT. O calor absorvido ou liberado é igual à massa vezes o calor específico vezes a variação de temperatura. A água tem alto calor específico (4186 J/kg·K), tornando-a excelente para regulação térmica.","pt_PT":"Q = mcΔT. O calor absorvido ou libertado é igual à massa vezes o calor específico vezes a variação de temperatura. A água tem elevado calor específico (4186 J/kg·K), tornando-a excelente para regulação térmica."}},
  { id: 'dc-physics-0064', deck_id: 'deck-physics', sort_order: 64, front: "Latent Heat", back: "Q = mL. Heat required for a phase change equals mass times latent heat. Temperature does not change during the phase transition. L_f (fusion) and L_v (vaporization) differ." , front_translations: {"es":"Calor Latente","it":"Chalore latente","de":"Latente Wärme","fr":"Chaleur latente","tr":"Gizli Isı","nl":"Latente warmte","ru":"Скрытая теплота","zh":"潜热","pt_BR":"Calor Latente","pt_PT":"Calor Latente"}, back_translations: {"es":"Q = mL. El calor necesario para una cambio de fase es igual a la masa veces el calor latente. La temperatura no muda durante a transición de fase. L_f (fusión) y L_v (vaporización) diferem.","it":"Q = mL. La calore necessario à un changement di phase e egale alla masse fois la calore latente. La temperature non change pendant la transizione di phase. L_f (fusion) e L_v (vaporisazione) different.","de":"Q = mL. Die für einen Phasenübergang benötigte Wärme ist gleich Masse mal latente Wärme. Die Temperatur ändert sich während des Phasenübergangs nicht. L_f (Schmelzen) und L_v (Verdampfen) unterscheiden sich.","fr":"Q = mL. La chaleur nécessaire à un changement de phase est égale à la masse fois la chaleur latente. La température ne change pas pendant la transition de phase. L_f (fusion) et L_v (vaporisation) diffèrent.","tr":"Q = mL. Bir faz değişimi için gereken ısı, kütle çarpı gizli ısıya eşittir. Faz geçişi sırasında sıcaklık değişmez. L_f (erime) ve L_v (buharlaşma) farklıdır.","nl":"Q = mL. De warmte die nodig is voor een faseovergang is gelijk aan massa maal latente warmte. De temperatuur verandert niet tijdens de faseovergang. L_f (smelten) en L_v (verdampen) verschillen.","ru":"Q = mL. Теплота, необходимая для фазового перехода, равна массе, умноженной на удельную скрытую теплоту. Во время фазового перехода температура не изменяется. L_f (плавление) и L_v (испарение) различаются.","zh":"Q = mL。相变所需的热量等于质量乘以潜热。相变过程中温度不变。L_f（熔化）和 L_v（汽化）的值不同。","pt_BR":"Q = mL. O calor necessário para uma mudança de fase é igual à massa vezes o calor latente. A temperatura não muda durante a transição de fase. L_f (fusão) e L_v (vaporização) diferem.","pt_PT":"Q = mL. O calor necessário para uma mudança de fase é igual à massa vezes o calor latente. A temperatura não muda durante a transição de fase. L_f (fusão) e L_v (vaporização) diferem."}},
  { id: 'dc-physics-0065', deck_id: 'deck-physics', sort_order: 65, front: "Carnot Efficiency", back: "η = 1 - T_cold/T_hot. Maximum theoretical efficiency of a heat engine operating between two temperatures (in Kelvin). No real engine can exceed Carnot efficiency." , front_translations: {"es":"Eficiencia de Carnot","it":"Rendemento di Carnot","de":"Carnot-Wirkungsgrad","fr":"Rendement de Carnot","tr":"Carnot Verimi","nl":"Carnot-rendement","ru":"КПД цикла Карно","zh":"卡诺效率","pt_BR":"Eficiência de Carnot","pt_PT":"Eficiência de Carnot"}, back_translations: {"es":"η = 1 - T_fria/T_quente. Eficiencia teórica máxima de un motor térmico operando entre de los temperaturas (en Kelvin). Nenhum motor real puede superar a eficiencia de Carnot.","it":"η = 1 - T_froid/T_chaud. Rendement theorico maximal di un motore thermico fonctionnant tra deux temperatures (en Kelvin). Aucun motore reel non può depasser il rendement di Carnot.","de":"η = 1 - T_kalt/T_heiß. Maximaler theoretischer Wirkungsgrad einer Wärmekraftmaschine, die zwischen zwei Temperaturen (in Kelvin) arbeitet. Kein realer Motor kann den Carnot-Wirkungsgrad übertreffen.","fr":"η = 1 - T_froid/T_chaud. Rendement théorique maximal d'un moteur thermique fonctionnant entre deux températures (en Kelvin). Aucun moteur réel ne peut dépasser le rendement de Carnot.","tr":"η = 1 - T_soğuk/T_sıcak. İki sıcaklık (Kelvin cinsinden) arasında çalışan bir ısı motorunun maksimum teorik verimi. Hiçbir gerçek motor Carnot verimini aşamaz.","nl":"η = 1 - T_koud/T_heet. Maximaal theoretisch rendement van een warmtemotor die werkt tussen twee temperaturen (in Kelvin). Geen enkele echte motor kan het Carnot-rendement overschrijden.","ru":"η = 1 - T_хол/T_гор. Максимальный теоретический КПД тепловой машины, работающей между двумя температурами (в Кельвинах). Ни один реальный двигатель не может превзойти КПД Карно.","zh":"η = 1 - T_冷/T_热。在两个温度（开尔文）之间工作的热机的最大理论效率。没有实际发动机能超过卡诺效率。","pt_BR":"η = 1 - T_fria/T_quente. Eficiência teórica máxima de um motor térmico operando entre duas temperaturas (em Kelvin). Nenhum motor real pode superar a eficiência de Carnot.","pt_PT":"η = 1 - T_fria/T_quente. Eficiência teórica máxima de um motor térmico a operar entre duas temperaturas (em Kelvin). Nenhum motor real pode superar a eficiência de Carnot."}},
  { id: 'dc-physics-0066', deck_id: 'deck-physics', sort_order: 66, front: "Einstein's Mass-Energy Equivalence", back: "E = mc². Mass and energy are interchangeable; a small amount of mass can release an enormous amount of energy. c ≈ 3×10⁸ m/s. Basis of nuclear energy." , front_translations: {"es":"Equivalencia Masa-Energía de Einstein","it":"Equivalenza massa-energia d'Einstein","de":"Einsteins Masse-Energie-Äquivalenz","fr":"Équivalence masse-énergie d'Einstein","tr":"Einstein'ın Kütle-Enerji Denkliği","nl":"Einsteins massa-energierelatie","ru":"Эквивалентность массы и энергии Эйнштейна","zh":"爱因斯坦质能等价","pt_BR":"Equivalência Massa-Energia de Einstein","pt_PT":"Equivalência Massa-Energia de Einstein"}, back_translations: {"es":"Y = mc². Masa y energía son intercambiables; una pequeña cantidad de masa puede liberar una enorme cantidad de energía. c ≈ 3×10⁸ m/s. Base de la energía nuclear.","it":"E = mc². La masse e l'energia sono interchangeables ; una piccola quantite di masse può liberer una enorme quantite d'energia. c ≈ 3×10⁸ m/s. Base dell'energia nucleaire.","de":"E = mc². Masse und Energie sind austauschbar; eine kleine Masse kann eine enorme Energiemenge freisetzen. c ≈ 3×10⁸ m/s. Grundlage der Kernenergie.","fr":"E = mc². La masse et l'énergie sont interchangeables ; une petite quantité de masse peut libérer une énorme quantité d'énergie. c ≈ 3×10⁸ m/s. Base de l'énergie nucléaire.","tr":"E = mc². Kütle ve enerji birbirinin yerine geçebilir; küçük bir miktar kütle muazzam miktarda enerji açığa çıkarabilir. c ≈ 3×10⁸ m/s. Nükleer enerjinin temelidir.","nl":"E = mc². Massa en energie zijn uitwisselbaar; een kleine hoeveelheid massa kan een enorme hoeveelheid energie vrijmaken. c ≈ 3×10⁸ m/s. Basis van kernenergie.","ru":"E = mc². Масса и энергия взаимозаменяемы; небольшое количество массы может высвободить огромное количество энергии. c ≈ 3×10⁸ м/с. Основа ядерной энергии.","zh":"E = mc²。质量和能量可以相互转换；少量质量可以释放巨大的能量。c ≈ 3×10⁸ m/s。核能的基础。","pt_BR":"E = mc². Massa e energia são intercambiáveis; uma pequena quantidade de massa pode liberar uma enorme quantidade de energia. c ≈ 3×10⁸ m/s. Base da energia nuclear.","pt_PT":"E = mc². A massa e a energia são intercambiáveis; uma pequena quantidade de massa pode libertar uma enorme quantidade de energia. c ≈ 3×10⁸ m/s. Base da energia nuclear."}},
  { id: 'dc-physics-0067', deck_id: 'deck-physics', sort_order: 67, front: "Photoelectric Effect", back: "E_k = hf - φ. Electrons are ejected from a metal surface when light of sufficient frequency strikes it. Proved the quantum nature of light; φ is the work function of the metal." , front_translations: {"es":"Efecto Fotoelétrico","it":"Effetto fotoelettrico","de":"Photoelektrischer Effekt","fr":"Effet photoélectrique","tr":"Fotoelektrik Etki","nl":"Foto-elektrisch effect","ru":"Фотоэлектрический эффект","zh":"光电效应","pt_BR":"Efeito Fotoelétrico","pt_PT":"Efeito Fotoelétrico"}, back_translations: {"es":"Y_k = hf - φ. Electrones son ejetados de una superficie metálica cuando luz de frecuencia suficiente a alcanza. Provou a natureza quantica de la luz; φ es a función trabajo del metal.","it":"E_k = hf - φ. Dei electrons sono ejectes d'una surface metallico quando della luce di frequenza suffisante la frappe. A prouve la nature quantico della luce ; φ e il travail d'extraczione del metal.","de":"E_k = hf - φ. Elektronen werden von einer Metalloberfläche emittiert, wenn Licht ausreichender Frequenz auftrifft. Bewies die Quantennatur des Lichts; φ ist die Austrittsarbeit des Metalls.","fr":"E_k = hf - φ. Des électrons sont éjectés d'une surface métallique lorsque de la lumière de fréquence suffisante la frappe. A prouvé la nature quantique de la lumière ; φ est le travail d'extraction du métal.","tr":"E_k = hf - φ. Yeterli frekansta ışık bir metal yüzeye çarptığında elektronlar fırlatılır. Işığın kuantum doğasını kanıtladı; φ metalin iş fonksiyonudur.","nl":"E_k = hf - φ. Elektronen worden uitgestoten van een metaaloppervlak wanneer licht van voldoende frequentie erop valt. Bewees de kwantumaard van licht; φ is de arbeidsfunctie van het metaal.","ru":"E_k = hf - φ. Электроны вырываются с поверхности металла при падении на неё света достаточной частоты. Доказал квантовую природу света; φ — работа выхода металла.","zh":"E_k = hf - φ。当足够频率的光照射到金属表面时，电子被射出。证明了光的量子性质；φ 是金属的逸出功。","pt_BR":"E_k = hf - φ. Elétrons são ejetados de uma superfície metálica quando luz de frequência suficiente a atinge. Provou a natureza quântica da luz; φ é a função trabalho do metal.","pt_PT":"E_k = hf - φ. Eletrões são ejetados de uma superfície metálica quando luz de frequência suficiente a atinge. Provou a natureza quântica da luz; φ é a função trabalho do metal."}},
  { id: 'dc-physics-0068', deck_id: 'deck-physics', sort_order: 68, front: "Planck's Equation", back: "E = hf. The energy of a photon equals Planck's constant times its frequency. h = 6.626×10⁻³⁴ J·s. Quantization of energy was the start of quantum mechanics." , front_translations: {"es":"Ecuación de Planck","it":"Equatione di Planck","de":"Planck'sche Gleichung","fr":"Équation de Planck","tr":"Planck Denklemi","nl":"Vergelijking van Planck","ru":"Уравнение Планка","zh":"普朗克方程","pt_BR":"Equação de Planck","pt_PT":"Equação de Planck"}, back_translations: {"es":"Y = hf. La energía de un fóton es igual a la constante de Planck veces su frecuencia. h = 6,626×10⁻³⁴ J·s. La quantización de la energía fue el início de la mecánica quantica.","it":"E = hf. L'energia di un photon e egale alla costante di Planck multipliee per la sua frequenza. h = 6,626×10⁻³⁴ J·s. La quantificazione dell'energia etait il debut della mecanico quantico.","de":"E = hf. Die Energie eines Photons ist gleich dem Planck'schen Wirkungsquantum mal seiner Frequenz. h = 6,626×10⁻³⁴ J·s. Die Quantisierung der Energie war der Beginn der Quantenmechanik.","fr":"E = hf. L'énergie d'un photon est égale à la constante de Planck multipliée par sa fréquence. h = 6,626×10⁻³⁴ J·s. La quantification de l'énergie était le début de la mécanique quantique.","tr":"E = hf. Bir fotonun enerjisi, Planck sabiti çarpı frekansına eşittir. h = 6,626×10⁻³⁴ J·s. Enerjinin kuantizasyonu, kuantum mekaniğinin başlangıcıydı.","nl":"E = hf. De energie van een foton is gelijk aan de constante van Planck maal zijn frequentie. h = 6,626×10⁻³⁴ J·s. Kwantisering van energie was het begin van de kwantummechanica.","ru":"E = hf. Энергия фотона равна постоянной Планка, умноженной на его частоту. h = 6,626×10⁻³⁴ Дж·с. Квантование энергии стало началом квантовой механики.","zh":"E = hf。光子的能量等于普朗克常数乘以其频率。h = 6.626×10⁻³⁴ J·s。能量量子化是量子力学的开端。","pt_BR":"E = hf. A energia de um fóton é igual à constante de Planck vezes sua frequência. h = 6,626×10⁻³⁴ J·s. A quantização da energia foi o início da mecânica quântica.","pt_PT":"E = hf. A energia de um fotão é igual à constante de Planck vezes a sua frequência. h = 6,626×10⁻³⁴ J·s. A quantização da energia foi o início da mecânica quântica."}},
  { id: 'dc-physics-0069', deck_id: 'deck-physics', sort_order: 69, front: "Heisenberg Uncertainty Principle", back: "ΔxΔp ≥ ℏ/2. It is impossible to simultaneously know a particle's exact position and momentum. This is a fundamental property of quantum systems, not a measurement limitation." , front_translations: {"es":"Principio de la Incerteza de Heisenberg","it":"Principio di indeterminazione di Heisenberg","de":"Heisenbergsche Unschärferelation","fr":"Principe d'incertitude de Heisenberg","tr":"Heisenberg Belirsizlik İlkesi","nl":"Onzekerheidsrelatie van Heisenberg","ru":"Принцип неопределённости Гейзенберга","zh":"海森堡不确定性原理","pt_BR":"Princípio da Incerteza de Heisenberg","pt_PT":"Princípio da Incerteza de Heisenberg"}, back_translations: {"es":"ΔxΔp ≥ ℏ/2. Es impossible conhecer simultáneamente a posición exata y el momento de una partícula. Esta es una propiedad fundamental de los sistemas quanticos, no una limitación de medición.","it":"ΔxΔp ≥ ℏ/2. Il e impossible di connaitre simultanement la posizione exacte e la quantite di mouvement d'una particule. C'e una propriete fondamentale dei sistemi quantici, una limitazione di mesure.","de":"ΔxΔp ≥ ℏ/2. Es ist unmöglich, gleichzeitig den genauen Ort und den Impuls eines Teilchens zu kennen. Dies ist eine fundamentale Eigenschaft von Quantensystemen, keine Meßlimitierung.","fr":"ΔxΔp ≥ ℏ/2. Il est impossible de connaître simultanément la position exacte et la quantité de mouvement d'une particule. C'est une propriété fondamentale des systèmes quantiques, pas une limitation de mesure.","tr":"ΔxΔp ≥ ℏ/2. Bir parçacığın tam konumunu ve momentumunu aynı anda bilmek imkânsızdır. Bu, kuantum sistemlerinin temel bir özelliğidir; bir ölçüm sınırlaması değildir.","nl":"ΔxΔp ≥ ℏ/2. Het is onmogelijk om tegelijkertijd de exacte positie en impuls van een deeltje te kennen. Dit is een fundamentele eigenschap van kwantumsystemen, geen meetbeperking.","ru":"ΔxΔp ≥ ℏ/2. Невозможно одновременно точно знать положение частицы и её импульс. Это фундаментальное свойство квантовых систем, а не ограничение измерений.","zh":"ΔxΔp ≥ ℏ/2。不可能同时精确知道粒子的位置和动量。这是量子系统的基本性质，而非测量限制。","pt_BR":"ΔxΔp ≥ ℏ/2. É impossível conhecer simultaneamente a posição exata e o momento de uma partícula. Esta é uma propriedade fundamental dos sistemas quânticos, não uma limitação de medição.","pt_PT":"ΔxΔp ≥ ℏ/2. É impossível conhecer simultaneamente a posição exata e o momento de uma partícula. Esta é uma propriedade fundamental dos sistemas quânticos, não uma limitação de medição."}},
  { id: 'dc-physics-0070', deck_id: 'deck-physics', sort_order: 70, front: "de Broglie Wavelength", back: "λ = h/p = h/(mv). All matter has wave-like properties; the de Broglie wavelength decreases with increasing momentum. Significant only for subatomic particles." , front_translations: {"es":"Comprimento de Onda de de Broglie","it":"Longuore d'onda di de Broglie","de":"De-Broglie-Wellenlänge","fr":"Longueur d'onde de de Broglie","tr":"de Broglie Dalga Boyu","nl":"De Broglie-golflengte","ru":"Длина волны де Бройля","zh":"德布罗意波长","pt_BR":"Comprimento de Onda de de Broglie","pt_PT":"Comprimento de Onda de de Broglie"}, back_translations: {"es":"λ = h/p = h/(mv). Toda materia tiene propiedades ondulatórias; el comprimento de onda de de Broglie disminuye con el aumento del momento. Significativo solo para partículas subatomicas.","it":"λ = h/p = h/(mv). Toute la matiere possedi dei proprietàs ondulatoires ; la longuore d'onde di di Broglie diminue con l'augmentazione della quantite di mouvement. Significatif uniquement per i particules subatomici.","de":"λ = h/p = h/(mv). Alle Materie besitzt wellenartige Eigenschaften; die de-Broglie-Wellenlänge nimmt mit zunehmendem Impuls ab. Bedeutend nur für subatomare Teilchen.","fr":"λ = h/p = h/(mv). Toute la matière possède des propriétés ondulatoires ; la longueur d'onde de de Broglie diminue avec l'augmentation de la quantité de mouvement. Significatif uniquement pour les particules subatomiques.","tr":"λ = h/p = h/(mv). Tüm madde dalga benzeri özelliklere sahiptir; de Broglie dalga boyu artan momentumla azalır. Yalnızca atom altı parçacıklar için önemlidir.","nl":"λ = h/p = h/(mv). Alle materie heeft golfachtige eigenschappen; de de Broglie-golflengte neemt af met toenemende impuls. Alleen significant voor subatomaire deeltjes.","ru":"λ = h/p = h/(mv). Вся материя обладает волновыми свойствами; длина волны де Бройля уменьшается с ростом импульса. Значима только для субатомных частиц.","zh":"λ = h/p = h/(mv)。所有物质都具有波动性；德布罗意波长随动量增大而减小。仅对亚原子粒子有显著意义。","pt_BR":"λ = h/p = h/(mv). Toda matéria tem propriedades ondulatórias; o comprimento de onda de de Broglie diminui com o aumento do momento. Significativo apenas para partículas subatômicas.","pt_PT":"λ = h/p = h/(mv). Toda a matéria tem propriedades ondulatórias; o comprimento de onda de de Broglie diminui com o aumento do momento. Significativo apenas para partículas subatómicas."}},
  { id: 'dc-physics-0071', deck_id: 'deck-physics', sort_order: 71, front: "Radioactive Decay Law", back: "N(t) = N₀e^(-λt). The number of undecayed nuclei decreases exponentially over time. λ is the decay constant; related to half-life by λ = ln2/t½." , front_translations: {"es":"Ley del Decaimento Radioativo","it":"Legge di decressanza radioactiva","de":"Radioaktives Zerfallsgesetz","fr":"Loi de décroissance radioactive","tr":"Radyoaktif Bozunma Yasası","nl":"Wet van radioactief verval","ru":"Закон радиоактивного распада","zh":"放射性衰变定律","pt_BR":"Lei do Decaimento Radioativo","pt_PT":"Lei do Decaimento Radioativo"}, back_translations: {"es":"N(t) = N₀y^(-λt). El número de núcleos no decaídos disminuye exponencialmente a lo ancho del tiempo. λ es a constante de decaimento; relacionada a la media-vida por λ = ln2/t½.","it":"N(t) = N₀e^(-λt). Il nombre di noyaux non desintegres diminue di fazon exponentielle al fil del temps. λ e la costante di desintegrazione ; liee alla emivita per λ = ln2/t½.","de":"N(t) = N₀e^(-λt). Die Anzahl der unzerfallenen Kerne nimmt exponentiell über die Zeit ab. λ ist die Zerfallskonstante; verbunden mit der Halbwertszeit durch λ = ln2/t½.","fr":"N(t) = N₀e^(-λt). Le nombre de noyaux non désintégrés diminue de façon exponentielle au fil du temps. λ est la constante de désintégration ; liée à la demi-vie par λ = ln2/t½.","tr":"N(t) = N₀e^(-λt). Bozunmamış çekirdek sayısı zaman içinde üstel olarak azalır. λ bozunma sabitidir; yarı ömürle λ = ln2/t½ ile ilişkilidir.","nl":"N(t) = N₀e^(-λt). Het aantal niet-vervallen kernen neemt exponentieel af in de tijd. λ is de vervalconstante; gerelateerd aan de halveringstijd door λ = ln2/t½.","ru":"N(t) = N₀e^(-λt). Число нераспавшихся ядер убывает экспоненциально со временем. λ — постоянная распада; связана с периодом полураспада соотношением λ = ln2/t½.","zh":"N(t) = N₀e^(-λt)。未衰变的核数随时间呈指数衰减。λ 是衰变常数；与半衰期的关系为 λ = ln2/t½。","pt_BR":"N(t) = N₀e^(-λt). O número de núcleos não decaídos diminui exponencialmente ao longo do tempo. λ é a constante de decaimento; relacionada à meia-vida por λ = ln2/t½.","pt_PT":"N(t) = N₀e^(-λt). O número de núcleos não desintegrados diminui exponencialmente ao longo do tempo. λ é a constante de desintegração; relacionada com a meia-vida por λ = ln2/t½."}},
  { id: 'dc-physics-0072', deck_id: 'deck-physics', sort_order: 72, front: "Half-Life", back: "t½ = ln2/λ = 0.693/λ. The time required for half of a radioactive sample to decay. Each successive half-life reduces the remaining quantity by half." , front_translations: {"es":"Media-vida","it":"Emivita","de":"Halbwertszeit","fr":"Demi-vie","tr":"Yarı Ömür","nl":"Halveringstijd","ru":"Период полураспада","zh":"半衰期","pt_BR":"Meia-vida","pt_PT":"Meia-vida"}, back_translations: {"es":"t½ = ln2/λ = 0,693/λ. El tiempo necesario para que metade de una amostra radioativa decaia. Cada media-vida sucessiva reduce a cantidad restante a la metade.","it":"t½ = ln2/λ = 0,693/λ. Il temps necessario per che la moitie di un echantillon radioactif se desintegre. Chaque emivita successive reduit la quantite restante di moitie.","de":"t½ = ln2/λ = 0,693/λ. Die Zeit, die benötigt wird, damit die Hälfte einer radioaktiven Probe zerfällt. Jede aufeinanderfolgende Halbwertszeit halbiert die verbleibende Menge.","fr":"t½ = ln2/λ = 0,693/λ. Le temps nécessaire pour que la moitié d'un échantillon radioactif se désintègre. Chaque demi-vie successive réduit la quantité restante de moitié.","tr":"t½ = ln2/λ = 0,693/λ. Radyoaktif bir numunenin yarısının bozunması için gereken süre. Her ardışık yarı ömür, kalan miktarı yarıya indirir.","nl":"t½ = ln2/λ = 0,693/λ. De tijd die nodig is voor de helft van een radioactief monster om te vervallen. Elke opeenvolgende halveringstijd vermindert de resterende hoeveelheid met de helft.","ru":"t½ = ln2/λ = 0,693/λ. Время, за которое распадается половина радиоактивного образца. Каждый последующий период полураспада уменьшает оставшееся количество вдвое.","zh":"t½ = ln2/λ = 0.693/λ。放射性样品中一半衰变所需的时间。每经过一个半衰期，剩余量减少一半。","pt_BR":"t½ = ln2/λ = 0,693/λ. O tempo necessário para que metade de uma amostra radioativa decaia. Cada meia-vida sucessiva reduz a quantidade restante à metade.","pt_PT":"t½ = ln2/λ = 0,693/λ. O tempo necessário para que metade de uma amostra radioativa se desintegre. Cada meia-vida sucessiva reduz a quantidade restante para metade."}},
  { id: 'dc-physics-0073', deck_id: 'deck-physics', sort_order: 73, front: "Alpha Decay", back: "A nucleus emits an alpha particle (⁴He nucleus, 2 protons + 2 neutrons). Mass number decreases by 4; atomic number decreases by 2. Low penetrating power but highly ionizing." , front_translations: {"es":"Decaimento Alfa","it":"Desintàgratione alpha","de":"Alphazerfall","fr":"Désintégration alpha","tr":"Alfa Bozunması","nl":"Alfaverval","ru":"Альфа-распад","zh":"阿尔法衰变","pt_BR":"Decaimento Alfa","pt_PT":"Desintegração Alfa"}, back_translations: {"es":"Un núcleo emite una partícula alfa (núcleo ⁴He, 2 protones + 2 neutrones). El número de masa disminuye 4; el número atómico disminuye 2. Bajo poder de penetración, pero altamente ionizante.","it":"Un noyau emet una particule alpha (noyau ⁴He, 2 protons + 2 neutrons). Il nombre di masse diminue di 4 ; il numero atomico diminue di 2. Faible pouvoir di penetrazione ma fortement ionisant.","de":"Ein Kern emittiert ein Alphateilchen (⁴He-Kern, 2 Protonen + 2 Neutronen). Die Massenzahl nimmt um 4 ab; die Ordnungszahl nimmt um 2 ab. Geringe Durchdringungskraft, aber stark ionisierend.","fr":"Un noyau émet une particule alpha (noyau ⁴He, 2 protons + 2 neutrons). Le nombre de masse diminue de 4 ; le numéro atomique diminue de 2. Faible pouvoir de pénétration mais fortement ionisant.","tr":"Bir çekirdek alfa parçacığı (⁴He çekirdeği, 2 proton + 2 nötron) yayar. Kütle sayısı 4 azalır; atom numarası 2 azalır. Düşük nüfuz gücü ancak yüksek iyonlaştırıcı etkiye sahiptir.","nl":"Een kern zendt een alfadeeltje uit (⁴He-kern, 2 protonen + 2 neutronen). Massagetal neemt af met 4; atoomnummer neemt af met 2. Lage penetratievermogen maar sterk ioniserend.","ru":"Ядро испускает альфа-частицу (ядро ⁴He, 2 протона + 2 нейтрона). Массовое число уменьшается на 4; атомный номер уменьшается на 2. Малая проникающая способность, но высокая ионизирующая способность.","zh":"核子放射出阿尔法粒子（⁴He核，2个质子 + 2个中子）。质量数减少4；原子序数减少2。穿透力弱，但电离能力强。","pt_BR":"Um núcleo emite uma partícula alfa (núcleo ⁴He, 2 prótons + 2 nêutrons). O número de massa diminui 4; o número atômico diminui 2. Baixo poder de penetração, mas altamente ionizante.","pt_PT":"Um núcleo emite uma partícula alfa (núcleo ⁴He, 2 protões + 2 neutrões). O número de massa diminui 4; o número atómico diminui 2. Baixo poder de penetração, mas altamente ionizante."}},
  { id: 'dc-physics-0074', deck_id: 'deck-physics', sort_order: 74, front: "Beta Decay", back: "A neutron converts to a proton (β⁻) or a proton to a neutron (β⁺), emitting a beta particle (electron or positron). Atomic number changes by ±1; mass number unchanged." , front_translations: {"es":"Decaimento Beta","it":"Desintàgratione beta","de":"Betazerfall","fr":"Désintégration bêta","tr":"Beta Bozunması","nl":"Betaverval","ru":"Бета-распад","zh":"贝塔衰变","pt_BR":"Decaimento Beta","pt_PT":"Desintegração Beta"}, back_translations: {"es":"Un neutrón se convierte en un protón (β⁻) o un protón en un neutrón (β⁺), emitindo una partícula beta (electrón o pósitron). El número atómico muda en ±1; el número de masa permanece inalterado.","it":"Un neutron se convertit en proton (β⁻) o un proton en neutron (β⁺), en emettant una particule beta (electron o positron). Il numero atomico change di ±1 ; il nombre di masse reste inchange.","de":"Ein Neutron wird in ein Proton (β⁻) oder ein Proton in ein Neutron (β⁺) umgewandelt, wobei ein Betateilchen (Elektron oder Positron) emittiert wird. Die Ordnungszahl ändert sich um ±1; die Massenzahl bleibt unverändert.","fr":"Un neutron se convertit en proton (β⁻) ou un proton en neutron (β⁺), en émettant une particule bêta (électron ou positron). Le numéro atomique change de ±1 ; le nombre de masse reste inchangé.","tr":"Bir nötron protona (β⁻) veya bir proton nötrona (β⁺) dönüşür ve bir beta parçacığı (elektron veya pozitron) yayılır. Atom numarası ±1 değişir; kütle sayısı değişmez.","nl":"Een neutron wordt omgezet in een proton (β⁻) of een proton in een neutron (β⁺), waarbij een betadeeltje (elektron of positron) wordt uitgestoten. Atoomnummer verandert met ±1; massagetal ongewijzigd.","ru":"Нейтрон превращается в протон (β⁻) или протон в нейтрон (β⁺) с испусканием бета-частицы (электрона или позитрона). Атомный номер изменяется на ±1; массовое число не меняется.","zh":"中子转变为质子（β⁻）或质子转变为中子（β⁺），放射出贝塔粒子（电子或正电子）。原子序数变化 ±1；质量数不变。","pt_BR":"Um nêutron se converte em um próton (β⁻) ou um próton em um nêutron (β⁺), emitindo uma partícula beta (elétron ou pósitron). O número atômico muda em ±1; o número de massa permanece inalterado.","pt_PT":"Um neutrão converte-se num protão (β⁻) ou um protão num neutrão (β⁺), emitindo uma partícula beta (eletrão ou positrão). O número atómico muda ±1; o número de massa permanece inalterado."}},
  { id: 'dc-physics-0075', deck_id: 'deck-physics', sort_order: 75, front: "Gamma Radiation", back: "High-energy electromagnetic radiation emitted by a nucleus during nuclear decay. No change in mass or atomic number. Most penetrating type of nuclear radiation; requires lead or thick concrete to shield." , front_translations: {"es":"Radiación Gama","it":"Rayonnemento gamma","de":"Gammastrahlung","fr":"Rayonnement gamma","tr":"Gama Işıması","nl":"Gammastraling","ru":"Гамма-излучение","zh":"伽马射线","pt_BR":"Radiação Gama","pt_PT":"Radiação Gama"}, back_translations: {"es":"Radiación eletromagnética de alta energía emitida por un núcleo durante el decaimento nuclear. Nenhuma cambio en el número de masa o atómico. Tipo de radiación nuclear más penetrante; requiere chumbo o concreto espesso para blindaje.","it":"Rayonnement electromagnetico di haute energia emis per un noyau lors d'una desintegrazione nucleaire. Aucun changement del nombre di masse ni del numero atomico. Type di rayonnement nucleaire il più penetrant ; necessite del plomb o del beton epais per se proteger.","de":"Hochenergetische elektromagnetische Strahlung, die von einem Kern während des Kernzerfalls emittiert wird. Keine Änderung der Massen- oder Ordnungszahl. Durchdringungsstärkste Art der Kernstrahlung; erfordert Blei oder dicken Beton zur Abschirmung.","fr":"Rayonnement électromagnétique de haute énergie émis par un noyau lors d'une désintégration nucléaire. Aucun changement du nombre de masse ni du numéro atomique. Type de rayonnement nucléaire le plus pénétrant ; nécessite du plomb ou du béton épais pour se protéger.","tr":"Nükleer bozunma sırasında bir çekirdek tarafından yayılan yüksek enerjili elektromanyetik radyasyon. Kütle veya atom numarasında değişiklik olmaz. Nükleer radyasyonun en nüfuz eden türü; kalkan için kurşun veya kalın beton gerektirir.","nl":"Hoogenergetische elektromagnetische straling uitgestoten door een kern tijdens nucleair verval. Geen verandering in massa- of atoomnummer. Meest doordringende type kernstraling; vereist lood of dik beton ter afscherming.","ru":"Высокоэнергетическое электромагнитное излучение, испускаемое ядром при ядерном распаде. Масса и атомный номер не изменяются. Наиболее проникающий вид ядерного излучения; для защиты требуется свинец или толстый бетон.","zh":"核衰变过程中由核子发射的高能电磁辐射。质量数和原子序数不变。穿透力最强的核辐射类型；需要铅或厚混凝土来屏蔽。","pt_BR":"Radiação eletromagnética de alta energia emitida por um núcleo durante o decaimento nuclear. Nenhuma mudança no número de massa ou atômico. Tipo de radiação nuclear mais penetrante; requer chumbo ou concreto espesso para blindagem.","pt_PT":"Radiação eletromagnética de alta energia emitida por um núcleo durante a desintegração nuclear. Nenhuma alteração no número de massa ou atómico. Tipo de radiação nuclear mais penetrante; requer chumbo ou betão espesso para blindagem."}},
  { id: 'dc-physics-0076', deck_id: 'deck-physics', sort_order: 76, front: "Nuclear Binding Energy", back: "The energy required to completely separate a nucleus into its individual protons and neutrons. Related to mass defect by E = Δmc². Higher binding energy per nucleon means greater nuclear stability." , front_translations: {"es":"Energía de Enlace Nuclear","it":"Energie di liaison nucleare","de":"Kernbindungsenergie","fr":"Énergie de liaison nucléaire","tr":"Nükleer Bağlanma Enerjisi","nl":"Kernbindingsenergie","ru":"Энергия связи ядра","zh":"核结合能","pt_BR":"Energia de Ligação Nuclear","pt_PT":"Energia de Ligação Nuclear"}, back_translations: {"es":"La energía necesaria para separar completamente un núcleo en sus protones y neutrones individuais. Relacionada al defeito de masa por Y = Δmc². Mayor energía de enlace por núcleon significa mayor estabilidad nuclear.","it":"L'energia necessario per separer completement un noyau en i suoi protons e neutrons individuels. Liee al defaut di masse per E = Δmc². Una energia di liaison per nucleon più elevee signifie una più grande stabilite nucleaire.","de":"Die Energie, die benötigt wird, um einen Atomkern vollständig in seine einzelnen Protonen und Neutronen aufzutrennen. Sie hängt mit dem Massendefekt zusammen: E = Δmc². Eine höhere Bindungsenergie pro Nukleon bedeutet eine größere Kernstabilität.","fr":"L'énergie nécessaire pour séparer complètement un noyau en ses protons et neutrons individuels. Liée au défaut de masse par E = Δmc². Une énergie de liaison par nucléon plus élevée signifie une plus grande stabilité nucléaire.","tr":"Bir çekirdeği tek tek proton ve nötronlarına ayırmak için gereken enerji. Kütle açığıyla E = Δmc² ile ilişkilidir. Nükleon başına daha yüksek bağlanma enerjisi, daha büyük nükleer kararlılık anlamına gelir.","nl":"De energie die nodig is om een kern volledig te scheiden in zijn afzonderlijke protonen en neutronen. Gerelateerd aan het massadefect via E = Δmc². Hogere bindingsenergie per nucleon betekent grotere kernstabiliteit.","ru":"Энергия, необходимая для полного разделения ядра на отдельные протоны и нейтроны. Связана с дефектом масс выражением E = Δmc². Большая энергия связи на нуклон означает большую стабильность ядра.","zh":"将原子核完全分离成单独的质子和中子所需的能量。通过 E = Δmc² 与质量亏损相关。每个核子的结合能越高，核稳定性越强。","pt_BR":"A energia necessária para separar completamente um núcleo em seus prótons e nêutrons individuais. Relacionada ao defeito de massa por E = Δmc². Maior energia de ligação por núcleon significa maior estabilidade nuclear.","pt_PT":"A energia necessária para separar completamente um núcleo nos seus protões e neutrões individuais. Relacionada com o defeito de massa por E = Δmc². Uma maior energia de ligação por nucleão significa maior estabilidade nuclear."}},
  { id: 'dc-physics-0077', deck_id: 'deck-physics', sort_order: 77, front: "Fission", back: "A heavy nucleus (e.g., ²³⁵U) splits into two smaller nuclei plus neutrons and energy. The released neutrons can trigger further fissions in a chain reaction, the basis of nuclear reactors and bombs." , front_translations: {"es":"Fisión Nuclear","it":"Fissione","de":"Kernspaltung","fr":"Fission","tr":"Fisyon","nl":"Kernsplijting","ru":"Деление ядра","zh":"核裂变","pt_BR":"Fissão Nuclear","pt_PT":"Fissão Nuclear"}, back_translations: {"es":"Un núcleo pesado (por ejemplo, ²³⁵U) se divide en de los núcleos menores más neutrones y energía. Los neutrones liberados pueden desencadear outras fisiones en una reacción en cadeia, a base de los reatores nucleares y de las bombas.","it":"Un noyau lourd (p. ex. ²³⁵U) se divise en deux noyaux più petits ainsi che dei neutrons e dell'energia. I neutrons liberes possono declencher d'autres fissions en reazione en chainon, base dei reactori nucleaires e dei bombes.","de":"Ein schwerer Atomkern (z. B. ²³⁵U) spaltet sich in zwei kleinere Kerne sowie Neutronen und Energie auf. Die freigesetzten Neutronen können weitere Spaltungen auslösen und so eine Kettenreaktion erzeugen – die Grundlage von Kernreaktoren und Atombomben.","fr":"Un noyau lourd (p. ex. ²³⁵U) se divise en deux noyaux plus petits ainsi que des neutrons et de l'énergie. Les neutrons libérés peuvent déclencher d'autres fissions en réaction en chaîne, base des réacteurs nucléaires et des bombes.","tr":"Ağır bir çekirdek (örneğin ²³⁵U), iki daha küçük çekirdeğe, nötronlara ve enerjiye bölünür. Salınan nötronlar zincirleme bir reaksiyonda daha fazla fisyon tetikleyebilir; bu durum nükleer reaktörlerin ve bombaların temelidir.","nl":"Een zwaar atoomkern (bijv. ²³⁵U) splitst in twee kleinere kernen plus neutronen en energie. De vrijgekomen neutronen kunnen verdere splitsingen uitlokken in een kettingreactie, de basis van kernreactoren en bommen.","ru":"Тяжёлое ядро (например, ²³⁵U) делится на два более лёгких ядра с выделением нейтронов и энергии. Освободившиеся нейтроны могут инициировать дальнейшие деления в цепной реакции — основе ядерных реакторов и бомб.","zh":"重核（如 ²³⁵U）分裂成两个较小的核，同时释放中子和能量。释放的中子可以引发进一步的裂变，形成链式反应，这是核反应堆和核弹的基础。","pt_BR":"Um núcleo pesado (por exemplo, ²³⁵U) se divide em dois núcleos menores mais nêutrons e energia. Os nêutrons liberados podem desencadear outras fissões em uma reação em cadeia, a base dos reatores nucleares e das bombas.","pt_PT":"Um núcleo pesado (por exemplo, ²³⁵U) divide-se em dois núcleos menores mais neutrões e energia. Os neutrões libertados podem desencadear outras fissões numa reação em cadeia, a base dos reatores nucleares e das bombas."}},
  { id: 'dc-physics-0078', deck_id: 'deck-physics', sort_order: 78, front: "Fusion", back: "Light nuclei (e.g., deuterium and tritium) combine to form a heavier nucleus, releasing large amounts of energy. Powers the Sun and stars. Requires extremely high temperatures." , front_translations: {"es":"Fusión Nuclear","it":"Fusione","de":"Kernfusion","fr":"Fusion","tr":"Füzyon","nl":"Kernfusie","ru":"Ядерный синтез","zh":"核聚变","pt_BR":"Fusão Nuclear","pt_PT":"Fusão Nuclear"}, back_translations: {"es":"Núcleos leves (por ejemplo, deutério y trítio) se combinam para formar un núcleo más pesado, liberando grandes quantidades de energía. Alimenta el Sol y las estrelas. Requiere temperaturas extremamente altas.","it":"Dei noyaux legers (p. ex. deuterium e tritium) fusionnent per former un noyau più lourd en liberant di grandes quantites d'energia. Alimente il Soleil e i etoiles. Necessite dei temperatures extremement elevees.","de":"Leichte Atomkerne (z. B. Deuterium und Tritium) vereinigen sich zu einem schwereren Kern und setzen dabei große Energiemengen frei. Sie treibt die Sonne und die Sterne an und erfordert extrem hohe Temperaturen.","fr":"Des noyaux légers (p. ex. deutérium et tritium) fusionnent pour former un noyau plus lourd en libérant de grandes quantités d'énergie. Alimente le Soleil et les étoiles. Nécessite des températures extrêmement élevées.","tr":"Hafif çekirdekler (örneğin döteryum ve trityum) birleşerek daha ağır bir çekirdek oluşturur ve büyük miktarda enerji salar. Güneş'i ve yıldızları güçlendirir. Aşırı yüksek sıcaklıklar gerektirir.","nl":"Lichte kernen (bijv. deuterium en tritium) combineren tot een zwaarder kern en zetten daarbij grote hoeveelheden energie vrij. Drijft de Zon en sterren aan. Vereist extreem hoge temperaturen.","ru":"Лёгкие ядра (например, дейтерий и тритий) объединяются в более тяжёлое ядро, выделяя большое количество энергии. Питает Солнце и звёзды. Требует чрезвычайно высоких температур.","zh":"轻核（如氘和氚）结合形成较重的核，释放大量能量。为太阳和恒星提供能量，需要极高的温度。","pt_BR":"Núcleos leves (por exemplo, deutério e trítio) se combinam para formar um núcleo mais pesado, liberando grandes quantidades de energia. Alimenta o Sol e as estrelas. Requer temperaturas extremamente altas.","pt_PT":"Núcleos leves (por exemplo, deutério e trítio) combinam-se para formar um núcleo mais pesado, libertando grandes quantidades de energia. Alimenta o Sol e as estrelas. Requer temperaturas extremamente elevadas."}},
  { id: 'dc-physics-0079', deck_id: 'deck-physics', sort_order: 79, front: "Special Relativity: Time Dilation", back: "t' = t/√(1 - v²/c²). A moving clock runs slower than a stationary one as observed from the stationary frame. The effect is significant only at speeds approaching c." , front_translations: {"es":"Relatividad Especial: Dilatación del Tiempo","it":"Relativite restrenete : dilatatione del temps","de":"Spezielle Relativitätstheorie: Zeitdilatation","fr":"Relativité restreinte : dilatation du temps","tr":"Özel Görelilik: Zaman Genişlemesi","nl":"Speciale relativiteit: tijddilatatie","ru":"Специальная теория относительности: замедление времени","zh":"狭义相对论：时间膨胀","pt_BR":"Relatividade Especial: Dilatação do Tempo","pt_PT":"Relatividade Especial: Dilatação do Tempo"}, back_translations: {"es":"t' = t/√(1 − v²/c²). Un relógio en movimiento funciona más devagar del que un estacionário, observado a partir del referencial estacionário. El efecto es significativo solo a velocidades próximas de c.","it":"t' = t/√(1 − v²/c²). Una horloge en mouvement ralentit per rapport à una horloge stationnaire observee depuis il referentiel stationnaire. L'effetto n'e significatif che à dei vitesses proches di c.","de":"t' = t/√(1 − v²/c²). Eine bewegte Uhr geht im Vergleich zu einer ruhenden langsamer, wie aus dem ruhenden Bezugssystem beobachtet. Der Effekt ist nur bei Geschwindigkeiten merklich, die sich c annähern.","fr":"t' = t/√(1 − v²/c²). Une horloge en mouvement ralentit par rapport à une horloge stationnaire observée depuis le référentiel stationnaire. L'effet n'est significatif qu'à des vitesses proches de c.","tr":"t' = t/√(1 − v²/c²). Hareket eden bir saat, durağan çerçeveden gözlemlendiğinde durağan bir saate göre daha yavaş çalışır. Etki yalnızca c'ye yakın hızlarda önemlidir.","nl":"t' = t/√(1 − v²/c²). Een bewegende klok loopt langzamer dan een stilstaande, zoals waargenomen vanuit het stilstaande referentiekader. Het effect is alleen significant bij snelheden dicht bij c.","ru":"t' = t/√(1 − v²/c²). Движущиеся часы идут медленнее, чем неподвижные, с точки зрения неподвижной системы отсчёта. Эффект заметен только при скоростях, близких к c.","zh":"t' = t/√(1 − v²/c²)。从静止参考系观测，运动的时钟比静止的时钟走得更慢。该效应仅在速度接近 c 时才显著。","pt_BR":"t' = t/√(1 − v²/c²). Um relógio em movimento funciona mais devagar do que um estacionário, observado a partir do referencial estacionário. O efeito é significativo apenas a velocidades próximas de c.","pt_PT":"t' = t/√(1 − v²/c²). Um relógio em movimento corre mais devagar do que um estacionário, observado a partir do referencial estacionário. O efeito é significativo apenas a velocidades próximas de c."}},
  { id: 'dc-physics-0080', deck_id: 'deck-physics', sort_order: 80, front: "Special Relativity: Length Contraction", back: "L' = L√(1 - v²/c²). An object moving relative to an observer appears shortened in the direction of motion. Only significant at speeds near c." , front_translations: {"es":"Relatividad Especial: Contración del Comprimento","it":"Relativite restrenete : contractione dei longuori","de":"Spezielle Relativitätstheorie: Längenkontraktion","fr":"Relativité restreinte : contraction des longueurs","tr":"Özel Görelilik: Uzunluk Kısalması","nl":"Speciale relativiteit: lengtecontractie","ru":"Специальная теория относительности: сокращение длины","zh":"狭义相对论：长度收缩","pt_BR":"Relatividade Especial: Contração do Comprimento","pt_PT":"Relatividade Especial: Contração do Comprimento"}, back_translations: {"es":"L' = L√(1 − v²/c²). Un objeto en movimiento en relación con un observador parece encurtado en la dirección del movimiento. Significativo solo a velocidades próximas de c.","it":"L' = L√(1 − v²/c²). Un objet en mouvement per rapport à un observatore semble raccourci in la direczione del mouvement. Seulement significatif à dei vitesses proches di c.","de":"L' = L√(1 − v²/c²). Ein sich relativ zu einem Beobachter bewegendes Objekt erscheint in Bewegungsrichtung verkürzt. Nur bei Geschwindigkeiten nahe c bedeutsam.","fr":"L' = L√(1 − v²/c²). Un objet en mouvement par rapport à un observateur semble raccourci dans la direction du mouvement. Seulement significatif à des vitesses proches de c.","tr":"L' = L√(1 − v²/c²). Bir gözlemciye göre hareket eden bir nesne, hareket yönünde kısalmış görünür. Yalnızca c'ye yakın hızlarda önemlidir.","nl":"L' = L√(1 − v²/c²). Een object dat beweegt ten opzichte van een waarnemer lijkt verkort in de bewegingsrichting. Alleen significant bij snelheden dicht bij c.","ru":"L' = L√(1 − v²/c²). Объект, движущийся относительно наблюдателя, выглядит укороченным в направлении движения. Заметно только при скоростях, близких к c.","zh":"L' = L√(1 − v²/c²)。相对于观测者运动的物体在运动方向上看起来缩短了。仅在速度接近 c 时才显著。","pt_BR":"L' = L√(1 − v²/c²). Um objeto em movimento em relação a um observador parece encurtado na direção do movimento. Significativo apenas a velocidades próximas de c.","pt_PT":"L' = L√(1 − v²/c²). Um objeto em movimento em relação a um observador parece encurtado na direção do movimento. Significativo apenas a velocidades próximas de c."}},
  { id: 'dc-physics-0081', deck_id: 'deck-physics', sort_order: 81, front: "Lorentz Factor", back: "γ = 1/√(1 - v²/c²). Appears in all relativistic formulas. Equals 1 at v=0 and approaches infinity as v→c, showing that infinite energy would be needed to reach c." , front_translations: {"es":"Fator de Lorentz","it":"Factore di Lorentz","de":"Lorentz-Faktor","fr":"Facteur de Lorentz","tr":"Lorentz Çarpanı","nl":"Lorentzfactor","ru":"Лоренц-фактор","zh":"洛伦兹因子","pt_BR":"Fator de Lorentz","pt_PT":"Fator de Lorentz"}, back_translations: {"es":"γ = 1/√(1 − v²/c²). Aparece en todas las fórmulas relativísticas. Igual a 1 cuando v=0 y tende al infinito cuando v→c, mostrando que sería necesaria energía infinita para atingir c.","it":"γ = 1/√(1 − v²/c²). Apparait in tutte i formules relativistes. Egal à 1 per v=0 e tend verso l'infini quando v→c, montrant che una energia infinie serait necessario per atteindre c.","de":"γ = 1/√(1 − v²/c²). Tritt in allen relativistischen Formeln auf. Bei v = 0 ist γ = 1 und nähert sich dem Unendlichen, wenn v → c, was zeigt, dass unendlich viel Energie benötigt würde, um c zu erreichen.","fr":"γ = 1/√(1 − v²/c²). Apparaît dans toutes les formules relativistes. Égal à 1 pour v=0 et tend vers l'infini lorsque v→c, montrant qu'une énergie infinie serait nécessaire pour atteindre c.","tr":"γ = 1/√(1 − v²/c²). Tüm göreli formüllerde yer alır. v=0'da 1'e eşittir ve v→c iken sonsuza yaklaşır; bu da c'ye ulaşmak için sonsuz enerjiye ihtiyaç duyulacağını gösterir.","nl":"γ = 1/√(1 − v²/c²). Verschijnt in alle relativistische formules. Gelijk aan 1 bij v=0 en nadert oneindig als v→c, wat aantoont dat oneindige energie nodig zou zijn om c te bereiken.","ru":"γ = 1/√(1 − v²/c²). Встречается во всех релятивистских формулах. При v=0 равен 1 и стремится к бесконечности при v→c, показывая, что для достижения c потребовалась бы бесконечная энергия.","zh":"γ = 1/√(1 − v²/c²)。出现在所有相对论公式中。v=0 时等于 1，v→c 时趋向无穷大，说明达到光速需要无限的能量。","pt_BR":"γ = 1/√(1 − v²/c²). Aparece em todas as fórmulas relativísticas. Igual a 1 quando v=0 e tende ao infinito quando v→c, mostrando que seria necessária energia infinita para atingir c.","pt_PT":"γ = 1/√(1 − v²/c²). Aparece em todas as fórmulas relativísticas. Igual a 1 quando v=0 e tende para o infinito quando v→c, mostrando que seria necessária energia infinita para atingir c."}},
  { id: 'dc-physics-0082', deck_id: 'deck-physics', sort_order: 82, front: "Pressure", back: "P = F/A. Pressure equals force divided by area. SI unit is the pascal (Pa = N/m²). Liquids exert pressure in all directions; atmospheric pressure ≈ 101,325 Pa." , front_translations: {"es":"Presión","it":"Pressione","de":"Druck","fr":"Pression","tr":"Basınç","nl":"Druk","ru":"Давление","zh":"压强","pt_BR":"Pressão","pt_PT":"Pressão"}, back_translations: {"es":"P = F/A. Presión es a fuerza dividida por la área. La unidad SI es el pascal (Pa = N/m²). Líquidos exercem presión en todas las direcciones; presión atmosférica ≈ 101.325 Pa.","it":"P = F/A. La pression e la force divisee per l'aire. L'unite SI e il pascal (Pa = N/m²). I liquides exercent una pression in tutte i direczioni ; la pression atmospherico ≈ 101 325 Pa.","de":"P = F/A. Druck ist die Kraft pro Flächeneinheit. SI-Einheit ist das Pascal (Pa = N/m²). Flüssigkeiten üben Druck in alle Richtungen aus; der Atmosphärendruck beträgt ca. 101.325 Pa.","fr":"P = F/A. La pression est la force divisée par l'aire. L'unité SI est le pascal (Pa = N/m²). Les liquides exercent une pression dans toutes les directions ; la pression atmosphérique ≈ 101 325 Pa.","tr":"P = F/A. Basınç, alana bölünen kuvvete eşittir. SI birimi pascal'dır (Pa = N/m²). Sıvılar her yönde basınç uygular; atmosfer basıncı ≈ 101.325 Pa.","nl":"P = F/A. Druk is kracht gedeeld door oppervlakte. SI-eenheid is de pascal (Pa = N/m²). Vloeistoffen oefenen druk in alle richtingen uit; atmosferische druk ≈ 101.325 Pa.","ru":"P = F/A. Давление равно силе, делённой на площадь. Единица СИ — паскаль (Па = Н/м²). Жидкости оказывают давление во всех направлениях; атмосферное давление ≈ 101 325 Па.","zh":"P = F/A。压强等于力除以面积。SI 单位是帕斯卡（Pa = N/m²）。液体向各个方向施加压力；大气压 ≈ 101 325 Pa。","pt_BR":"P = F/A. Pressão é a força dividida pela área. A unidade SI é o pascal (Pa = N/m²). Líquidos exercem pressão em todas as direções; pressão atmosférica ≈ 101.325 Pa.","pt_PT":"P = F/A. Pressão é a força dividida pela área. A unidade SI é o pascal (Pa = N/m²). Os líquidos exercem pressão em todas as direções; pressão atmosférica ≈ 101.325 Pa."}},
  { id: 'dc-physics-0083', deck_id: 'deck-physics', sort_order: 83, front: "Buoyancy (Archimedes' Principle)", back: "F_b = ρ_fluid·V_submerged·g. An object submerged in a fluid experiences an upward buoyant force equal to the weight of the fluid displaced." , front_translations: {"es":"Empuxo (Principio de Arquimedes)","it":"Spinta di Archimede (principio di Archimede)","de":"Auftrieb (Archimedisches Prinzip)","fr":"Poussée d'Archimède","tr":"Kaldırma Kuvveti (Arşimet İlkesi)","nl":"Opwaartse kracht (Wet van Archimedes)","ru":"Сила Архимеда","zh":"浮力（阿基米德原理）","pt_BR":"Empuxo (Princípio de Arquimedes)","pt_PT":"Impulsão (Princípio de Arquimedes)"}, back_translations: {"es":"F_b = ρ_fluido·V_submerso·g. Un objeto submerso en un fluido experimenta una fuerza de empuxo para cima igual al peso del fluido deslocado.","it":"F_b = ρ_fluide·V_immerge·g. Un objet immerge in un fluide subit una force di poussee verso il haut egale al poids del fluide deplace.","de":"F_b = ρ_Flüssigkeit·V_eingetaucht·g. Ein in eine Flüssigkeit eingetauchtes Objekt erfährt eine nach oben gerichtete Auftriebskraft, die gleich dem Gewicht der verdrängten Flüssigkeit ist.","fr":"F_b = ρ_fluide·V_immergé·g. Un objet immergé dans un fluide subit une force de poussée vers le haut égale au poids du fluide déplacé.","tr":"F_b = ρ_sıvı·V_daldırılmış·g. Bir sıvıya daldırılan cisim, yerinden ettiği sıvının ağırlığına eşit bir yukarı yönlü kaldırma kuvveti yaşar.","nl":"F_b = ρ_vloeistof·V_ondergedompeld·g. Een in een vloeistof ondergedompeld object ervaart een opwaartse vloeistofkracht gelijk aan het gewicht van de verplaatste vloeistof.","ru":"F_b = ρ_жидк·V_погруж·g. На тело, погружённое в жидкость, действует направленная вверх сила Архимеда, равная весу вытесненной жидкости.","zh":"F_b = ρ_液体·V_浸没·g。浸在液体中的物体受到一个向上的浮力，等于被排开液体的重力。","pt_BR":"F_b = ρ_fluido·V_submerso·g. Um objeto submerso em um fluido experimenta uma força de empuxo para cima igual ao peso do fluido deslocado.","pt_PT":"F_b = ρ_fluido·V_submerso·g. Um objeto submerso num fluido experimenta uma força de impulsão para cima igual ao peso do fluido deslocado."}},
  { id: 'dc-physics-0084', deck_id: 'deck-physics', sort_order: 84, front: "Bernoulli's Equation", back: "P + ½ρv² + ρgh = constant. Along a streamline in steady, incompressible flow, the sum of pressure, kinetic energy density, and potential energy density is constant." , front_translations: {"es":"Ecuación de Bernoulli","it":"Equatione di Bernoulli","de":"Bernoulli-Gleichung","fr":"Équation de Bernoulli","tr":"Bernoulli Denklemi","nl":"Vergelijking van Bernoulli","ru":"Уравнение Бернулли","zh":"伯努利方程","pt_BR":"Equação de Bernoulli","pt_PT":"Equação de Bernoulli"}, back_translations: {"es":"P + ½ρv² + ρgh = constante. La lo ancho de una línea de flujo en escoamento estacionário y incompressible, a suma de presión, densidad de energía cinética y densidad de energía potencial es constante.","it":"P + ½ρv² + ρgh = costante. Il long d'una ligne di courant in un ecoulement stationnaire incompressible, la somme della pression, della densite d'energia cinetico e della densite d'energia potenziale e costante.","de":"P + ½ρv² + ρgh = konstant. Entlang einer Stromlinie in einer stationären, inkompressiblen Strömung ist die Summe aus Druck, kinetischer Energiedichte und potenzieller Energiedichte konstant.","fr":"P + ½ρv² + ρgh = constante. Le long d'une ligne de courant dans un écoulement stationnaire incompressible, la somme de la pression, de la densité d'énergie cinétique et de la densité d'énergie potentielle est constante.","tr":"P + ½ρv² + ρgh = sabit. Durağan, sıkıştırılamaz bir akışta bir akım çizgisi boyunca basınç, kinetik enerji yoğunluğu ve potansiyel enerji yoğunluğunun toplamı sabittir.","nl":"P + ½ρv² + ρgh = constant. Langs een stroomlijn in een stationaire, incompressibele stroming is de som van druk, kinetische energiedichtheid en potentiële energiedichtheid constant.","ru":"P + ½ρv² + ρgh = const. Вдоль линии тока в стационарном несжимаемом потоке сумма давления, кинетической и потенциальной энергии единицы объёма постоянна.","zh":"P + ½ρv² + ρgh = 常数。在稳定不可压缩流动的流线上，压强、动能密度和势能密度之和为常数。","pt_BR":"P + ½ρv² + ρgh = constante. Ao longo de uma linha de fluxo em escoamento estacionário e incompressível, a soma de pressão, densidade de energia cinética e densidade de energia potencial é constante.","pt_PT":"P + ½ρv² + ρgh = constante. Ao longo de uma linha de corrente em escoamento estacionário e incompressível, a soma da pressão, da densidade de energia cinética e da densidade de energia potencial é constante."}},
  { id: 'dc-physics-0085', deck_id: 'deck-physics', sort_order: 85, front: "Continuity Equation (Fluids)", back: "A₁v₁ = A₂v₂. In an incompressible fluid, flow rate is constant; where the pipe narrows, fluid speed increases. Volume flow rate Q = Av." , front_translations: {"es":"Ecuación de la Continuidad (Fluidos)","it":"Equatione di continuite (fluides)","de":"Kontinuitätsgleichung (Strömungsmechanik)","fr":"Équation de continuité (fluides)","tr":"Süreklilik Denklemi (Akışkanlar)","nl":"Continuïteitsvergelijking (vloeistoffen)","ru":"Уравнение неразрывности (жидкости)","zh":"连续性方程（流体）","pt_BR":"Equação da Continuidade (Fluidos)","pt_PT":"Equação da Continuidade (Fluidos)"}, back_translations: {"es":"La₁v₁ = A₂v₂. En un fluido incompressible, a vazão es constante; donde el tubo estrecha, a velocidad del fluido aumenta. Vazão volumétrica Q = Av.","it":"A₁v₁ = A₂v₂. In un fluide incompressible, il debit e constant ; là où il tube se retrecit, la vitesse del fluide augmente. Debit volumico Q = Av.","de":"A₁v₁ = A₂v₂. Bei einer inkompressiblen Flüssigkeit ist der Volumenstrom konstant; wo das Rohr enger wird, steigt die Strömungsgeschwindigkeit. Volumenstrom Q = Av.","fr":"A₁v₁ = A₂v₂. Dans un fluide incompressible, le débit est constant ; là où le tube se rétrécit, la vitesse du fluide augmente. Débit volumique Q = Av.","tr":"A₁v₁ = A₂v₂. Sıkıştırılamaz bir sıvıda akış hızı sabittir; boru daraldıkça sıvı hızı artar. Hacimsel debi Q = Av.","nl":"A₁v₁ = A₂v₂. In een incompressibele vloeistof is de debietsnelheid constant; waar de buis smaller wordt, neemt de vloeistofsnelheid toe. Volumedebiet Q = Av.","ru":"A₁v₁ = A₂v₂. В несжимаемой жидкости объёмный расход постоянен; там, где трубка сужается, скорость жидкости увеличивается. Объёмный расход Q = Av.","zh":"A₁v₁ = A₂v₂。在不可压缩流体中，流量恒定；管道变窄处，流速增大。体积流量 Q = Av。","pt_BR":"A₁v₁ = A₂v₂. Em um fluido incompressível, a vazão é constante; onde o tubo estreita, a velocidade do fluido aumenta. Vazão volumétrica Q = Av.","pt_PT":"A₁v₁ = A₂v₂. Num fluido incompressível, o caudal é constante; onde o tubo estreita, a velocidade do fluido aumenta. Caudal volumétrico Q = Av."}},
  { id: 'dc-physics-0086', deck_id: 'deck-physics', sort_order: 86, front: "Pascal's Principle", back: "A change in pressure applied to an enclosed fluid is transmitted undiminished to every part of the fluid. Basis of hydraulic systems: F₁/A₁ = F₂/A₂." , front_translations: {"es":"Principio de Pascal","it":"Principio di Pascal","de":"Pascalsches Prinzip","fr":"Principe de Pascal","tr":"Pascal İlkesi","nl":"Wet van Pascal","ru":"Принцип Паскаля","zh":"帕斯卡原理","pt_BR":"Princípio de Pascal","pt_PT":"Princípio de Pascal"}, back_translations: {"es":"Una cambio de presión aplicada a un fluido fechado es transmitida sin disminución a cada parte del fluido. Base de los sistemas hidráulicos: F₁/A₁ = F₂/A₂.","it":"Un changement di pression applique à un fluide enferme e transmis senza attenuazione à tutte i parties del fluide. Base dei sistemi hydraulici : F₁/A₁ = F₂/A₂.","de":"Eine Druckänderung in einer eingeschlossenen Flüssigkeit wird ungeschwächt auf jeden Teil der Flüssigkeit übertragen. Grundlage hydraulischer Systeme: F₁/A₁ = F₂/A₂.","fr":"Un changement de pression appliqué à un fluide enfermé est transmis sans atténuation à toutes les parties du fluide. Base des systèmes hydrauliques : F₁/A₁ = F₂/A₂.","tr":"Kapalı bir sıvıya uygulanan basınç değişikliği, sıvının her noktasına eksiksiz iletilir. Hidrolik sistemlerin temeli: F₁/A₁ = F₂/A₂.","nl":"Een drukverandering die op een ingesloten vloeistof wordt aangebracht, wordt onverminderd overgedragen aan elk deel van de vloeistof. Basis van hydraulische systemen: F₁/A₁ = F₂/A₂.","ru":"Изменение давления, приложенное к замкнутой жидкости, передаётся без ослабления во все точки жидкости. Основа гидравлических систем: F₁/A₁ = F₂/A₂.","zh":"施加在密闭流体上的压强变化无衰减地传递到流体的每个部分。液压系统的基础：F₁/A₁ = F₂/A₂。","pt_BR":"Uma mudança de pressão aplicada a um fluido fechado é transmitida sem diminuição a cada parte do fluido. Base dos sistemas hidráulicos: F₁/A₁ = F₂/A₂.","pt_PT":"Uma alteração de pressão aplicada a um fluido fechado é transmitida sem diminuição a cada parte do fluido. Base dos sistemas hidráulicos: F₁/A₁ = F₂/A₂."}},
  { id: 'dc-physics-0087', deck_id: 'deck-physics', sort_order: 87, front: "Viscosity", back: "A measure of a fluid's resistance to flow. High viscosity (e.g., honey) flows slowly; low viscosity (e.g., water) flows easily. SI unit: pascal-second (Pa·s)." , front_translations: {"es":"Viscosidad","it":"Viscosite","de":"Viskosität","fr":"Viscosité","tr":"Viskozite","nl":"Viscositeit","ru":"Вязкость","zh":"粘度","pt_BR":"Viscosidade","pt_PT":"Viscosidade"}, back_translations: {"es":"Una medida de la resistencia de un fluido al escoamento. Alta viscosidad (por ejemplo, mel) flui lentamente; baja viscosidad (por ejemplo, agua) flui fácilmente. Unidad SI: pascal-según (Pa·s).","it":"Una mesure della resistanza di un fluide all'ecoulement. Haute viscosite (p. ex. miel) coule lentement ; faible viscosite (p. ex. eau) coule facilement. Unite SI : pascal-seconde (Pa·s).","de":"Ein Maß für den Strömungswiderstand einer Flüssigkeit. Hohe Viskosität (z. B. Honig) fließt langsam; niedrige Viskosität (z. B. Wasser) fließt leicht. SI-Einheit: Pascal-Sekunde (Pa·s).","fr":"Une mesure de la résistance d'un fluide à l'écoulement. Haute viscosité (p. ex. miel) coule lentement ; faible viscosité (p. ex. eau) coule facilement. Unité SI : pascal-seconde (Pa·s).","tr":"Bir sıvının akışa karşı direncinin ölçüsü. Yüksek viskoziteli (örneğin bal) yavaş akar; düşük viskoziteli (örneğin su) kolayca akar. SI birimi: pascal-saniye (Pa·s).","nl":"Een maat voor de weerstand van een vloeistof tegen stroming. Hoge viscositeit (bijv. honing) stroomt langzaam; lage viscositeit (bijv. water) stroomt gemakkelijk. SI-eenheid: pascal-seconde (Pa·s).","ru":"Мера сопротивления жидкости течению. Высокая вязкость (например, мёд) — течёт медленно; низкая вязкость (например, вода) — течёт легко. Единица СИ: паскаль-секунда (Па·с).","zh":"衡量流体对流动阻力的量。高粘度（如蜂蜜）流动缓慢；低粘度（如水）流动容易。SI 单位：帕斯卡·秒（Pa·s）。","pt_BR":"Uma medida da resistência de um fluido ao escoamento. Alta viscosidade (por exemplo, mel) flui lentamente; baixa viscosidade (por exemplo, água) flui facilmente. Unidade SI: pascal-segundo (Pa·s).","pt_PT":"Uma medida da resistência de um fluido ao escoamento. Alta viscosidade (por exemplo, mel) flui lentamente; baixa viscosidade (por exemplo, água) flui facilmente. Unidade SI: pascal-segundo (Pa·s)."}},
  { id: 'dc-physics-0088', deck_id: 'deck-physics', sort_order: 88, front: "Surface Tension", back: "The cohesive force at a liquid's surface that causes it to behave like a stretched elastic membrane. Allows insects to walk on water and causes capillary action." , front_translations: {"es":"Tensão Superficial","it":"Tensione superficielle","de":"Oberflächenspannung","fr":"Tension superficielle","tr":"Yüzey Gerilimi","nl":"Oppervlaktespanning","ru":"Поверхностное натяжение","zh":"表面张力","pt_BR":"Tensão Superficial","pt_PT":"Tensão Superficial"}, back_translations: {"es":"La fuerza coesiva en la superficie de un líquido que hace con que ele se comporte como una membrana elástica esticada. Permite que insetos caminhem sobre a agua y causa acción capilar.","it":"La force di cohesion alla surface di un liquide che lui fait se comporter come una membrane elastico tendue. Permet ai insectes di marcher su l'eau e provoque l'aczione capillaire.","de":"Die Kohäsionskraft an der Oberfläche einer Flüssigkeit, die sie wie eine gespannte elastische Membran wirken lässt. Ermöglicht es Insekten, auf Wasser zu laufen, und erzeugt Kapillarwirkung.","fr":"La force de cohésion à la surface d'un liquide qui lui fait se comporter comme une membrane élastique tendue. Permet aux insectes de marcher sur l'eau et provoque l'action capillaire.","tr":"Bir sıvının yüzeyindeki uyum kuvveti, onu gerilmiş esnek bir zar gibi davranmaya zorlar. Böceklerin su üzerinde yürümesine ve kılcal etkiye neden olur.","nl":"De cohesiekracht aan het oppervlak van een vloeistof die ervoor zorgt dat het zich gedraagt als een gestrekt elastisch membraan. Stelt insecten in staat op water te lopen en veroorzaakt capillaire werking.","ru":"Сила сцепления на поверхности жидкости, заставляющая её вести себя как натянутая упругая плёнка. Позволяет насекомым ходить по воде и является причиной капиллярного эффекта.","zh":"液体表面的内聚力，使其表现得像一张拉伸的弹性膜。使昆虫能在水面行走，并引起毛细管现象。","pt_BR":"A força coesiva na superfície de um líquido que faz com que ele se comporte como uma membrana elástica esticada. Permite que insetos caminhem sobre a água e causa ação capilar.","pt_PT":"A força coesiva na superfície de um líquido que o faz comportar-se como uma membrana elástica esticada. Permite que insetos caminhem sobre a água e causa ação capilar."}},
  { id: 'dc-physics-0089', deck_id: 'deck-physics', sort_order: 89, front: "Friction Force", back: "f = μN. Friction force equals the coefficient of friction times the normal force. Static friction (μ_s) is typically greater than kinetic friction (μ_k) for the same surfaces." , front_translations: {"es":"Fuerza de Atrito","it":"Force di frottemento","de":"Reibungskraft","fr":"Force de frottement","tr":"Sürtünme Kuvveti","nl":"Wrijvingskracht","ru":"Сила трения","zh":"摩擦力","pt_BR":"Força de Atrito","pt_PT":"Força de Atrito"}, back_translations: {"es":"f = μN. Fuerza de atrito es igual al coeficiente de atrito veces a fuerza normal. Atrito estático (μ_s) es típicamente mayor que el atrito cinético (μ_k) para las mismas superfícies.","it":"f = μN. La force di frottement e egale al coefficient di frottement multiplie per la force normale. La friczione statico (μ_s) e generalement superieure alla friczione cinetico (μ_k) per i memes surfaces.","de":"f = μN. Die Reibungskraft ist gleich dem Reibungskoeffizienten mal der Normalkraft. Haftreibung (μ_s) ist in der Regel größer als Gleitreibung (μ_k) bei denselben Oberflächen.","fr":"f = μN. La force de frottement est égale au coefficient de frottement multiplié par la force normale. La friction statique (μ_s) est généralement supérieure à la friction cinétique (μ_k) pour les mêmes surfaces.","tr":"f = μN. Sürtünme kuvveti, sürtünme katsayısı ile normal kuvvetin çarpımına eşittir. Statik sürtünme (μ_s), aynı yüzeyler için genellikle kinetik sürtünmeden (μ_k) büyüktür.","nl":"f = μN. Wrijvingskracht is gelijk aan de wrijvingscoëfficiënt maal de normaalkracht. Statische wrijving (μ_s) is typisch groter dan kinetische wrijving (μ_k) voor dezelfde oppervlakken.","ru":"f = μN. Сила трения равна коэффициенту трения, умноженному на нормальную силу. Сила трения покоя (μ_s) обычно больше силы трения скольжения (μ_k) для тех же поверхностей.","zh":"f = μN。摩擦力等于摩擦系数乘以法向力。对于相同的表面，静摩擦力（μ_s）通常大于动摩擦力（μ_k）。","pt_BR":"f = μN. Força de atrito é igual ao coeficiente de atrito vezes a força normal. Atrito estático (μ_s) é tipicamente maior que o atrito cinético (μ_k) para as mesmas superfícies.","pt_PT":"f = μN. Força de atrito é igual ao coeficiente de atrito vezes a força normal. O atrito estático (μ_s) é tipicamente maior do que o atrito cinético (μ_k) para as mesmas superfícies."}},
  { id: 'dc-physics-0090', deck_id: 'deck-physics', sort_order: 90, front: "Projectile Motion", back: "Horizontal: x = v₀cosθ·t. Vertical: y = v₀sinθ·t - ½gt². The horizontal and vertical components of motion are independent. Maximum range at 45°." , front_translations: {"es":"Movimiento de Projétil","it":"Moto parabolico","de":"Schiefer Wurf","fr":"Mouvement de projectile","tr":"Mermi Hareketi","nl":"Projectielbeweging","ru":"Движение тела, брошенного под углом","zh":"抛体运动","pt_BR":"Movimento de Projétil","pt_PT":"Movimento de Projétil"}, back_translations: {"es":"Horizontal: x = v₀cosθ·t. Vertical: y = v₀sinθ·t − ½gt². Los componentes horizontal y vertical del movimiento son independentes. Alcance máximo a 45°.","it":"Horizontal : x = v₀cosθ·t. Vertical : y = v₀sinθ·t − ½gt². I composantes horizontale e verticale del mouvement sono independantes. Portee maximale à 45°.","de":"Horizontal: x = v₀cosθ·t. Vertikal: y = v₀sinθ·t − ½gt². Die horizontale und vertikale Bewegungskomponente sind unabhängig voneinander. Maximale Reichweite bei 45°.","fr":"Horizontal : x = v₀cosθ·t. Vertical : y = v₀sinθ·t − ½gt². Les composantes horizontale et verticale du mouvement sont indépendantes. Portée maximale à 45°.","tr":"Yatay: x = v₀cosθ·t. Dikey: y = v₀sinθ·t − ½gt². Hareketin yatay ve dikey bileşenleri birbirinden bağımsızdır. Maksimum menzil 45°'de elde edilir.","nl":"Horizontaal: x = v₀cosθ·t. Verticaal: y = v₀sinθ·t − ½gt². De horizontale en verticale bewegingscomponenten zijn onafhankelijk. Maximaal bereik bij 45°.","ru":"Горизонталь: x = v₀cosθ·t. Вертикаль: y = v₀sinθ·t − ½gt². Горизонтальная и вертикальная составляющие движения независимы. Максимальная дальность при 45°.","zh":"水平：x = v₀cosθ·t。垂直：y = v₀sinθ·t − ½gt²。水平和垂直运动分量相互独立。45° 时射程最远。","pt_BR":"Horizontal: x = v₀cosθ·t. Vertical: y = v₀sinθ·t − ½gt². Os componentes horizontal e vertical do movimento são independentes. Alcance máximo a 45°.","pt_PT":"Horizontal: x = v₀cosθ·t. Vertical: y = v₀sinθ·t − ½gt². As componentes horizontal e vertical do movimento são independentes. Alcance máximo a 45°."}},
  { id: 'dc-physics-0091', deck_id: 'deck-physics', sort_order: 91, front: "Gravitational Field Strength", back: "g = GM/r². The gravitational acceleration at distance r from a mass M. On Earth's surface, g ≈ 9.81 m/s². Decreases as inverse square of distance from center." , front_translations: {"es":"Intensidad del Campo Gravitacional","it":"Intensite del campo gravitationenel","de":"Gravitationsfeldstärke","fr":"Intensité du champ gravitationnel","tr":"Yerçekimi Alanı Şiddeti","nl":"Zwaartekrachtveldsterkte","ru":"Напряжённость гравитационного поля","zh":"引力场强度","pt_BR":"Intensidade do Campo Gravitacional","pt_PT":"Intensidade do Campo Gravitacional"}, back_translations: {"es":"g = GM/r². La aceleración gravitacional a la distancia r de una masa M. Na superficie de la Tierra, g ≈ 9,81 m/s². Disminuye con el inverso del cuadrado de la distancia al centro.","it":"g = GM/r². L'accelerazione gravitationnelle alla distanza r d'una masse M. A la surface della Terre, g ≈ 9,81 m/s². Diminue selon il carre inverse della distanza al centre.","de":"g = GM/r². Die Gravitationsbeschleunigung im Abstand r von einer Masse M. An der Erdoberfläche beträgt g ≈ 9,81 m/s². Sie nimmt mit dem Quadrat des Abstands vom Mittelpunkt ab.","fr":"g = GM/r². L'accélération gravitationnelle à la distance r d'une masse M. À la surface de la Terre, g ≈ 9,81 m/s². Diminue selon le carré inverse de la distance au centre.","tr":"g = GM/r². M kütlesinden r uzaklıktaki yerçekimi ivmesi. Dünya yüzeyinde g ≈ 9,81 m/s². Merkezden uzaklığın karesiyle ters orantılı olarak azalır.","nl":"g = GM/r². De zwaartekrachtversnelling op afstand r van een massa M. Aan het aardoppervlak g ≈ 9,81 m/s². Neemt af als omgekeerde kwadraatfunctie van de afstand tot het middelpunt.","ru":"g = GM/r². Гравитационное ускорение на расстоянии r от массы M. На поверхности Земли g ≈ 9,81 м/с². Убывает обратно пропорционально квадрату расстояния от центра.","zh":"g = GM/r²。距质量 M 为 r 处的引力加速度。在地球表面，g ≈ 9.81 m/s²。随着距中心距离的平方成反比减小。","pt_BR":"g = GM/r². A aceleração gravitacional à distância r de uma massa M. Na superfície da Terra, g ≈ 9,81 m/s². Diminui com o inverso do quadrado da distância ao centro.","pt_PT":"g = GM/r². A aceleração gravitacional à distância r de uma massa M. Na superfície da Terra, g ≈ 9,81 m/s². Diminui com o inverso do quadrado da distância ao centro."}},
  { id: 'dc-physics-0092', deck_id: 'deck-physics', sort_order: 92, front: "Escape Velocity", back: "v_e = √(2GM/r). The minimum speed needed to escape a gravitational field without further propulsion. For Earth, v_e ≈ 11.2 km/s. Derived by setting KE = PE." , front_translations: {"es":"Velocidad de Escape","it":"Velocità di fuga","de":"Fluchtgeschwindigkeit","fr":"Vitesse de libération","tr":"Kaçış Hızı","nl":"Ontsnappingssnelheid","ru":"Вторая космическая скорость","zh":"逃逸速度","pt_BR":"Velocidade de Escape","pt_PT":"Velocidade de Escape"}, back_translations: {"es":"v_y = √(2GM/r). La velocidad mínima necesaria para escapar de un campo gravitacional sin propulsão adicional. Para a Tierra, v_y ≈ 11,2 km/s. Derivada igualando EC = EP.","it":"v_e = √(2GM/r). La vitesse minimale necessario per echapper à un champ gravitationnel senza propulsion supplementaire. Per la Terre, v_e ≈ 11,2 km/s. Derivee en posant KE = PE.","de":"v_e = √(2GM/r). Die Mindestgeschwindigkeit, die benötigt wird, um ohne weiteren Antrieb ein Gravitationsfeld zu verlassen. Für die Erde gilt v_e ≈ 11,2 km/s. Abgeleitet durch Gleichsetzen von kinetischer und potenzieller Energie.","fr":"v_e = √(2GM/r). La vitesse minimale nécessaire pour échapper à un champ gravitationnel sans propulsion supplémentaire. Pour la Terre, v_e ≈ 11,2 km/s. Dérivée en posant KE = PE.","tr":"v_e = √(2GM/r). Ek itici güç olmadan bir yerçekimi alanından kaçmak için gereken minimum hız. Dünya için v_e ≈ 11,2 km/s. KE = PE olarak ayarlanarak türetilir.","nl":"v_e = √(2GM/r). De minimale snelheid die nodig is om een zwaartekrachtveld te ontsnappen zonder verdere voortstuwing. Voor de Aarde v_e ≈ 11,2 km/s. Afgeleid door KE = PE te stellen.","ru":"v_e = √(2GM/r). Минимальная скорость, необходимая для выхода из поля тяготения без дополнительного ускорения. Для Земли v_e ≈ 11,2 км/с. Выводится из условия KE = PE.","zh":"v_e = √(2GM/r)。无需额外推力脱离引力场所需的最小速度。对于地球，v_e ≈ 11.2 km/s。通过令 KE = PE 推导得出。","pt_BR":"v_e = √(2GM/r). A velocidade mínima necessária para escapar de um campo gravitacional sem propulsão adicional. Para a Terra, v_e ≈ 11,2 km/s. Derivada igualando EC = EP.","pt_PT":"v_e = √(2GM/r). A velocidade mínima necessária para escapar de um campo gravitacional sem propulsão adicional. Para a Terra, v_e ≈ 11,2 km/s. Derivada igualando EC = EP."}},
  { id: 'dc-physics-0093', deck_id: 'deck-physics', sort_order: 93, front: "Orbital Velocity", back: "v = √(GM/r). The speed required to maintain a circular orbit at radius r. Balances gravitational force with the centripetal acceleration requirement." , front_translations: {"es":"Velocidad Orbital","it":"Velocita orbitale","de":"Orbitalgeschwindigkeit","fr":"Vitesse orbitale","tr":"Yörünge Hızı","nl":"Baansnelheid","ru":"Орбитальная скорость","zh":"轨道速度","pt_BR":"Velocidade Orbital","pt_PT":"Velocidade Orbital"}, back_translations: {"es":"v = √(GM/r). La velocidad necesaria para mantener una órbita circular en el raio r. Equilibra a fuerza gravitacional con el requisito de aceleración centrípeta.","it":"v = √(GM/r). La vitesse requise per maintenir una orbite circulaire al rayon r. Equilibre la force gravitationnelle con l'exigenza d'accelerazione centripete.","de":"v = √(GM/r). Die Geschwindigkeit, die erforderlich ist, um eine kreisförmige Umlaufbahn im Abstand r aufrechtzuerhalten. Sie balanciert die Gravitationskraft mit der Zentripetalbeschleunigung.","fr":"v = √(GM/r). La vitesse requise pour maintenir une orbite circulaire au rayon r. Équilibre la force gravitationnelle avec l'exigence d'accélération centripète.","tr":"v = √(GM/r). r yarıçapında dairesel bir yörüngeyi sürdürmek için gereken hız. Yerçekimi kuvvetini merkezcil ivme gerekliliğiyle dengeler.","nl":"v = √(GM/r). De snelheid die nodig is om een cirkelbaan op straal r te handhaven. Balanceert de zwaartekracht met de centripetale versnellingsvereiste.","ru":"v = √(GM/r). Скорость, необходимая для поддержания круговой орбиты на радиусе r. Уравновешивает силу тяготения и центростремительное ускорение.","zh":"v = √(GM/r)。在半径 r 处维持圆形轨道所需的速度。使引力与向心加速度需求相平衡。","pt_BR":"v = √(GM/r). A velocidade necessária para manter uma órbita circular no raio r. Equilibra a força gravitacional com o requisito de aceleração centrípeta.","pt_PT":"v = √(GM/r). A velocidade necessária para manter uma órbita circular no raio r. Equilibra a força gravitacional com o requisito de aceleração centrípeta."}},
  { id: 'dc-physics-0094', deck_id: 'deck-physics', sort_order: 94, front: "Kepler's Third Law", back: "T² ∝ r³, or T² = (4π²/GM)r³. The square of a planet's orbital period is proportional to the cube of its semi-major axis. Applies to any orbit around the same central body." , front_translations: {"es":"Tercera Ley de Kepler","it":"Terza legge di Kepler","de":"Keplers drittes Gesetz","fr":"Troisième loi de Kepler","tr":"Kepler'in Üçüncü Yasası","nl":"Derde wet van Kepler","ru":"Третий закон Кеплера","zh":"开普勒第三定律","pt_BR":"Terceira Lei de Kepler","pt_PT":"Terceira Lei de Kepler"}, back_translations: {"es":"T² ∝ r³, o T² = (4π²/GM)r³. El cuadrado del período orbital de un planeta es proporcional al cubo de su semieixo mayor. Se aplica a cualquier órbita en torno del mismo cuerpo central.","it":"T² ∝ r³, o T² = (4π²/GM)r³. Il carre della periode orbitale d'una planete e proportionnel al cube di il suo demi-grande axe. S'applico à tutta orbite autour del stesso corps central.","de":"T² ∝ r³ bzw. T² = (4π²/GM)r³. Das Quadrat der Umlaufzeit eines Planeten ist proportional zur dritten Potenz seiner großen Halbachse. Gilt für jede Umlaufbahn um denselben Zentralkörper.","fr":"T² ∝ r³, ou T² = (4π²/GM)r³. Le carré de la période orbitale d'une planète est proportionnel au cube de son demi-grand axe. S'applique à toute orbite autour du même corps central.","tr":"T² ∝ r³ veya T² = (4π²/GM)r³. Bir gezegenin yörünge periyodunun karesi, yarı-büyük ekseninin küpüyle orantılıdır. Aynı merkezi cisim etrafındaki herhangi bir yörünge için geçerlidir.","nl":"T² ∝ r³, of T² = (4π²/GM)r³. Het kwadraat van de omlooptijd van een planeet is evenredig met de kubus van zijn halve grote as. Geldt voor elke baan om hetzelfde centrale lichaam.","ru":"T² ∝ r³, или T² = (4π²/GM)r³. Квадрат периода обращения планеты пропорционален кубу большой полуоси её орбиты. Применимо к любой орбите вокруг одного и того же центрального тела.","zh":"T² ∝ r³，或 T² = (4π²/GM)r³。行星轨道周期的平方与其半长轴的立方成正比。适用于围绕同一中心天体的任何轨道。","pt_BR":"T² ∝ r³, ou T² = (4π²/GM)r³. O quadrado do período orbital de um planeta é proporcional ao cubo de seu semieixo maior. Aplica-se a qualquer órbita em torno do mesmo corpo central.","pt_PT":"T² ∝ r³, ou T² = (4π²/GM)r³. O quadrado do período orbital de um planeta é proporcional ao cubo do seu semieixo maior. Aplica-se a qualquer órbita em torno do mesmo corpo central."}},
  { id: 'dc-physics-0095', deck_id: 'deck-physics', sort_order: 95, front: "Electric Current", back: "I = Q/t = nqvA. Electric current is the rate of charge flow. One ampere equals one coulomb per second. Conventional current flows from high to low potential." , front_translations: {"es":"Corrente Eléctrica","it":"Courant elettrico","de":"Elektrischer Strom","fr":"Courant électrique","tr":"Elektrik Akımı","nl":"Elektrische stroom","ru":"Электрический ток","zh":"电流","pt_BR":"Corrente Elétrica","pt_PT":"Corrente Elétrica"}, back_translations: {"es":"I = Q/t = nqvA. Corrente eléctrica es a taxa de flujo de carga. Un ampere equivale a un coulomb por según. La corrente convencional flui del potencial alto para el bajo.","it":"I = Q/t = nqvA. Il courant electrico e il debit di charge. Un ampere equivaut à un coulomb per seconde. Il courant conventionnel va del potentiel eleve al potentiel faible.","de":"I = Q/t = nqvA. Elektrischer Strom ist die Ladungsflussrate. Ein Ampere entspricht einem Coulomb pro Sekunde. Der konventionelle Strom fließt vom hohen zum niedrigen Potential.","fr":"I = Q/t = nqvA. Le courant électrique est le débit de charge. Un ampère équivaut à un coulomb par seconde. Le courant conventionnel va du potentiel élevé au potentiel faible.","tr":"I = Q/t = nqvA. Elektrik akımı, yük akış hızıdır. Bir amper, saniyede bir coulomb'a eşittir. Geleneksel akım, yüksekten düşük potansiyele doğru akar.","nl":"I = Q/t = nqvA. Elektrische stroom is de stroomsnelheid van lading. Eén ampère staat gelijk aan één coulomb per seconde. De conventionele stroom stroomt van hoog naar laag potentiaal.","ru":"I = Q/t = nqvA. Электрический ток — это скорость переноса заряда. Один ампер равен одному кулону в секунду. Условный ток течёт от высокого потенциала к низкому.","zh":"I = Q/t = nqvA。电流是电荷流动的速率。一安培等于每秒一库仑。传统电流从高电位流向低电位。","pt_BR":"I = Q/t = nqvA. Corrente elétrica é a taxa de fluxo de carga. Um ampere equivale a um coulomb por segundo. A corrente convencional flui do potencial alto para o baixo.","pt_PT":"I = Q/t = nqvA. Corrente elétrica é a taxa de fluxo de carga. Um ampere equivale a um coulomb por segundo. A corrente convencional flui do potencial alto para o baixo."}},
  { id: 'dc-physics-0096', deck_id: 'deck-physics', sort_order: 96, front: "Magnetic Flux", back: "Φ = BAcosθ. Magnetic flux is the product of the magnetic field component perpendicular to a surface and the surface area. SI unit: weber (Wb = T·m²)." , front_translations: {"es":"Flujo Magnético","it":"Flux magnetico","de":"Magnetischer Fluss","fr":"Flux magnétique","tr":"Manyetik Akı","nl":"Magnetische flux","ru":"Магнитный поток","zh":"磁通量","pt_BR":"Fluxo Magnético","pt_PT":"Fluxo Magnético"}, back_translations: {"es":"Φ = BAcosθ. Flujo magnético es el producto de la componente del campo magnético perpendicular a una superficie por la área de la superficie. Unidad SI: weber (Wb = T·m²).","it":"Φ = BAcosθ. Il flux magnetico e il prodotto della composante del champ magnetico perpendiculaire à una surface per l'aire di questa surface. Unite SI : weber (Wb = T·m²).","de":"Φ = BAcosθ. Der magnetische Fluss ist das Produkt aus der senkrecht zur Fläche stehenden Magnetfeldkomponente und dem Flächeninhalt. SI-Einheit: Weber (Wb = T·m²).","fr":"Φ = BAcosθ. Le flux magnétique est le produit de la composante du champ magnétique perpendiculaire à une surface par l'aire de cette surface. Unité SI : weber (Wb = T·m²).","tr":"Φ = BAcosθ. Manyetik akı, manyetik alanın bir yüzeye dik bileşeni ile yüzey alanının çarpımıdır. SI birimi: weber (Wb = T·m²).","nl":"Φ = BAcosθ. Magnetische flux is het product van de magnetische veldcomponent loodrecht op een oppervlak en het oppervlak. SI-eenheid: weber (Wb = T·m²).","ru":"Φ = BAcosθ. Магнитный поток — это произведение составляющей магнитного поля, перпендикулярной поверхности, на площадь поверхности. Единица СИ: вебер (Вб = Тл·м²).","zh":"Φ = BAcosθ。磁通量是垂直于表面的磁场分量与表面积的乘积。SI 单位：韦伯（Wb = T·m²）。","pt_BR":"Φ = BAcosθ. Fluxo magnético é o produto da componente do campo magnético perpendicular a uma superfície pela área da superfície. Unidade SI: weber (Wb = T·m²).","pt_PT":"Φ = BAcosθ. Fluxo magnético é o produto da componente do campo magnético perpendicular a uma superfície pela área da superfície. Unidade SI: weber (Wb = T·m²)."}},
  { id: 'dc-physics-0097', deck_id: 'deck-physics', sort_order: 97, front: "Inductance", back: "EMF = -L(dI/dt). An inductor opposes changes in current. The induced EMF is proportional to the rate of change of current. SI unit: henry (H). Stores energy in its magnetic field." , front_translations: {"es":"Indutancia","it":"Inductanza","de":"Induktivität","fr":"Inductance","tr":"İndüktans","nl":"Inductantie","ru":"Индуктивность","zh":"电感","pt_BR":"Indutância","pt_PT":"Indutância"}, back_translations: {"es":"FEM = −L(dI/dt). Un indutor se opõe a cambios en la corrente. La FEM induzida es proporcional a la taxa de variación de la corrente. Unidad SI: henry (H). Almacena energía en su campo magnético.","it":"FEM = −L(dI/dt). Una bobine resiste ai changements di courant. La FEM induite e proportionnelle al taux di variazione del courant. Unite SI : henry (H). Stocke dell'energia in il suo champ magnetico.","de":"EMK = −L(dI/dt). Eine Spule setzt Änderungen des Stroms entgegen. Die induzierte EMK ist proportional zur Änderungsrate des Stroms. SI-Einheit: Henry (H). Speichert Energie im Magnetfeld.","fr":"FEM = −L(dI/dt). Une bobine résiste aux changements de courant. La FEM induite est proportionnelle au taux de variation du courant. Unité SI : henry (H). Stocke de l'énergie dans son champ magnétique.","tr":"EMK = −L(dI/dt). Bir endüktör, akımdaki değişikliklere karşı koyar. İndüklenen EMK, akımın değişim oranıyla orantılıdır. SI birimi: henry (H). Enerjisini manyetik alanında depolar.","nl":"EMK = −L(dI/dt). Een spoel weerstaat veranderingen in stroom. De geïnduceerde EMK is evenredig met de veranderingssnelheid van de stroom. SI-eenheid: henry (H). Slaat energie op in zijn magnetisch veld.","ru":"ЭДС = −L(dI/dt). Индуктор противодействует изменениям тока. Индуцированная ЭДС пропорциональна скорости изменения тока. Единица СИ: генри (Гн). Запасает энергию в магнитном поле.","zh":"EMF = −L(dI/dt)。电感器抵抗电流的变化。感应电动势与电流的变化率成正比。SI 单位：亨利（H）。在磁场中储存能量。","pt_BR":"FEM = −L(dI/dt). Um indutor se opõe a mudanças na corrente. A FEM induzida é proporcional à taxa de variação da corrente. Unidade SI: henry (H). Armazena energia em seu campo magnético.","pt_PT":"FEM = −L(dI/dt). Um indutor opõe-se a variações na corrente. A FEM induzida é proporcional à taxa de variação da corrente. Unidade SI: henry (H). Armazena energia no seu campo magnético."}},
  { id: 'dc-physics-0098', deck_id: 'deck-physics', sort_order: 98, front: "Transformer Equation", back: "V_s/V_p = N_s/N_p. In an ideal transformer, the ratio of voltages equals the ratio of turns. Step-up transformers increase voltage; step-down transformers decrease it." , front_translations: {"es":"Ecuación del Transformador","it":"Equatione del transformatore","de":"Transformatorgleichung","fr":"Équation du transformateur","tr":"Transformatör Denklemi","nl":"Transformatorvergelijking","ru":"Уравнение трансформатора","zh":"变压器方程","pt_BR":"Equação do Transformador","pt_PT":"Equação do Transformador"}, back_translations: {"es":"V_s/V_p = N_s/N_p. En un transformador ideal, a razão de las tensões es igual a la razão del número de espiras. Transformadores elevadores aumentan a tensão; transformadores abaixadores a disminuyen.","it":"V_s/V_p = N_s/N_p. In un transformatore ideal, il rapport dei tensions e egal al rapport dei spires. I transformatori elevatori augmentent la tension ; i transformatori abaissori la diminuent.","de":"V_s/V_p = N_s/N_p. Bei einem idealen Transformator ist das Verhältnis der Spannungen gleich dem Verhältnis der Windungszahlen. Aufwärtstransformatoren erhöhen die Spannung; Abwärtstransformatoren senken sie.","fr":"V_s/V_p = N_s/N_p. Dans un transformateur idéal, le rapport des tensions est égal au rapport des spires. Les transformateurs élévateurs augmentent la tension ; les transformateurs abaisseurs la diminuent.","tr":"V_s/V_p = N_s/N_p. İdeal bir transformatörde, gerilim oranı sarım sayısı oranına eşittir. Yükseltici transformatörler gerilimi artırır; alçaltıcı transformatörler ise düşürür.","nl":"V_s/V_p = N_s/N_p. In een ideale transformator is de verhouding van spanningen gelijk aan de verhouding van wikkelingen. Step-up transformatoren verhogen spanning; step-down transformatoren verlagen deze.","ru":"V_s/V_p = N_s/N_p. В идеальном трансформаторе отношение напряжений равно отношению числа витков. Повышающие трансформаторы увеличивают напряжение; понижающие — уменьшают.","zh":"V_s/V_p = N_s/N_p。在理想变压器中，电压比等于匝数比。升压变压器升高电压；降压变压器降低电压。","pt_BR":"V_s/V_p = N_s/N_p. Em um transformador ideal, a razão das tensões é igual à razão do número de espiras. Transformadores elevadores aumentam a tensão; transformadores abaixadores a diminuem.","pt_PT":"V_s/V_p = N_s/N_p. Num transformador ideal, a razão das tensões é igual à razão do número de espiras. Transformadores elevadores aumentam a tensão; transformadores redutores diminuem-na."}},
  { id: 'dc-physics-0099', deck_id: 'deck-physics', sort_order: 99, front: "Electromagnetic Spectrum", back: "From lowest to highest frequency: radio waves, microwaves, infrared, visible light, ultraviolet, X-rays, gamma rays. All travel at c in vacuum. Higher frequency = higher energy photons." , front_translations: {"es":"Espectro Eletromagnético","it":"Spettro elettromagnetico","de":"Elektromagnetisches Spektrum","fr":"Spectre électromagnétique","tr":"Elektromanyetik Spektrum","nl":"Elektromagnetisch spectrum","ru":"Электромагнитный спектр","zh":"电磁波谱","pt_BR":"Espectro Eletromagnético","pt_PT":"Espectro Eletromagnético"}, back_translations: {"es":"Da menor para a mayor frecuencia: ondas de rádio, micro-ondas, infravermelho, luz visible, ultravioleta, raios X, raios gama. Todos se propagam a c en el vácuo. Mayor frecuencia = fótons de mayor energía.","it":"Di la frequenza la più basse alla più haute : ondes radio, micro-ondes, infrarouge, luce visible, ultraviolet, rayons X, rayons gamma. Tous se propagent à c in il vide. Frequenza più elevee = photons di più haute energia.","de":"Von der niedrigsten zur höchsten Frequenz: Radiowellen, Mikrowellen, Infrarot, sichtbares Licht, Ultraviolett, Röntgenstrahlen, Gammastrahlen. Alle breiten sich im Vakuum mit c aus. Höhere Frequenz = energiereichere Photonen.","fr":"De la fréquence la plus basse à la plus haute : ondes radio, micro-ondes, infrarouge, lumière visible, ultraviolet, rayons X, rayons gamma. Tous se propagent à c dans le vide. Fréquence plus élevée = photons de plus haute énergie.","tr":"En düşükten en yüksek frekansa: radyo dalgaları, mikrodalgalar, kızılötesi, görünür ışık, ultraviyole, X ışınları, gama ışınları. Tümü vakumda c ile yayılır. Daha yüksek frekans = daha yüksek enerjili fotonlar.","nl":"Van laagste tot hoogste frequentie: radiogolven, microgolven, infrarood, zichtbaar licht, ultraviolet, röntgenstralen, gammastralen. Alle reizen met c in vacuüm. Hogere frequentie = hogere energiefotonen.","ru":"От наименьшей к наибольшей частоте: радиоволны, микроволны, инфракрасное, видимый свет, ультрафиолет, рентгеновские лучи, гамма-лучи. Все распространяются со скоростью c в вакууме. Чем выше частота — тем выше энергия фотонов.","zh":"从最低到最高频率：无线电波、微波、红外线、可见光、紫外线、X 射线、伽马射线。在真空中均以 c 传播。频率越高 = 光子能量越高。","pt_BR":"Da menor para a maior frequência: ondas de rádio, micro-ondas, infravermelho, luz visível, ultravioleta, raios X, raios gama. Todos se propagam a c no vácuo. Maior frequência = fótons de maior energia.","pt_PT":"Da menor para a maior frequência: ondas de rádio, micro-ondas, infravermelho, luz visível, ultravioleta, raios X, raios gama. Todos se propagam a c no vácuo. Maior frequência = fotões de maior energia."}},
  { id: 'dc-physics-0100', deck_id: 'deck-physics', sort_order: 100, front: "Diffraction", back: "The bending of waves around obstacles or through openings. Most pronounced when the gap size is comparable to the wavelength. Explains why sound bends around corners more than light." , front_translations: {"es":"Difración","it":"Diffrazione","de":"Beugung","fr":"Diffraction","tr":"Kırınım","nl":"Diffractie","ru":"Дифракция","zh":"衍射","pt_BR":"Difração","pt_PT":"Difração"}, back_translations: {"es":"El dobramento de ondas alrededor de obstáculos o a través de aberturas. Más pronunciado cuando el tamaño de la abertura es comparable al comprimento de onda. Explica por que el sonido dobra alrededor de cantos más del que a luz.","it":"La deviazione dei ondes autour d'obstacles o attraverso dei ouvertures. La più prononcee quando la taille dell'ouverture e comparable alla longuore d'onde. Explico pourquoi il il suo contourne i angles mieux che la luce.","de":"Das Beugen von Wellen um Hindernisse oder durch Öffnungen. Am ausgeprägtesten, wenn die Spaltbreite vergleichbar mit der Wellenlänge ist. Erklärt, warum Schall um Ecken biegt, mehr als Licht.","fr":"La déviation des ondes autour d'obstacles ou à travers des ouvertures. La plus prononcée quand la taille de l'ouverture est comparable à la longueur d'onde. Explique pourquoi le son contourne les angles mieux que la lumière.","tr":"Dalgaların engeller etrafında veya açıklıklardan geçerek kıvrılması. Açıklık boyutu dalga boyuyla kıyaslanabilir olduğunda en belirgindir. Sesin ışıktan daha fazla köşeleri neden döndüğünü açıklar.","nl":"Het buigen van golven om obstakels of door openingen. Meest uitgesproken wanneer de opening vergelijkbaar is met de golflengte. Verklaart waarom geluid meer om hoeken buigt dan licht.","ru":"Огибание волнами препятствий или прохождение через отверстия. Наиболее выражено, когда размер щели сопоставим с длиной волны. Объясняет, почему звук огибает углы лучше, чем свет.","zh":"波绕过障碍物或通过开口时的弯曲现象。当开口尺寸与波长相当时最为明显。解释了为什么声音比光更容易绕过角落。","pt_BR":"O dobramento de ondas ao redor de obstáculos ou através de aberturas. Mais pronunciado quando o tamanho da abertura é comparável ao comprimento de onda. Explica por que o som dobra em torno de cantos mais do que a luz.","pt_PT":"O dobramento de ondas em torno de obstáculos ou através de aberturas. Mais pronunciado quando o tamanho da abertura é comparável ao comprimento de onda. Explica por que o som dobra em torno de cantos mais do que a luz."}},
  { id: 'dc-physics-0101', deck_id: 'deck-physics', sort_order: 101, front: "Polarization of Light", back: "Light is a transverse wave; polarization refers to the orientation of the electric field vector. Polaroid filters transmit only one plane of polarization, reducing glare." , front_translations: {"es":"Polarización de la Luz","it":"Polarisatione di la luce","de":"Polarisation von Licht","fr":"Polarisation de la lumière","tr":"Işığın Polarizasyonu","nl":"Polarisatie van licht","ru":"Поляризация света","zh":"光的偏振","pt_BR":"Polarização da Luz","pt_PT":"Polarização da Luz"}, back_translations: {"es":"La luz es una onda transversal; a polarización se refiere a la orientación del vetor del campo eléctrico. Filtros polaroid transmitem solo un plano de polarización, reduciendo el brilho.","it":"La luce e una onde transversale ; la polarisazione designe l'orientazione del vectore champ electrico. I filtres polaroid non transmettent che un plan di polarisazione, reduisant ainsi i reflets.","de":"Licht ist eine Transversalwelle; Polarisation beschreibt die Ausrichtung des elektrischen Feldvektors. Polaroidfilter lassen nur eine Schwingungsebene durch und reduzieren so Blendung.","fr":"La lumière est une onde transversale ; la polarisation désigne l'orientation du vecteur champ électrique. Les filtres polaroïd ne transmettent qu'un plan de polarisation, réduisant ainsi les reflets.","tr":"Işık bir enine dalgadır; polarizasyon, elektrik alan vektörünün yönelimini ifade eder. Polaroid filtreler yalnızca tek bir polarizasyon düzlemini ileterek parlamayı azaltır.","nl":"Licht is een transversale golf; polarisatie verwijst naar de oriëntatie van de elektrische veldvector. Polaroidfilters laten slechts één polarisatievlak door, waardoor schittering wordt verminderd.","ru":"Свет является поперечной волной; поляризация относится к ориентации вектора электрического поля. Поляроидные фильтры пропускают только одну плоскость поляризации, уменьшая блики.","zh":"光是横波；偏振是指电场矢量的方向。偏振滤光片只透射一个偏振面，从而减少眩光。","pt_BR":"A luz é uma onda transversal; a polarização refere-se à orientação do vetor do campo elétrico. Filtros polaroid transmitem apenas um plano de polarização, reduzindo o brilho.","pt_PT":"A luz é uma onda transversal; a polarização refere-se à orientação do vetor do campo elétrico. Os filtros polaroid transmitem apenas um plano de polarização, reduzindo o brilho."}},
  { id: 'dc-physics-0102', deck_id: 'deck-physics', sort_order: 102, front: "Resonance", back: "When a system is driven at its natural frequency, it absorbs maximum energy and oscillates with maximum amplitude. Examples: tuning forks, radio circuits, Tacoma Narrows Bridge collapse." , front_translations: {"es":"Ressonancia","it":"Resonanza","de":"Resonanz","fr":"Résonance","tr":"Rezonans","nl":"Resonantie","ru":"Резонанс","zh":"共振","pt_BR":"Ressonância","pt_PT":"Ressonância"}, back_translations: {"es":"Cuando un sistema es excitado en su frecuencia natural, ele absorbe energía máxima y oscila con amplitude máxima. Ejemplos: diapasões, circuitos de rádio, colapso de la ponte Tacoma Narrows.","it":"Quand un sistema e excite alla sua frequenza naturelle, il absorbe un maximum d'energia e oscille con una amplitude maximale. Exemples : diapasons, circuits radio, effondrement del pont di Tacoma Narrows.","de":"Wenn ein System mit seiner Eigenfrequenz angeregt wird, absorbiert es maximale Energie und schwingt mit maximaler Amplitude. Beispiele: Stimmgabeln, Radioschaltkreise, Einsturz der Tacoma-Narrows-Brücke.","fr":"Quand un système est excité à sa fréquence naturelle, il absorbe un maximum d'énergie et oscille avec une amplitude maximale. Exemples : diapasons, circuits radio, effondrement du pont de Tacoma Narrows.","tr":"Bir sistem doğal frekansında sürüldüğünde maksimum enerji emer ve maksimum genlikle titreşir. Örnekler: diyapazonlar, radyo devreleri, Tacoma Narrows Köprüsü çöküşü.","nl":"Wanneer een systeem wordt aangedreven op zijn eigenfrequentie, absorbeert het maximale energie en trilt het met maximale amplitude. Voorbeelden: stemvorken, radiocircuits, instorting van de Tacoma Narrows Bridge.","ru":"Когда система возбуждается на своей собственной частоте, она поглощает максимальную энергию и колеблется с максимальной амплитудой. Примеры: камертоны, радиоцепи, обрушение моста Такома-Нэрроус.","zh":"当系统以其固有频率被驱动时，它吸收最大能量并以最大振幅振荡。例子：音叉、无线电电路、塔科马海峡大桥倒塌。","pt_BR":"Quando um sistema é excitado em sua frequência natural, ele absorve energia máxima e oscila com amplitude máxima. Exemplos: diapasões, circuitos de rádio, colapso da ponte Tacoma Narrows.","pt_PT":"Quando um sistema é excitado na sua frequência natural, absorbe energia máxima e oscila com amplitude máxima. Exemplos: diapasões, circuitos de rádio, colapso da ponte Tacoma Narrows."}},
  { id: 'dc-physics-0103', deck_id: 'deck-physics', sort_order: 103, front: "Beat Frequency", back: "f_beat = |f₁ - f₂|. When two sound waves of slightly different frequencies superpose, they produce a pulsating sound (beats) at a rate equal to the difference in their frequencies." , front_translations: {"es":"Frecuencia de Batimento","it":"Frequenza di battemento","de":"Schwebungsfrequenz","fr":"Fréquence de battement","tr":"Vuru Frekansı","nl":"Kloppingsfrequentie","ru":"Частота биений","zh":"拍频","pt_BR":"Frequência de Batimento","pt_PT":"Frequência de Batimento"}, back_translations: {"es":"f_batimento = |f₁ - f₂|. Cuando de los ondas sonoras de frequencias ligeiramente diferentes se superpõem, producen un sonido pulsante (batimentos) a una taxa igual a la diferencia en sus frequencias.","it":"f_battement = |f₁ - f₂|. Quand deux ondes sonores di frequenze legerement differentes se superposent, elles produisent un il suo pulse (battements) à una cadenza egale alla differenza di i loro frequenze.","de":"f_Schwebung = |f₁ - f₂|. Wenn sich zwei Schallwellen mit leicht unterschiedlichen Frequenzen überlagern, erzeugen sie einen pulsierenden Klang (Schwebungen) mit einer Rate gleich der Frequenzdifferenz.","fr":"f_battement = |f₁ - f₂|. Quand deux ondes sonores de fréquences légèrement différentes se superposent, elles produisent un son pulsé (battements) à une cadence égale à la différence de leurs fréquences.","tr":"f_vuru = |f₁ - f₂|. Hafif farklı frekanslardaki iki ses dalgası üst üste geldiğinde, frekans farklarına eşit bir hızda titreşen bir ses (vurular) üretirler.","nl":"f_kloppingen = |f₁ - f₂|. Wanneer twee geluidsgolven van iets verschillende frequenties samenvallen, produceren ze een pulserend geluid (klopping) met een snelheid gelijk aan het verschil in frequenties.","ru":"f_биений = |f₁ - f₂|. Когда две звуковые волны с немного различающимися частотами суперпозируют, они производят пульсирующий звук (биения) с частотой, равной разности их частот.","zh":"f_拍 = |f₁ - f₂|。当两列频率稍有不同的声波叠加时，会产生以其频率差为速率的脉动声音（拍）。","pt_BR":"f_batimento = |f₁ - f₂|. Quando duas ondas sonoras de frequências ligeiramente diferentes se superpõem, produzem um som pulsante (batimentos) a uma taxa igual à diferença em suas frequências.","pt_PT":"f_batimento = |f₁ - f₂|. Quando duas ondas sonoras de frequências ligeiramente diferentes se sobrepõem, produzem um som pulsante (batimentos) a uma taxa igual à diferença das suas frequências."}},
  { id: 'dc-physics-0104', deck_id: 'deck-physics', sort_order: 104, front: "Work Done by a Gas", back: "W = PΔV (at constant pressure). The work done by a gas expanding against pressure equals pressure times change in volume. Positive work is done when gas expands." , front_translations: {"es":"Trabajo Realizado por un Gas","it":"Travail effectue per un gaz","de":"Arbeit eines Gases","fr":"Travail effectué par un gaz","tr":"Bir Gazın Yaptığı İş","nl":"Arbeid verricht door een gas","ru":"Работа, совершаемая газом","zh":"气体做的功","pt_BR":"Trabalho Realizado por um Gás","pt_PT":"Trabalho Realizado por um Gás"}, back_translations: {"es":"W = PΔV (a presión constante). El trabajo realizado por un gas en expansão contra a presión es igual a la presión multiplicada por la variación de volumen. Trabajo positivo es realizado cuando el gas se expande.","it":"W = PΔV (à pression costante). Il travail effectue per un gaz en expansion contre la pression e egal alla pression multipliee per la variazione di volume. Un travail positif e fourni quando il gaz se dilate.","de":"W = PΔV (bei konstantem Druck). Die von einem sich ausdehnenden Gas gegen den Druck geleistete Arbeit entspricht dem Druck multipliziert mit der Volumenänderung. Positive Arbeit wird geleistet, wenn das Gas sich ausdehnt.","fr":"W = PΔV (à pression constante). Le travail effectué par un gaz en expansion contre la pression est égal à la pression multipliée par la variation de volume. Un travail positif est fourni quand le gaz se dilate.","tr":"W = PΔV (sabit basınçta). Basınca karşı genişleyen bir gazın yaptığı iş, basınç çarpı hacim değişimine eşittir. Gaz genişlediğinde pozitif iş yapılır.","nl":"W = PΔV (bij constante druk). De arbeid verricht door een gas dat uitdijt tegen druk is gelijk aan druk maal volumeverandering. Positieve arbeid wordt verricht wanneer het gas uitzet.","ru":"W = PΔV (при постоянном давлении). Работа, совершаемая расширяющимся газом против давления, равна давлению, умноженному на изменение объёма. Положительная работа совершается при расширении газа.","zh":"W = PΔV（恒压条件下）。气体对抗压力膨胀所做的功等于压力乘以体积变化量。气体膨胀时做正功。","pt_BR":"W = PΔV (a pressão constante). O trabalho realizado por um gás em expansão contra a pressão é igual à pressão multiplicada pela variação de volume. Trabalho positivo é realizado quando o gás se expande.","pt_PT":"W = PΔV (a pressão constante). O trabalho realizado por um gás em expansão contra a pressão é igual à pressão multiplicada pela variação de volume. Trabalho positivo é realizado quando o gás se expande."}},
  { id: 'dc-physics-0105', deck_id: 'deck-physics', sort_order: 105, front: "Internal Energy of an Ideal Gas", back: "U = (3/2)nRT for monatomic ideal gas. Internal energy depends only on temperature, not pressure or volume. For diatomic gases, U = (5/2)nRT at room temperature." , front_translations: {"es":"Energía Interna de un Gas Ideal","it":"Energie interne d'un gaz parfait","de":"Innere Energie eines idealen Gases","fr":"Énergie interne d'un gaz parfait","tr":"İdeal Bir Gazın İç Enerjisi","nl":"Inwendige energie van een ideaal gas","ru":"Внутренняя энергия идеального газа","zh":"理想气体的内能","pt_BR":"Energia Interna de um Gás Ideal","pt_PT":"Energia Interna de um Gás Ideal"}, back_translations: {"es":"U = (3/2)nRT para gas ideal monoatomico. La energía interna depende solo de la temperatura, no de la presión o del volumen. Para gases diatomicos, U = (5/2)nRT a la temperatura ambiente.","it":"U = (3/2)nRT per un gaz parfait monoatomico. L'energia interne non depend che della temperature, della pression o del volume. Per i gaz diatomici, U = (5/2)nRT à temperature ambiante.","de":"U = (3/2)nRT für einatomiges ideales Gas. Die innere Energie hängt nur von der Temperatur ab, nicht von Druck oder Volumen. Für zweiatomige Gase gilt U = (5/2)nRT bei Raumtemperatur.","fr":"U = (3/2)nRT pour un gaz parfait monoatomique. L'énergie interne ne dépend que de la température, pas de la pression ou du volume. Pour les gaz diatomiques, U = (5/2)nRT à température ambiante.","tr":"U = (3/2)nRT tek atomlu ideal gaz için. İç enerji yalnızca sıcaklığa bağlıdır, basınç veya hacme değil. İki atomlu gazlar için oda sıcaklığında U = (5/2)nRT.","nl":"U = (3/2)nRT voor een eenatomig ideaal gas. Inwendige energie hangt alleen af van temperatuur, niet van druk of volume. Voor tweeatomige gassen geldt U = (5/2)nRT bij kamertemperatuur.","ru":"U = (3/2)nRT для одноатомного идеального газа. Внутренняя энергия зависит только от температуры, а не от давления или объёма. Для двухатомных газов U = (5/2)nRT при комнатной температуре.","zh":"单原子理想气体 U = (3/2)nRT。内能只取决于温度，与压力或体积无关。室温下双原子气体 U = (5/2)nRT。","pt_BR":"U = (3/2)nRT para gás ideal monoatômico. A energia interna depende apenas da temperatura, não da pressão ou do volume. Para gases diatômicos, U = (5/2)nRT à temperatura ambiente.","pt_PT":"U = (3/2)nRT para gás ideal monoatómico. A energia interna depende apenas da temperatura, não da pressão ou do volume. Para gases diatómicos, U = (5/2)nRT à temperatura ambiente."}},
  { id: 'dc-physics-0106', deck_id: 'deck-physics', sort_order: 106, front: "Entropy", back: "ΔS = Q/T (reversible process). Entropy is a measure of disorder or the number of available microstates. The entropy of the universe always increases in irreversible processes." , front_translations: {"es":"Entropia","it":"Entropie","de":"Entropie","fr":"Entropie","tr":"Entropi","nl":"Entropie","ru":"Энтропия","zh":"熵","pt_BR":"Entropia","pt_PT":"Entropia"}, back_translations: {"es":"ΔS = Q/T (proceso reversible). Entropia es una medida de desordem o del número de microestados disponibles. La entropia del universo siempre aumenta en procesos irreversibles.","it":"ΔS = Q/T (processo reversible). L'entropie mesure il desordre o il nombre di microetats disponibles. L'entropie dell'univers augmente toujours lors di processo irreversibles.","de":"ΔS = Q/T (reversibler Prozess). Entropie ist ein Maß für Unordnung oder die Anzahl verfügbarer Mikrozustände. Die Entropie des Universums nimmt bei irreversiblen Prozessen stets zu.","fr":"ΔS = Q/T (processus réversible). L'entropie mesure le désordre ou le nombre de microétats disponibles. L'entropie de l'univers augmente toujours lors de processus irréversibles.","tr":"ΔS = Q/T (tersinir süreç). Entropi, düzensizliğin veya mevcut mikro durumların sayısının bir ölçüsüdür. Evrenin entropisi geri dönüşümsüz süreçlerde her zaman artar.","nl":"ΔS = Q/T (reversibel proces). Entropie is een maat voor wanorde of het aantal beschikbare microtoestanden. De entropie van het universum neemt altijd toe bij onomkeerbare processen.","ru":"ΔS = Q/T (обратимый процесс). Энтропия — мера беспорядка или числа доступных микросостояний. Энтропия вселенной всегда возрастает при необратимых процессах.","zh":"ΔS = Q/T（可逆过程）。熵是无序程度或可用微观状态数的量度。在不可逆过程中，宇宙的熵总是增加。","pt_BR":"ΔS = Q/T (processo reversível). Entropia é uma medida de desordem ou do número de microestados disponíveis. A entropia do universo sempre aumenta em processos irreversíveis.","pt_PT":"ΔS = Q/T (processo reversível). A entropia é uma medida de desordem ou do número de microestados disponíveis. A entropia do universo aumenta sempre em processos irreversíveis."}},
  { id: 'dc-physics-0107', deck_id: 'deck-physics', sort_order: 107, front: "Maxwell's Equations (Overview)", back: "Four equations describing all classical electromagnetic phenomena: Gauss's law for E, Gauss's law for B, Faraday's law, and Ampere-Maxwell law. Unified electricity, magnetism, and optics." , front_translations: {"es":"Ecuaciones de Maxwell (Visão Geral)","it":"Equationes di Maxwell (aperzu)","de":"Maxwellsche Gleichungen (Überblick)","fr":"Équations de Maxwell (aperçu)","tr":"Maxwell Denklemleri (Genel Bakış)","nl":"Vergelijkingen van Maxwell (overzicht)","ru":"Уравнения Максвелла (обзор)","zh":"麦克斯韦方程组（概述）","pt_BR":"Equações de Maxwell (Visão Geral)","pt_PT":"Equações de Maxwell (Visão Geral)"}, back_translations: {"es":"Cuatro ecuaciones que descrevem todos los fenómenos eletromagnéticos clássicos: ley de Gauss para Y, ley de Gauss para B, ley de Faraday y ley de Ampère-Maxwell. Unificaram eletricidad, magnetismo y óptica.","it":"Quatre equazioni decrivant tutti i phenomenes electromagnetici classici : loi di Gauss per E, loi di Gauss per B, loi di Faraday e loi d'Ampere-Maxwell. Ont unifie l'electricite, il magnetisme e l'optico.","de":"Vier Gleichungen, die alle klassischen elektromagnetischen Phänomene beschreiben: Gaußsches Gesetz für E, Gaußsches Gesetz für B, Faradaysches Gesetz und Ampère-Maxwell-Gesetz. Vereinten Elektrizität, Magnetismus und Optik.","fr":"Quatre équations décrivant tous les phénomènes électromagnétiques classiques : loi de Gauss pour E, loi de Gauss pour B, loi de Faraday et loi d'Ampère-Maxwell. Ont unifié l'électricité, le magnétisme et l'optique.","tr":"Tüm klasik elektromanyetik olguları tanımlayan dört denklem: E için Gauss yasası, B için Gauss yasası, Faraday yasası ve Ampère-Maxwell yasası. Elektriği, manyetizmayı ve optiği birleştirdi.","nl":"Vier vergelijkingen die alle klassieke elektromagnetische verschijnselen beschrijven: de wet van Gauss voor E, de wet van Gauss voor B, de wet van Faraday en de Ampère-Maxwell-wet. Verenigden elektriciteit, magnetisme en optica.","ru":"Четыре уравнения, описывающие все классические электромагнитные явления: закон Гаусса для E, закон Гаусса для B, закон Фарадея и закон Ампера–Максвелла. Объединили электричество, магнетизм и оптику.","zh":"描述所有经典电磁现象的四个方程：E的高斯定律、B的高斯定律、法拉第定律和安培-麦克斯韦定律。统一了电、磁和光学。","pt_BR":"Quatro equações que descrevem todos os fenômenos eletromagnéticos clássicos: lei de Gauss para E, lei de Gauss para B, lei de Faraday e lei de Ampère-Maxwell. Unificaram eletricidade, magnetismo e óptica.","pt_PT":"Quatro equações que descrevem todos os fenómenos eletromagnéticos clássicos: lei de Gauss para E, lei de Gauss para B, lei de Faraday e lei de Ampère-Maxwell. Unificaram eletricidade, magnetismo e ótica."}},
  { id: 'dc-physics-0108', deck_id: 'deck-physics', sort_order: 108, front: "Bohr Model of the Atom", back: "Electrons orbit the nucleus in fixed energy levels. Transitions between levels emit or absorb photons: E = hf = E_initial - E_final. Accurately predicts hydrogen spectrum." , front_translations: {"es":"Modelo Atómico de Bohr","it":"Modello atomico di Bohr","de":"Bohrsches Atommodell","fr":"Modèle atomique de Bohr","tr":"Bohr Atom Modeli","nl":"Bohrmodel van het atoom","ru":"Модель атома Бора","zh":"玻尔原子模型","pt_BR":"Modelo Atômico de Bohr","pt_PT":"Modelo Atómico de Bohr"}, back_translations: {"es":"Los electrones orbitam el núcleo en niveles de energía fixos. As transiciones entre niveles emitem o absorben fótons: Y = hf = Y_inicial - Y_final. Preve con precisão el espectro del hidrógeno.","it":"I electrons orbitent autour del noyau su dei niveaux d'energia fixes. I transizioni tra niveaux emettent o absorbent dei photons : E = hf = E_initial - E_final. Predit con precision il spectre dell'hydrogenon.","de":"Elektronen umkreisen den Kern auf festen Energieniveaus. Übergänge zwischen Niveaus emittieren oder absorbieren Photonen: E = hf = E_Anfang - E_Ende. Beschreibt das Wasserstoffspektrum korrekt.","fr":"Les électrons orbitent autour du noyau sur des niveaux d'énergie fixes. Les transitions entre niveaux émettent ou absorbent des photons : E = hf = E_initial - E_final. Prédit avec précision le spectre de l'hydrogène.","tr":"Elektronlar çekirdeği sabit enerji seviyelerinde yörüngede döner. Seviyeler arasındaki geçişler foton yayar veya soğurur: E = hf = E_başlangıç - E_son. Hidrojen spektrumunu doğru şekilde tahmin eder.","nl":"Elektronen draaien om de kern in vaste energieniveaus. Overgangen tussen niveaus zenden fotonen uit of absorberen ze: E = hf = E_initieel - E_finaal. Voorspelt het waterstofspectrum nauwkeurig.","ru":"Электроны вращаются вокруг ядра на фиксированных энергетических уровнях. Переходы между уровнями сопровождаются испусканием или поглощением фотонов: E = hf = E_начальное - E_конечное. Точно описывает спектр водорода.","zh":"电子在固定能级上绕核运动。能级之间的跃迁会发射或吸收光子：E = hf = E_初 - E_末。准确预测了氢原子光谱。","pt_BR":"Os elétrons orbitam o núcleo em níveis de energia fixos. As transições entre níveis emitem ou absorvem fótons: E = hf = E_inicial - E_final. Prevê com precisão o espectro do hidrogênio.","pt_PT":"Os eletrões orbitam o núcleo em níveis de energia fixos. As transições entre níveis emitem ou absorvem fotões: E = hf = E_inicial - E_final. Prevê com precisão o espectro do hidrogénio."}},
  { id: 'dc-physics-0109', deck_id: 'deck-physics', sort_order: 109, front: "Hydrogen Energy Levels", back: "E_n = -13.6/n² eV. Energy of the nth level in hydrogen. Ground state (n=1) has energy -13.6 eV. Positive energy indicates ionization (electron freed from atom)." , front_translations: {"es":"Niveles de Energía del Hidrógeno","it":"Niveaux d'energia dell'hydrogene","de":"Energieniveaus des Wasserstoffatoms","fr":"Niveaux d'énergie de l'hydrogène","tr":"Hidrojen Enerji Seviyeleri","nl":"Energieniveaus van waterstof","ru":"Энергетические уровни водорода","zh":"氢原子能级","pt_BR":"Níveis de Energia do Hidrogênio","pt_PT":"Níveis de Energia do Hidrogénio"}, back_translations: {"es":"Y_n = -13,6/n² eV. Energía del n-ésimo nivel en el hidrógeno. El estado fundamental (n=1) tiene energía -13,6 eV. Energía positiva indica ionización (electrón liberado del átomo).","it":"E_n = -13,6/n² eV. Energie del n-ieme niveau in l'hydrogenon. L'etat fondamental (n=1) ha una energia di -13,6 eV. Una energia positive indico l'ionisazione (electron libere dell'atome).","de":"E_n = -13,6/n² eV. Energie des n-ten Niveaus im Wasserstoff. Grundzustand (n=1) hat die Energie -13,6 eV. Positive Energie bedeutet Ionisation (Elektron wird vom Atom gelöst).","fr":"E_n = -13,6/n² eV. Énergie du n-ième niveau dans l'hydrogène. L'état fondamental (n=1) a une énergie de -13,6 eV. Une énergie positive indique l'ionisation (électron libéré de l'atome).","tr":"E_n = -13,6/n² eV. Hidrojendeki n'inci seviyenin enerjisi. Taban durum (n=1) -13,6 eV enerjiye sahiptir. Pozitif enerji iyonizasyonu (elektronun atomdan kopması) gösterir.","nl":"E_n = -13,6/n² eV. Energie van het n-de niveau in waterstof. Grondtoestand (n=1) heeft energie -13,6 eV. Positieve energie duidt op ionisatie (elektron losgemaakt van atoom).","ru":"E_n = -13,6/n² эВ. Энергия n-го уровня в водороде. Основное состояние (n=1) имеет энергию -13,6 эВ. Положительная энергия означает ионизацию (электрон освобождён от атома).","zh":"E_n = -13.6/n² eV。氢原子第n个能级的能量。基态（n=1）能量为-13.6 eV。正能量表示电离（电子从原子中逃脱）。","pt_BR":"E_n = -13,6/n² eV. Energia do n-ésimo nível no hidrogênio. O estado fundamental (n=1) tem energia -13,6 eV. Energia positiva indica ionização (elétron liberado do átomo).","pt_PT":"E_n = -13,6/n² eV. Energia do n-ésimo nível no hidrogénio. O estado fundamental (n=1) tem energia -13,6 eV. Energia positiva indica ionização (eletrão libertado do átomo)."}},
  { id: 'dc-physics-0110', deck_id: 'deck-physics', sort_order: 110, front: "Wave-Particle Duality", back: "Quantum objects like electrons and photons exhibit both wave-like and particle-like behavior depending on the experiment. The double-slit experiment demonstrates this duality dramatically." , front_translations: {"es":"Dualidad Onda-Partícula","it":"Dualità onda-particella","de":"Welle-Teilchen-Dualismus","fr":"Dualité onde-corpuscule","tr":"Dalga-Parçacık İkilemi","nl":"Golf-deeltje-dualiteit","ru":"Корпускулярно-волновой дуализм","zh":"波粒二象性","pt_BR":"Dualidade Onda-Partícula","pt_PT":"Dualidade Onda-Partícula"}, back_translations: {"es":"Objetos quanticos como electrones y fótons exibem comportamiento tanto ondulatório quanto corpuscular, dependendo del experimento. El experimento de dupla fenda demonstra dramaticamente essa dualidad.","it":"I objets quantici come i electrons e i photons presentent allo stesso tempo dei comportements ondulatoires e corpusculaires selon l'experienza. L'experienza della double fente illustre spectaculairement questa dualite.","de":"Quantenobjekte wie Elektronen und Photonen zeigen je nach Experiment sowohl wellen- als auch teilchenartige Eigenschaften. Das Doppelspaltexperiment veranschaulicht diesen Dualismus eindrucksvoll.","fr":"Les objets quantiques comme les électrons et les photons présentent à la fois des comportements ondulatoires et corpusculaires selon l'expérience. L'expérience de la double fente illustre spectaculairement cette dualité.","tr":"Elektronlar ve fotonlar gibi kuantum nesneleri, deneye bağlı olarak hem dalga hem de parçacık benzeri davranışlar sergiler. Çift yarık deneyi bu ikiliği çarpıcı biçimde gösterir.","nl":"Kwantumobjecten zoals elektronen en fotonen vertonen zowel golfachtig als deeltjesachtig gedrag, afhankelijk van het experiment. Het dubbelspletexperiment toont deze dualiteit op dramatische wijze aan.","ru":"Квантовые объекты, такие как электроны и фотоны, проявляют как волновые, так и корпускулярные свойства в зависимости от эксперимента. Опыт с двойной щелью наглядно демонстрирует этот дуализм.","zh":"电子和光子等量子物体根据实验的不同，既表现出波动性，也表现出粒子性。双缝实验戏剧性地展示了这种二象性。","pt_BR":"Objetos quânticos como elétrons e fótons exibem comportamento tanto ondulatório quanto corpuscular, dependendo do experimento. O experimento de dupla fenda demonstra dramaticamente essa dualidade.","pt_PT":"Objetos quânticos como eletrões e fotões exibem comportamento tanto ondulatório como corpuscular, dependendo da experiência. A experiência de dupla fenda demonstra dramaticamente esta dualidade."}},
  { id: 'dc-physics-0111', deck_id: 'deck-physics', sort_order: 111, front: "Pauli Exclusion Principle", back: "No two fermions (electrons, protons, neutrons) in the same system can occupy the same quantum state simultaneously. Explains electron shell structure and the stability of matter." , front_translations: {"es":"Principio de Exclusão de Pauli","it":"Principe d'exclusione di Pauli","de":"Pauli-Ausschlussprinzip","fr":"Principe d'exclusion de Pauli","tr":"Pauli Dışlama İlkesi","nl":"Uitsluitingsprincipe van Pauli","ru":"Принцип запрета Паули","zh":"泡利不相容原理","pt_BR":"Princípio de Exclusão de Pauli","pt_PT":"Princípio de Exclusão de Pauli"}, back_translations: {"es":"Dos férmions (electrones, protones, neutrones) en el mismo sistema no pueden ocupar el mismo estado quantico simultáneamente. Explica a estructura de las capas eletronicas y a estabilidad de la materia.","it":"Deux fermions (electrons, protons, neutrons) in il stesso sistema non possono occuper simultanement il stesso etat quantico. Explico la structure dei couches electronici e la stabilite della matiere.","de":"Keine zwei Fermionen (Elektronen, Protonen, Neutronen) im gleichen System können gleichzeitig denselben Quantenzustand einnehmen. Erklärt die Elektronenschalenstruktur und die Stabilität der Materie.","fr":"Deux fermions (électrons, protons, neutrons) dans le même système ne peuvent pas occuper simultanément le même état quantique. Explique la structure des couches électroniques et la stabilité de la matière.","tr":"Aynı sistemdeki iki fermiyon (elektron, proton, nötron) aynı anda aynı kuantum durumunu işgal edemez. Elektron kabuk yapısını ve maddenin kararlılığını açıklar.","nl":"Geen twee fermionen (elektronen, protonen, neutronen) in hetzelfde systeem kunnen tegelijkertijd dezelfde kwantumtoestand innemen. Verklaart de elektronenschaalstructuur en de stabiliteit van materie.","ru":"Никакие два фермиона (электроны, протоны, нейтроны) в одной системе не могут одновременно находиться в одном квантовом состоянии. Объясняет структуру электронных оболочек и устойчивость вещества.","zh":"同一系统中没有两个费米子（电子、质子、中子）可以同时占据相同的量子态。解释了电子壳层结构和物质的稳定性。","pt_BR":"Dois férmions (elétrons, prótons, nêutrons) no mesmo sistema não podem ocupar o mesmo estado quântico simultaneamente. Explica a estrutura das camadas eletrônicas e a estabilidade da matéria.","pt_PT":"Dois fermiões (eletrões, protões, neutrões) no mesmo sistema não podem ocupar o mesmo estado quântico simultaneamente. Explica a estrutura das camadas eletrónicas e a estabilidade da matéria."}},
  { id: 'dc-physics-0112', deck_id: 'deck-physics', sort_order: 112, front: "Strong Nuclear Force", back: "The force that holds protons and neutrons together in the nucleus. Strongest of the four fundamental forces but acts only at very short range (~10⁻¹⁵ m). Overcomes electrostatic repulsion." , front_translations: {"es":"Fuerza Nuclear Fuerte","it":"Force nucleare forte","de":"Starke Kernkraft","fr":"Force nucléaire forte","tr":"Güçlü Nükleer Kuvvet","nl":"Sterke kernkracht","ru":"Сильное ядерное взаимодействие","zh":"强核力","pt_BR":"Força Nuclear Forte","pt_PT":"Força Nuclear Forte"}, back_translations: {"es":"La fuerza que mantiene protones y neutrones juntos en el núcleo. La más fuerte de las cuatro fuerzas fundamentales, pero age solo en distancias muy curtas (~10⁻¹⁵ m). Supera a repulsão eletrostática.","it":"La force che maintient i protons e i neutrons ensemble in il noyau. La più forte dei quatre forces fondamentales, ma n'agit che à molto courte portee (~10⁻¹⁵ m). Surmonte la repulsion electrostatico.","de":"Die Kraft, die Protonen und Neutronen im Kern zusammenhält. Stärkste der vier Grundkräfte, wirkt aber nur auf sehr kurze Distanzen (~10⁻¹⁵ m). Überwindet die elektrostatische Abstoßung.","fr":"La force qui maintient les protons et les neutrons ensemble dans le noyau. La plus forte des quatre forces fondamentales, mais n'agit qu'à très courte portée (~10⁻¹⁵ m). Surmonte la répulsion électrostatique.","tr":"Protonları ve nötronları çekirdekte bir arada tutan kuvvet. Dört temel kuvvetin en güçlüsüdür, ancak yalnızca çok kısa mesafelerde (~10⁻¹⁵ m) etki eder. Elektrostatik itmeyi yener.","nl":"De kracht die protonen en neutronen bij elkaar houdt in de kern. Sterkste van de vier fundamentele krachten maar werkt slechts op zeer korte afstand (~10⁻¹⁵ m). Overwint elektrostatische afstoting.","ru":"Сила, удерживающая протоны и нейтроны вместе в ядре. Самая сильная из четырёх фундаментальных взаимодействий, но действует лишь на очень малых расстояниях (~10⁻¹⁵ м). Преодолевает электростатическое отталкивание.","zh":"将质子和中子结合在原子核中的力。是四种基本力中最强的，但只在极短距离（约10⁻¹⁵ m）内起作用。克服了静电排斥力。","pt_BR":"A força que mantém prótons e nêutrons juntos no núcleo. A mais forte das quatro forças fundamentais, mas age apenas em distâncias muito curtas (~10⁻¹⁵ m). Supera a repulsão eletrostática.","pt_PT":"A força que mantém protões e neutrões juntos no núcleo. A mais forte das quatro forças fundamentais, mas atua apenas a distâncias muito curtas (~10⁻¹⁵ m). Supera a repulsão eletrostática."}},
  { id: 'dc-physics-0113', deck_id: 'deck-physics', sort_order: 113, front: "Weak Nuclear Force", back: "Responsible for beta decay and other flavor-changing particle interactions. Mediated by W and Z bosons. Much weaker than the strong force and acts at extremely short range." , front_translations: {"es":"Fuerza Nuclear Débil","it":"Force nucleare faibile","de":"Schwache Kernkraft","fr":"Force nucléaire faible","tr":"Zayıf Nükleer Kuvvet","nl":"Zwakke kernkracht","ru":"Слабое ядерное взаимодействие","zh":"弱核力","pt_BR":"Força Nuclear Fraca","pt_PT":"Força Nuclear Fraca"}, back_translations: {"es":"Responsable por el decaimento beta y outras interacciones de partículas con cambio de sabor. Mediada por los bósons W y Z. Muito más débil del que a fuerza fuerte y actúa en distancias extremamente curtas.","it":"Responsable della desintegrazione beta e d'autres interaczioni tra particules impliquant dei changements di savore. Transmise per i bosons W e Z. Beaucoup più faible che la force forte e agit à una portee extremement courte.","de":"Verantwortlich für den Betazerfall und andere teilchenwechselwirkungen mit Flavor-Änderungen. Vermittelt durch W- und Z-Bosonen. Viel schwächer als die starke Kraft und wirkt auf extrem kurze Reichweiten.","fr":"Responsable de la désintégration bêta et d'autres interactions entre particules impliquant des changements de saveur. Transmise par les bosons W et Z. Beaucoup plus faible que la force forte et agit à une portée extrêmement courte.","tr":"Beta bozunması ve diğer tat değiştiren parçacık etkileşimlerinden sorumludur. W ve Z bozonları tarafından iletilir. Güçlü kuvvetten çok daha zayıftır ve son derece kısa mesafelerde etki eder.","nl":"Verantwoordelijk voor bètaverval en andere smaakveranderende deeltjesinteracties. Gemedieerd door W- en Z-bosonen. Veel zwakker dan de sterke kracht en werkt op extreem korte afstand.","ru":"Отвечает за бета-распад и другие взаимодействия частиц с изменением аромата. Переносится W- и Z-бозонами. Значительно слабее сильного взаимодействия и действует на крайне малых расстояниях.","zh":"负责β衰变和其他改变味道的粒子相互作用。由W和Z玻色子传递。比强力弱得多，作用于极短的距离。","pt_BR":"Responsável pelo decaimento beta e outras interações de partículas com mudança de sabor. Mediada pelos bósons W e Z. Muito mais fraca do que a força forte e atua em distâncias extremamente curtas.","pt_PT":"Responsável pela desintegração beta e outras interações de partículas com mudança de sabor. Mediada pelos bosões W e Z. Muito mais fraca do que a força forte e atua a distâncias extremamente curtas."}},
  { id: 'dc-physics-0114', deck_id: 'deck-physics', sort_order: 114, front: "Four Fundamental Forces", back: "Gravity, electromagnetism, strong nuclear force, weak nuclear force. Gravity is weakest but infinite range; strong force is strongest but very short range. All others fall between." , front_translations: {"es":"Cuatro Fuerzas Fundamentales","it":"Les quatre forzas fondamentalees","de":"Vier Grundkräfte","fr":"Les quatre forces fondamentales","tr":"Dört Temel Kuvvet","nl":"Vier fundamentele krachten","ru":"Четыре фундаментальных взаимодействия","zh":"四种基本力","pt_BR":"Quatro Forças Fundamentais","pt_PT":"Quatro Forças Fundamentais"}, back_translations: {"es":"Gravidad, eletromagnetismo, fuerza nuclear fuerte, fuerza nuclear débil. La gravidad es a más débil, pero tiene alcance infinito; a fuerza fuerte es a más poderosa, pero tiene alcance muy corto. Todas las outras ficam entre los de los.","it":"Gravite, electromagnetisme, force nucleaire forte, force nucleaire faible. La gravite e la più faible ma ha una portee infinie ; la force forte e la più puissante ma à molto courte portee. Toutes i autres se situent tra i deux.","de":"Gravitation, Elektromagnetismus, starke Kernkraft, schwache Kernkraft. Gravitation ist die schwächste, hat aber unendliche Reichweite; die starke Kraft ist am stärksten, hat aber sehr kurze Reichweite. Alle anderen liegen dazwischen.","fr":"Gravité, électromagnétisme, force nucléaire forte, force nucléaire faible. La gravité est la plus faible mais a une portée infinie ; la force forte est la plus puissante mais à très courte portée. Toutes les autres se situent entre les deux.","tr":"Yerçekimi, elektromanyetizma, güçlü nükleer kuvvet, zayıf nükleer kuvvet. Yerçekimi en zayıfıdır ama sonsuz menzillidir; güçlü kuvvet en güçlüdür ama çok kısa menzillidir. Diğerleri bu ikisi arasında yer alır.","nl":"Zwaartekracht, elektromagnetisme, sterke kernkracht, zwakke kernkracht. Zwaartekracht is het zwakst maar heeft oneindige reikwijdte; de sterke kracht is het sterkst maar heeft een zeer korte reikwijdte. Alle andere vallen er tussenin.","ru":"Гравитация, электромагнетизм, сильное ядерное взаимодействие, слабое ядерное взаимодействие. Гравитация — самое слабое, но с бесконечным радиусом действия; сильное — самое мощное, но с очень малым радиусом. Остальные занимают промежуточное положение.","zh":"引力、电磁力、强核力、弱核力。引力最弱但作用范围无限；强力最强但作用范围极短。其余两种介于两者之间。","pt_BR":"Gravidade, eletromagnetismo, força nuclear forte, força nuclear fraca. A gravidade é a mais fraca, mas tem alcance infinito; a força forte é a mais poderosa, mas tem alcance muito curto. Todas as outras ficam entre os dois.","pt_PT":"Gravidade, eletromagnetismo, força nuclear forte, força nuclear fraca. A gravidade é a mais fraca, mas tem alcance infinito; a força forte é a mais poderosa, mas tem alcance muito curto. Todas as outras situam-se entre os dois extremos."}},
  { id: 'dc-physics-0115', deck_id: 'deck-physics', sort_order: 115, front: "Speed of Light", back: "c ≈ 2.998×10⁸ m/s in vacuum. The universal speed limit; no information or matter with mass can travel at or beyond c. All electromagnetic waves travel at c in vacuum." , front_translations: {"es":"Velocidad de la Luz","it":"Velocita di la luce","de":"Lichtgeschwindigkeit","fr":"Vitesse de la lumière","tr":"Işık Hızı","nl":"Lichtsnelheid","ru":"Скорость света","zh":"光速","pt_BR":"Velocidade da Luz","pt_PT":"Velocidade da Luz"}, back_translations: {"es":"c ≈ 2,998×10⁸ m/s en el vácuo. El limite universal de velocidad; ninguna información o materia con masa puede viajar en c o além de c. Todas las ondas eletromagnéticas viajam a c en el vácuo.","it":"c ≈ 2,998×10⁸ m/s in il vide. La vitesse limite universelle ; aucune informazione ni matiere con masse non può atteindre o depasser c. Toutes i ondes electromagnetici se propagent à c in il vide.","de":"c ≈ 2,998×10⁸ m/s im Vakuum. Die universelle Geschwindigkeitsgrenze; keine Information und keine Materie mit Masse kann c erreichen oder überschreiten. Alle elektromagnetischen Wellen bewegen sich im Vakuum mit c.","fr":"c ≈ 2,998×10⁸ m/s dans le vide. La vitesse limite universelle ; aucune information ni matière avec masse ne peut atteindre ou dépasser c. Toutes les ondes électromagnétiques se propagent à c dans le vide.","tr":"c ≈ 2,998×10⁸ m/s boşlukta. Evrensel hız sınırı; kütlesi olan hiçbir bilgi veya madde c'ye ulaşamaz veya geçemez. Tüm elektromanyetik dalgalar boşlukta c hızında hareket eder.","nl":"c ≈ 2,998×10⁸ m/s in vacuüm. De universele snelheidslimiet; geen informatie of materie met massa kan c bereiken of overschrijden. Alle elektromagnetische golven reizen met c in vacuüm.","ru":"c ≈ 2,998×10⁸ м/с в вакууме. Универсальный предел скорости; никакая информация и никакое вещество с массой не могут достичь скорости c или превысить её. Все электромагнитные волны движутся в вакууме со скоростью c.","zh":"c ≈ 2.998×10⁸ m/s（真空中）。宇宙速度极限；任何有质量的物质或信息都无法达到或超过c。所有电磁波在真空中都以c传播。","pt_BR":"c ≈ 2,998×10⁸ m/s no vácuo. O limite universal de velocidade; nenhuma informação ou matéria com massa pode viajar em c ou além de c. Todas as ondas eletromagnéticas viajam a c no vácuo.","pt_PT":"c ≈ 2,998×10⁸ m/s no vácuo. O limite universal de velocidade; nenhuma informação ou matéria com massa pode viajar a c ou além de c. Todas as ondas eletromagnéticas viajam a c no vácuo."}},
  { id: 'dc-physics-0116', deck_id: 'deck-physics', sort_order: 116, front: "Electron Volt (eV)", back: "1 eV = 1.602×10⁻¹⁹ J. The energy gained by an electron moving through a potential difference of one volt. Convenient unit for atomic and nuclear energy scales." , front_translations: {"es":"Electrón-volt (eV)","it":"Electron-volt (eV)","de":"Elektronenvolt (eV)","fr":"Électron-volt (eV)","tr":"Elektron Volt (eV)","nl":"Elektronvolt (eV)","ru":"Электронвольт (эВ)","zh":"电子伏特（eV）","pt_BR":"Elétron-volt (eV)","pt_PT":"Eletrão-volt (eV)"}, back_translations: {"es":"1 eV = 1,602×10⁻¹⁹ J. La energía ganha por un electrón al se mover a través de una diferencia de potencial de un volt. Unidad conveniente para escalas de energía atómica y nuclear.","it":"1 eV = 1,602×10⁻¹⁹ J. L'energia acquise per un electron traversant una differenza di potentiel di un volt. Unite pratico per i echelles d'energia atomico e nucleaire.","de":"1 eV = 1,602×10⁻¹⁹ J. Die Energie, die ein Elektron gewinnt, wenn es eine Potentialdifferenz von einem Volt durchquert. Praktische Einheit für atomare und nukleare Energieskalen.","fr":"1 eV = 1,602×10⁻¹⁹ J. L'énergie acquise par un électron traversant une différence de potentiel d'un volt. Unité pratique pour les échelles d'énergie atomique et nucléaire.","tr":"1 eV = 1,602×10⁻¹⁹ J. Bir elektronun bir volt potansiyel fark boyunca hareket ederken kazandığı enerji. Atomik ve nükleer enerji ölçekleri için uygun bir birim.","nl":"1 eV = 1,602×10⁻¹⁹ J. De energie die een elektron wint bij het doorlopen van een potentiaalverschil van één volt. Handige eenheid voor atomaire en nucleaire energieschalen.","ru":"1 эВ = 1,602×10⁻¹⁹ Дж. Энергия, приобретаемая электроном при движении через разность потенциалов в один вольт. Удобная единица для атомных и ядерных энергетических шкал.","zh":"1 eV = 1.602×10⁻¹⁹ J。电子通过一伏特电位差所获得的能量。原子和核能量尺度的便捷单位。","pt_BR":"1 eV = 1,602×10⁻¹⁹ J. A energia ganha por um elétron ao se mover através de uma diferença de potencial de um volt. Unidade conveniente para escalas de energia atômica e nuclear.","pt_PT":"1 eV = 1,602×10⁻¹⁹ J. A energia ganha por um eletrão ao mover-se através de uma diferença de potencial de um volt. Unidade conveniente para escalas de energia atómica e nuclear."}},
  { id: 'dc-physics-0117', deck_id: 'deck-physics', sort_order: 117, front: "Avogadro's Number", back: "N_A = 6.022×10²³ mol⁻¹. The number of particles (atoms, molecules, etc.) in one mole of substance. Connects macroscopic quantities to atomic-scale properties." , front_translations: {"es":"Número de Avogadro","it":"Numero di Avogadro","de":"Avogadro-Zahl","fr":"Nombre d'Avogadro","tr":"Avogadro Sayısı","nl":"Getal van Avogadro","ru":"Число Авогадро","zh":"阿伏伽德罗常数","pt_BR":"Número de Avogadro","pt_PT":"Número de Avogadro"}, back_translations: {"es":"N_A = 6,022×10²³ mol⁻¹. El número de partículas (átomos, moléculas, etc.) en un mol de sustancia. Conecta quantidades macroscópicas a propiedades en la escala atómica.","it":"N_A = 6,022×10²³ mol⁻¹. Il nombre di particules (atomes, molecole, etc.) in una mole di substanza. Relie i grandori macroscopici ai proprietàs all'echelle atomico.","de":"N_A = 6,022×10²³ mol⁻¹. Die Anzahl der Teilchen (Atome, Moleküle usw.) in einem Mol eines Stoffes. Verbindet makroskopische Größen mit atomaren Eigenschaften.","fr":"N_A = 6,022×10²³ mol⁻¹. Le nombre de particules (atomes, molécules, etc.) dans une mole de substance. Relie les grandeurs macroscopiques aux propriétés à l'échelle atomique.","tr":"N_A = 6,022×10²³ mol⁻¹. Bir mol madde içindeki parçacık (atom, molekül vb.) sayısı. Makroskopik miktarları atomik ölçekteki özelliklerle ilişkilendirir.","nl":"N_A = 6,022×10²³ mol⁻¹. Het aantal deeltjes (atomen, moleculen, enz.) in één mol stof. Verbindt macroscopische grootheden met eigenschappen op atomaire schaal.","ru":"N_A = 6,022×10²³ моль⁻¹. Число частиц (атомов, молекул и т.д.) в одном моле вещества. Связывает макроскопические величины с атомными свойствами.","zh":"N_A = 6.022×10²³ mol⁻¹。一摩尔物质中的粒子（原子、分子等）数目。将宏观量与原子尺度的性质联系起来。","pt_BR":"N_A = 6,022×10²³ mol⁻¹. O número de partículas (átomos, moléculas, etc.) em um mol de substância. Conecta quantidades macroscópicas a propriedades na escala atômica.","pt_PT":"N_A = 6,022×10²³ mol⁻¹. O número de partículas (átomos, moléculas, etc.) num mol de substância. Liga as quantidades macroscópicas às propriedades à escala atómica."}},
  { id: 'dc-physics-0118', deck_id: 'deck-physics', sort_order: 118, front: "Boltzmann Constant", back: "k_B = 1.381×10⁻²³ J/K. Relates the average thermal kinetic energy of particles to temperature: KE_avg = (3/2)k_BT. Bridges macroscopic thermodynamics and statistical mechanics." , front_translations: {"es":"Constante de Boltzmann","it":"Costante di Boltzmann","de":"Boltzmann-Konstante","fr":"Constante de Boltzmann","tr":"Boltzmann Sabiti","nl":"Constante van Boltzmann","ru":"Постоянная Больцмана","zh":"玻尔兹曼常数","pt_BR":"Constante de Boltzmann","pt_PT":"Constante de Boltzmann"}, back_translations: {"es":"k_B = 1,381×10⁻²³ J/K. Relaciona a energía cinética térmica média de las partículas con a temperatura: KE_méd = (3/2)k_BT. Conecta a termodinamica macroscópica y a mecánica estadística.","it":"k_B = 1,381×10⁻²³ J/K. Relie l'energia cinetico thermico moyenne dei particules alla temperature : KE_moy = (3/2)k_BT. Fait il lien tra la thermodynamico macroscopico e la mecanico statistico.","de":"k_B = 1,381×10⁻²³ J/K. Setzt die mittlere thermische kinetische Energie der Teilchen mit der Temperatur in Beziehung: KE_Mittel = (3/2)k_BT. Verbindet makroskopische Thermodynamik und statistische Mechanik.","fr":"k_B = 1,381×10⁻²³ J/K. Relie l'énergie cinétique thermique moyenne des particules à la température : KE_moy = (3/2)k_BT. Fait le lien entre la thermodynamique macroscopique et la mécanique statistique.","tr":"k_B = 1,381×10⁻²³ J/K. Parçacıkların ortalama termal kinetik enerjisini sıcaklıkla ilişkilendirir: KE_ort = (3/2)k_BT. Makroskopik termodinamik ile istatistiksel mekaniği köprüler.","nl":"k_B = 1,381×10⁻²³ J/K. Relateert de gemiddelde thermische kinetische energie van deeltjes aan temperatuur: KE_gem = (3/2)k_BT. Verbindt macroscopische thermodynamica en statistische mechanica.","ru":"k_B = 1,381×10⁻²³ Дж/К. Связывает среднюю тепловую кинетическую энергию частиц с температурой: KE_ср = (3/2)k_BT. Связывает макроскопическую термодинамику и статистическую механику.","zh":"k_B = 1.381×10⁻²³ J/K。将粒子的平均热动能与温度联系起来：KE_均 = (3/2)k_BT。连接宏观热力学与统计力学。","pt_BR":"k_B = 1,381×10⁻²³ J/K. Relaciona a energia cinética térmica média das partículas com a temperatura: KE_méd = (3/2)k_BT. Conecta a termodinâmica macroscópica e a mecânica estatística.","pt_PT":"k_B = 1,381×10⁻²³ J/K. Relaciona a energia cinética térmica média das partículas com a temperatura: KE_méd = (3/2)k_BT. Conecta a termodinâmica macroscópica e a mecânica estatística."}},
  { id: 'dc-physics-0119', deck_id: 'deck-physics', sort_order: 119, front: "Root Mean Square Speed of Gas", back: "v_rms = √(3RT/M) = √(3k_BT/m). The effective average speed of gas molecules. Increases with temperature and decreases with molar mass. Used in kinetic theory." , front_translations: {"es":"Velocidad Cuadrática Média del Gas","it":"Velocita quadratico moyenne dei molecolas di gaz","de":"Quadratisches Mittel der Gasgeschwindigkeit","fr":"Vitesse quadratique moyenne des molécules de gaz","tr":"Gazın Etkin Hızı (Karekök Ortalama)","nl":"Effectieve snelheid van gasmoleculen","ru":"Среднеквадратическая скорость газа","zh":"气体均方根速率","pt_BR":"Velocidade Quadrática Média do Gás","pt_PT":"Velocidade Quadrática Média do Gás"}, back_translations: {"es":"v_rms = √(3RT/M) = √(3k_BT/m). La velocidad média efetiva de las moléculas de gas. Aumenta con a temperatura y disminuye con a masa molar. Usada en la teoría cinética.","it":"v_rms = √(3RT/M) = √(3k_BT/m). La vitesse moyenne effective dei molecole di gaz. Augmente con la temperature e diminue con la masse molaire. Utilisee in la teoria cinetico.","de":"v_rms = √(3RT/M) = √(3k_BT/m). Die effektive Durchschnittsgeschwindigkeit von Gasmolekülen. Nimmt mit der Temperatur zu und mit der Molmasse ab. Wird in der kinetischen Theorie verwendet.","fr":"v_rms = √(3RT/M) = √(3k_BT/m). La vitesse moyenne effective des molécules de gaz. Augmente avec la température et diminue avec la masse molaire. Utilisée dans la théorie cinétique.","tr":"v_rms = √(3RT/M) = √(3k_BT/m). Gaz moleküllerinin efektif ortalama hızı. Sıcaklıkla artar ve molar kütleyle azalır. Kinetik teoride kullanılır.","nl":"v_rms = √(3RT/M) = √(3k_BT/m). De effectieve gemiddelde snelheid van gasmoleculen. Neemt toe met temperatuur en af met molaire massa. Gebruikt in de kinetische theorie.","ru":"v_rms = √(3RT/M) = √(3k_BT/m). Эффективная средняя скорость молекул газа. Увеличивается с ростом температуры и уменьшается с ростом молярной массы. Используется в кинетической теории.","zh":"v_rms = √(3RT/M) = √(3k_BT/m)。气体分子的有效平均速率。随温度升高而增大，随摩尔质量增大而减小。用于气体动理论。","pt_BR":"v_rms = √(3RT/M) = √(3k_BT/m). A velocidade média efetiva das moléculas de gás. Aumenta com a temperatura e diminui com a massa molar. Usada na teoria cinética.","pt_PT":"v_rms = √(3RT/M) = √(3k_BT/m). A velocidade média efetiva das moléculas de gás. Aumenta com a temperatura e diminui com a massa molar. Usada na teoria cinética."}},
  { id: 'dc-physics-0120', deck_id: 'deck-physics', sort_order: 120, front: "Kinetic Theory of Gases", back: "Gas pressure arises from molecular collisions with container walls. P = ⅓(nm v²_rms), where n is number density. Average kinetic energy per molecule = (3/2)k_BT." , front_translations: {"es":"Teoría Cinética de los Gases","it":"Teoria cinetico dei gaz","de":"Kinetische Gastheorie","fr":"Théorie cinétique des gaz","tr":"Gazların Kinetik Teorisi","nl":"Kinetische gastheorie","ru":"Молекулярно-кинетическая теория газов","zh":"气体动理论","pt_BR":"Teoria Cinética dos Gases","pt_PT":"Teoria Cinética dos Gases"}, back_translations: {"es":"La presión del gas surge de las colisões moleculares con las paredes del recipiente. P = ⅓(nm v²_rms), donde n es a densidad numérica. Energía cinética média por molécula = (3/2)k_BT.","it":"La pression di un gaz provient dei chocs moleculaires con i parois del recipient. P = ⅓(nm v²_rms), où n e la densite numerico. Energie cinetico moyenne per molecola = (3/2)k_BT.","de":"Gasdruck entsteht durch molekulare Stöße mit den Behälterwänden. P = ⅓(nm v²_rms), wobei n die Teilchenzahldichte ist. Mittlere kinetische Energie pro Molekül = (3/2)k_BT.","fr":"La pression d'un gaz provient des chocs moléculaires avec les parois du récipient. P = ⅓(nm v²_rms), où n est la densité numérique. Énergie cinétique moyenne par molécule = (3/2)k_BT.","tr":"Gaz basıncı, kap duvarlarıyla moleküler çarpışmalardan kaynaklanır. P = ⅓(nm v²_rms), burada n sayı yoğunluğudur. Molekül başına ortalama kinetik enerji = (3/2)k_BT.","nl":"Gasdruk ontstaat door moleculaire botsingen met de containerwanden. P = ⅓(nm v²_rms), waarbij n de getalsdichtheid is. Gemiddelde kinetische energie per molecuul = (3/2)k_BT.","ru":"Давление газа возникает в результате молекулярных столкновений со стенками сосуда. P = ⅓(nm v²_rms), где n — числовая плотность. Средняя кинетическая энергия молекулы = (3/2)k_BT.","zh":"气体压强来源于分子与容器壁的碰撞。P = ⅓(nm v²_rms)，其中n为数密度。每个分子的平均动能 = (3/2)k_BT。","pt_BR":"A pressão do gás surge das colisões moleculares com as paredes do recipiente. P = ⅓(nm v²_rms), onde n é a densidade numérica. Energia cinética média por molécula = (3/2)k_BT.","pt_PT":"A pressão do gás surge das colisões moleculares com as paredes do recipiente. P = ⅓(nm v²_rms), onde n é a densidade numérica. Energia cinética média por molécula = (3/2)k_BT."}},
  { id: 'dc-physics-0121', deck_id: 'deck-physics', sort_order: 121, front: "Diffraction Grating", back: "d·sinθ = mλ. A diffraction grating with many slits produces sharp interference maxima. The angle of each maximum depends on wavelength, allowing precise measurement of spectra." , front_translations: {"es":"Red de Difración","it":"Reseau di diffractione","de":"Beugungsgitter","fr":"Réseau de diffraction","tr":"Kırınım Izgara","nl":"Diffractierooster","ru":"Дифракционная решётка","zh":"衍射光栅","pt_BR":"Rede de Difração","pt_PT":"Rede de Difração"}, back_translations: {"es":"d·sinθ = mλ. Una red de difración con muchas fendas produce máximos de interferencia nítidos. El ángulo de cada máximo depende del comprimento de onda, permitiendo a medición precisa de espectros.","it":"d·sinθ = mλ. Un reseau di diffraczione à nombreuses fentes prodotto dei maxima d'interferenza nets. L'angle di ogni maximum depend della longuore d'onde, permettant una mesure precise dei spectres.","de":"d·sinθ = mλ. Ein Beugungsgitter mit vielen Spalten erzeugt scharfe Interferenzmaxima. Der Winkel jedes Maximums hängt von der Wellenlänge ab, was eine präzise Messung von Spektren ermöglicht.","fr":"d·sinθ = mλ. Un réseau de diffraction à nombreuses fentes produit des maxima d'interférence nets. L'angle de chaque maximum dépend de la longueur d'onde, permettant une mesure précise des spectres.","tr":"d·sinθ = mλ. Çok sayıda yarıklı bir kırınım ızgarası keskin girişim maksimumları üretir. Her maksimumun açısı dalga boyuna bağlıdır ve spektrumların hassas ölçümüne olanak tanır.","nl":"d·sinθ = mλ. Een diffractierooster met veel spleten produceert scherpe interferentiemaxima. De hoek van elk maximum is afhankelijk van de golflengte, waardoor nauwkeurige meting van spectra mogelijk is.","ru":"d·sinθ = mλ. Дифракционная решётка с многими щелями даёт чёткие интерференционные максимумы. Угол каждого максимума зависит от длины волны, что позволяет точно измерять спектры.","zh":"d·sinθ = mλ。具有多条缝的衍射光栅产生锐利的干涉极大值。每个极大值的角度取决于波长，从而可以精确测量光谱。","pt_BR":"d·sinθ = mλ. Uma rede de difração com muitas fendas produz máximos de interferência nítidos. O ângulo de cada máximo depende do comprimento de onda, permitindo a medição precisa de espectros.","pt_PT":"d·sinθ = mλ. Uma rede de difração com muitas fendas produz máximos de interferência nítidos. O ângulo de cada máximo depende do comprimento de onda, permitindo a medição precisa de espectros."}},
  { id: 'dc-physics-0122', deck_id: 'deck-physics', sort_order: 122, front: "Compton Scattering", back: "X-ray photons scattered by electrons shift to longer wavelengths: Δλ = (h/m_ec)(1 - cosθ). Demonstrated that photons have momentum p = h/λ, confirming their particle nature." , front_translations: {"es":"Espalhamento Compton","it":"Diffusione Compton","de":"Compton-Streuung","fr":"Diffusion Compton","tr":"Compton Saçılması","nl":"Comptonverstrooiing","ru":"Эффект Комптона","zh":"康普顿散射","pt_BR":"Espalhamento Compton","pt_PT":"Dispersão de Compton"}, back_translations: {"es":"Fótons de raios-X espalhados por electrones mudam para comprimentos de onda mayores: Δλ = (h/m_ec)(1 - cosθ). Demonstrou que fótons tienen momento p = h/λ, confirmando su natureza corpuscular.","it":"I photons X diffuses per dei electrons se decalent verso di più grandes longuori d'onde : Δλ = (h/m_ec)(1 - cosθ). A montre che i photons hanno una quantite di mouvement p = h/λ, confirmant il loro nature corpusculaire.","de":"Röntgenphotonen, die von Elektronen gestreut werden, verschieben sich zu längeren Wellenlängen: Δλ = (h/m_ec)(1 - cosθ). Bewies, dass Photonen den Impuls p = h/λ besitzen und bestätigte damit ihre Teilchennatur.","fr":"Les photons X diffusés par des électrons se décalent vers de plus grandes longueurs d'onde : Δλ = (h/m_ec)(1 - cosθ). A montré que les photons ont une quantité de mouvement p = h/λ, confirmant leur nature corpusculaire.","tr":"Elektronlar tarafından saçılan X-ışını fotonları daha uzun dalga boylarına kayar: Δλ = (h/m_ec)(1 - cosθ). Fotonların p = h/λ momentuma sahip olduğunu göstererek parçacık doğalarını doğruladı.","nl":"Röntgenfotonen die worden verstrooid door elektronen verschuiven naar langere golflengten: Δλ = (h/m_ec)(1 - cosθ). Toonde aan dat fotonen impuls p = h/λ hebben, wat hun deeltjesnatuur bevestigde.","ru":"Рентгеновские фотоны, рассеянные на электронах, смещаются в сторону бо́льших длин волн: Δλ = (h/m_ec)(1 - cosθ). Показал, что фотоны имеют импульс p = h/λ, подтвердив их корпускулярную природу.","zh":"X射线光子被电子散射后波长变长：Δλ = (h/m_ec)(1 - cosθ)。证明了光子具有动量p = h/λ，确认了其粒子性。","pt_BR":"Fótons de raios-X espalhados por elétrons mudam para comprimentos de onda maiores: Δλ = (h/m_ec)(1 - cosθ). Demonstrou que fótons têm momento p = h/λ, confirmando sua natureza corpuscular.","pt_PT":"Fotões de raios-X dispersos por eletrões deslocam-se para comprimentos de onda maiores: Δλ = (h/m_ec)(1 - cosθ). Demonstrou que os fotões têm momento p = h/λ, confirmando a sua natureza corpuscular."}},
  { id: 'dc-physics-0123', deck_id: 'deck-physics', sort_order: 123, front: "Pair Production", back: "A high-energy photon converts into an electron-positron pair near a nucleus: γ → e⁻ + e⁺. Requires photon energy ≥ 1.022 MeV (twice the electron rest mass energy)." , front_translations: {"es":"Criación de Pares","it":"Creatione di paires","de":"Paarerzeugung","fr":"Création de paires","tr":"Çift Üretimi","nl":"Paarcreatie","ru":"Рождение пар","zh":"正负电子对产生","pt_BR":"Criação de Pares","pt_PT":"Criação de Pares"}, back_translations: {"es":"Un fóton de alta energía se convierte en un par electrón-pósitron próximo a un núcleo: γ → y⁻ + y⁺. Requiere energía del fóton ≥ 1,022 MeV (el dobro de la energía de masa en reposo del electrón).","it":"Un photon molto energetico se convertit en una paire electron-positron pres di un noyau : γ → e⁻ + e⁺. Necessite una energia di photon ≥ 1,022 MeV (deux fois l'energia di masse al repos dell'electron).","de":"Ein hochenergetisches Photon wandelt sich in der Nähe eines Kerns in ein Elektron-Positron-Paar um: γ → e⁻ + e⁺. Erfordert eine Photonenenergie von ≥ 1,022 MeV (das Doppelte der Ruhemassenergie eines Elektrons).","fr":"Un photon très énergétique se convertit en une paire électron-positron près d'un noyau : γ → e⁻ + e⁺. Nécessite une énergie de photon ≥ 1,022 MeV (deux fois l'énergie de masse au repos de l'électron).","tr":"Yüksek enerjili bir foton, bir çekirdeğin yakınında elektron-pozitron çiftine dönüşür: γ → e⁻ + e⁺. Foton enerjisinin ≥ 1,022 MeV (elektronun durgun kütle enerjisinin iki katı) olmasını gerektirir.","nl":"Een hoog-energetisch foton converteert in de buurt van een kern naar een elektron-positronpaar: γ → e⁻ + e⁺. Vereist fotonenenergie ≥ 1,022 MeV (tweemaal de rustmassaenergie van het elektron).","ru":"Высокоэнергетический фотон вблизи ядра превращается в электрон-позитронную пару: γ → e⁻ + e⁺. Требует энергии фотона ≥ 1,022 МэВ (вдвое больше энергии покоя электрона).","zh":"高能光子在原子核附近转变为电子-正电子对：γ → e⁻ + e⁺。要求光子能量 ≥ 1.022 MeV（电子静止质量能量的两倍）。","pt_BR":"Um fóton de alta energia se converte em um par elétron-pósitron próximo a um núcleo: γ → e⁻ + e⁺. Requer energia do fóton ≥ 1,022 MeV (o dobro da energia de massa em repouso do elétron).","pt_PT":"Um fotão de alta energia converte-se num par eletrão-positrão perto de um núcleo: γ → e⁻ + e⁺. Requer energia do fotão ≥ 1,022 MeV (o dobro da energia de massa em repouso do eletrão)."}},
  { id: 'dc-physics-0124', deck_id: 'deck-physics', sort_order: 124, front: "Annihilation", back: "An electron and positron annihilate to produce two gamma photons: e⁻ + e⁺ → 2γ. Each photon has energy = 0.511 MeV (electron rest mass energy). Basis of PET scans." , front_translations: {"es":"Aniquilación","it":"Annihilatione","de":"Annihilation","fr":"Annihilation","tr":"Yok Oluş (Annihilation)","nl":"Annihilatie","ru":"Аннигиляция","zh":"湮灭","pt_BR":"Aniquilação","pt_PT":"Aniquilação"}, back_translations: {"es":"Un electrón y un pósitron se aniquilam para produzir de los fótons gama: y⁻ + y⁺ → 2γ. Cada fóton tiene energía = 0,511 MeV (energía de masa en reposo del electrón). Base de los exámenes de PET.","it":"Un electron e un positron s'annihilent per produire deux photons gamma : e⁻ + e⁺ → 2γ. Chaque photon ha una energia di 0,511 MeV (energia di masse al repos dell'electron). Base dei scanners TEP.","de":"Ein Elektron und ein Positron vernichten sich gegenseitig und erzeugen zwei Gammaphotonen: e⁻ + e⁺ → 2γ. Jedes Photon hat eine Energie von 0,511 MeV (Ruhemassenergie des Elektrons). Grundlage der PET-Scans.","fr":"Un électron et un positron s'annihilent pour produire deux photons gamma : e⁻ + e⁺ → 2γ. Chaque photon a une énergie de 0,511 MeV (énergie de masse au repos de l'électron). Base des scanners TEP.","tr":"Bir elektron ve pozitron birbirini yok ederek iki gama foton üretir: e⁻ + e⁺ → 2γ. Her fotonun enerjisi = 0,511 MeV (elektronun durgun kütle enerjisi). PET taramalarının temeli.","nl":"Een elektron en positron annihileren tot twee gammafoton: e⁻ + e⁺ → 2γ. Elk foton heeft energie = 0,511 MeV (rustmassaenergie van het elektron). Basis van PET-scans.","ru":"Электрон и позитрон аннигилируют с образованием двух гамма-фотонов: e⁻ + e⁺ → 2γ. Каждый фотон имеет энергию 0,511 МэВ (энергия покоя электрона). Основа ПЭТ-сканирования.","zh":"电子和正电子湮灭产生两个γ光子：e⁻ + e⁺ → 2γ。每个光子能量 = 0.511 MeV（电子静止质量能量）。PET扫描的基础。","pt_BR":"Um elétron e um pósitron se aniquilam para produzir dois fótons gama: e⁻ + e⁺ → 2γ. Cada fóton tem energia = 0,511 MeV (energia de massa em repouso do elétron). Base dos exames de PET.","pt_PT":"Um eletrão e um positrão aniquilam-se para produzir dois fotões gama: e⁻ + e⁺ → 2γ. Cada fotão tem energia = 0,511 MeV (energia de massa em repouso do eletrão). Base dos exames de PET."}},
  { id: 'dc-physics-0125', deck_id: 'deck-physics', sort_order: 125, front: "Standard Model of Particle Physics", back: "Describes the elementary particles (quarks, leptons) and their interactions via force-carrying bosons (gluons, photons, W/Z). Does not include gravity. Higgs boson confirmed in 2012." , front_translations: {"es":"Modelo Padrão de la Física de Partículas","it":"Modello standard di la fisico dei particules","de":"Standardmodell der Teilchenphysik","fr":"Modèle standard de la physique des particules","tr":"Parçacık Fiziğinin Standart Modeli","nl":"Standaardmodel van de deeltjesfysica","ru":"Стандартная модель физики частиц","zh":"粒子物理标准模型","pt_BR":"Modelo Padrão da Física de Partículas","pt_PT":"Modelo Padrão da Física de Partículas"}, back_translations: {"es":"Descreve las partículas elementares (quarks, léptons) y sus interacciones via bósons mediadores (glúons, fótons, W/Z). No incluye a gravidad. Bóson de Higgs confirmado en 2012.","it":"Decrit i particules elementaires (quarks, leptons) e i loro interaczioni via dei bosons vectori (gluons, photons, W/Z). N'include la gravite. Boson di Higgs confirme en 2012.","de":"Beschreibt die Elementarteilchen (Quarks, Leptonen) und ihre Wechselwirkungen über krafttragende Bosonen (Gluonen, Photonen, W/Z). Enthält keine Gravitation. Higgs-Boson 2012 bestätigt.","fr":"Décrit les particules élémentaires (quarks, leptons) et leurs interactions via des bosons vecteurs (gluons, photons, W/Z). N'inclut pas la gravité. Boson de Higgs confirmé en 2012.","tr":"Temel parçacıkları (kuarklar, leptonlar) ve kuvvet taşıyıcı bozonlar (gluonlar, fotonlar, W/Z) aracılığıyla etkileşimlerini tanımlar. Yerçekimini içermez. Higgs bozonu 2012'de doğrulandı.","nl":"Beschrijft de elementaire deeltjes (quarks, leptonen) en hun interacties via krachtdragende bosonen (gluonen, fotonen, W/Z). Bevat geen zwaartekracht. Higgs-boson bevestigd in 2012.","ru":"Описывает элементарные частицы (кварки, лептоны) и их взаимодействия через переносчики сил (глюоны, фотоны, W/Z). Не включает гравитацию. Бозон Хиггса подтверждён в 2012 году.","zh":"描述了基本粒子（夸克、轻子）及其通过传力玻色子（胶子、光子、W/Z玻色子）的相互作用。不包含引力。希格斯玻色子于2012年得到证实。","pt_BR":"Descreve as partículas elementares (quarks, léptons) e suas interações via bósons mediadores (glúons, fótons, W/Z). Não inclui a gravidade. Bóson de Higgs confirmado em 2012.","pt_PT":"Descreve as partículas elementares (quarks, leptões) e as suas interações via bosões mediadores (gluões, fotões, W/Z). Não inclui a gravidade. Bosão de Higgs confirmado em 2012."}},
  { id: 'dc-physics-0126', deck_id: 'deck-physics', sort_order: 126, front: "Quarks", back: "Elementary particles that make up protons and neutrons. Six flavors: up, down, charm, strange, top, bottom. Proton = uud; neutron = udd. Held together by gluons (strong force)." , front_translations: {"es":"Quarks","it":"Quarks","de":"Quarks","fr":"Quarks","tr":"Kuarklar","nl":"Quarks","ru":"Кварки","zh":"夸克","pt_BR":"Quarks","pt_PT":"Quarks"}, back_translations: {"es":"Partículas elementares que compõem protones y neutrones. Seis sabores: up, down, charm, strange, top, bottom. Carregam carga eléctrica fracionária y interaje por la fuerza fuerte.","it":"Particules elementaires constituant i protons e i neutrons. Six savori : up, down, charm, strange, top, bottom. Ils portent una charge electrico fractionnaire e interagissent via la force forte.","de":"Elementarteilchen, aus denen Protonen und Neutronen bestehen. Sechs Flavours: Up, Down, Charm, Strange, Top, Bottom. Sie tragen gebrochene elektrische Ladung und wechselwirken über die starke Kraft.","fr":"Particules élémentaires constituant les protons et les neutrons. Six saveurs : up, down, charm, strange, top, bottom. Ils portent une charge électrique fractionnaire et interagissent via la force forte.","tr":"Protonları ve nötronları oluşturan temel parçacıklar. Altı çeşnisi vardır: yukarı, aşağı, tılsım, garip, tepe, dip. Kesirli elektrik yükü taşırlar ve güçlü kuvvet aracılığıyla etkileşirler.","nl":"Elementaire deeltjes waaruit protonen en neutronen bestaan. Zes smaken: up, down, charm, strange, top, bottom. Ze dragen een fractionele elektrische lading en interageren via de sterke kracht.","ru":"Элементарные частицы, из которых состоят протоны и нейтроны. Шесть ароматов: верхний, нижний, очарованный, странный, истинный, прелестный. Они несут дробный электрический заряд и взаимодействуют посредством сильного взаимодействия.","zh":"构成质子和中子的基本粒子。六种味：上、下、粲、奇、顶、底。它们携带分数电荷，通过强力相互作用。","pt_BR":"Partículas elementares que compõem prótons e nêutrons. Seis sabores: up, down, charm, strange, top, bottom. Carregam carga elétrica fracionária e interagem pela força forte.","pt_PT":"Partículas elementares que compõem protões e neutrões. Seis sabores: up, down, charm, strange, top, bottom. Transportam carga elétrica fracionária e interagem pela força forte."}},
  { id: 'dc-physics-0127', deck_id: 'deck-physics', sort_order: 127, front: "Leptons", back: "Elementary particles not subject to the strong force. Six types: electron, muon, tau, and their corresponding neutrinos. Electrons are stable; muons and taus decay." , front_translations: {"es":"Léptons","it":"Leptons","de":"Leptonen","fr":"Leptons","tr":"Leptonlar","nl":"Leptonen","ru":"Лептоны","zh":"轻子","pt_BR":"Léptons","pt_PT":"Leptões"}, back_translations: {"es":"Partículas elementares no sujeitas a la fuerza fuerte. Seis tipos: electrón, múon, tau y sus neutrinos associados. Los electrones son el lépton más conocido.","it":"Particules elementaires non soumises alla force forte. Six types : electron, muon, tau e i loro neutrinos associes. L'electron e il lepton il più familier.","de":"Elementarteilchen, die nicht der starken Kraft unterliegen. Sechs Typen: Elektron, Myon, Tau und ihre zugehörigen Neutrinos. Elektronen sind das bekannteste Lepton.","fr":"Particules élémentaires non soumises à la force forte. Six types : électron, muon, tau et leurs neutrinos associés. L'électron est le lepton le plus familier.","tr":"Güçlü kuvvete tabi olmayan temel parçacıklar. Altı türü vardır: elektron, müon, tau ve bunların ilişkili nötrinoları. Elektronlar en bilinen leptondur.","nl":"Elementaire deeltjes die niet onderhevig zijn aan de sterke kracht. Zes typen: elektron, muon, tau en hun bijbehorende neutrino's. Elektronen zijn het meest bekende lepton.","ru":"Элементарные частицы, не участвующие в сильном взаимодействии. Шесть типов: электрон, мюон, тау и связанные с ними нейтрино. Электроны — наиболее известный лептон.","zh":"不参与强相互作用的基本粒子。六种类型：电子、μ子、τ子及其对应的中微子。电子是最常见的轻子。","pt_BR":"Partículas elementares não sujeitas à força forte. Seis tipos: elétron, múon, tau e seus neutrinos associados. Os elétrons são o lépton mais conhecido.","pt_PT":"Partículas elementares não sujeitas à força forte. Seis tipos: eletrão, muão, tau e os seus neutrinos associados. Os eletrões são o leptão mais conhecido."}},
  { id: 'dc-physics-0128', deck_id: 'deck-physics', sort_order: 128, front: "Displacement vs. Distance", back: "Distance is the total path length traveled (scalar); displacement is the straight-line change in position from start to finish (vector). They are equal only for straight-line motion in one direction." , front_translations: {"es":"Deslocamento vs. Distancia","it":"Deplacemento vs. Distanza","de":"Verschiebung vs. Strecke","fr":"Déplacement vs. Distance","tr":"Yer Değiştirme ve Mesafe","nl":"Verplaatsing vs. Afstand","ru":"Перемещение и путь","zh":"位移与路程","pt_BR":"Deslocamento vs. Distância","pt_PT":"Deslocamento vs. Distância"}, back_translations: {"es":"Distancia es el comprimento total del caminho percorrido (escalar); deslocamento es el vetor en línea reta del início al fin. Eles só son iguais en el movimiento retilíneo.","it":"La distanza e la longuore totale del trajet parcouru (scalaire) ; il deplacement e il vectore en ligne droite del point di depart al point d'arrivee. Ils non sono egaux che per un mouvement rectiligne.","de":"Die Strecke ist die gesamte zurückgelegte Weglänge (Skalar); die Verschiebung ist der geradlinige Vektor vom Start- zum Endpunkt. Sie sind nur bei geradliniger Bewegung gleich.","fr":"La distance est la longueur totale du trajet parcouru (scalaire) ; le déplacement est le vecteur en ligne droite du point de départ au point d'arrivée. Ils ne sont égaux que pour un mouvement rectiligne.","tr":"Mesafe, kat edilen toplam yol uzunluğudur (skaler); yer değiştirme, başlangıçtan bitişe doğru olan düz çizgi vektörüdür. Yalnızca doğrusal hareket için birbirlerine eşittirler.","nl":"Afstand is de totale afgelegde weglengte (scalair); verplaatsing is de rechte-lijn vector van begin tot eind. Ze zijn alleen gelijk bij rechtlijnige beweging.","ru":"Путь — это общая длина пройденной траектории (скаляр); перемещение — это вектор по прямой от начальной до конечной точки. Они равны только при прямолинейном движении.","zh":"路程是经过的总路径长度（标量）；位移是从起点到终点的直线向量。只有在直线运动时两者才相等。","pt_BR":"Distância é o comprimento total do caminho percorrido (escalar); deslocamento é o vetor em linha reta do início ao fim. Eles só são iguais no movimento retilíneo.","pt_PT":"Distância é o comprimento total do caminho percorrido (escalar); deslocamento é o vetor em linha reta do início ao fim. São iguais apenas no movimento retilíneo."}},
  { id: 'dc-physics-0129', deck_id: 'deck-physics', sort_order: 129, front: "Speed vs. Velocity", back: "Speed is the magnitude of velocity (scalar); velocity is speed in a specified direction (vector). A car going around a circular track at constant speed has changing velocity." , front_translations: {"es":"Rapidez vs. Velocidad","it":"Velocita scalaire vs. Velocita vectorielle","de":"Geschwindigkeit vs. Geschwindigkeitsvektor","fr":"Vitesse scalaire vs. Vitesse vectorielle","tr":"Sürat ve Hız","nl":"Snelheid vs. Snelheidsvector","ru":"Скорость (скалярная) и скорость (векторная)","zh":"速率与速度","pt_BR":"Rapidez vs. Velocidade","pt_PT":"Rapidez vs. Velocidade"}, back_translations: {"es":"Rapidez es a magnitude de la velocidad (escalar); velocidad es a rapidez en una dirección específica (vetor). La rapidez média puede diferir de la magnitude de la velocidad média.","it":"La vitesse scalaire e la valore absolue della vitesse vectorielle (scalaire) ; la vitesse vectorielle e la vitesse in una direczione donnee (vectore). La vitesse scalaire moyenne può differer della norme della vitesse vectorielle moyenne.","de":"Die Geschwindigkeit ist der Betrag des Geschwindigkeitsvektors (Skalar); der Geschwindigkeitsvektor ist die Geschwindigkeit in einer bestimmten Richtung (Vektor). Die Durchschnittsgeschwindigkeit kann vom Betrag der Durchschnittsgeschwindigkeit abweichen.","fr":"La vitesse scalaire est la valeur absolue de la vitesse vectorielle (scalaire) ; la vitesse vectorielle est la vitesse dans une direction donnée (vecteur). La vitesse scalaire moyenne peut différer de la norme de la vitesse vectorielle moyenne.","tr":"Sürat, hızın büyüklüğüdür (skaler); hız, belirli bir yöndeki sürattir (vektör). Ortalama sürat, ortalama hızın büyüklüğünden farklı olabilir.","nl":"Snelheid is de grootte van de snelheidsvector (scalair); de snelheidsvector is snelheid in een bepaalde richting (vector). De gemiddelde snelheid kan verschillen van de grootte van de gemiddelde snelheidsvector.","ru":"Скорость (скалярная) — это модуль вектора скорости (скаляр); скорость (векторная) — это скорость в определённом направлении (вектор). Средняя скалярная скорость может отличаться от модуля средней векторной скорости.","zh":"速率是速度的大小（标量）；速度是具有方向的速率（向量）。平均速率可能与平均速度的大小不同。","pt_BR":"Rapidez é a magnitude da velocidade (escalar); velocidade é a rapidez em uma direção específica (vetor). A rapidez média pode diferir da magnitude da velocidade média.","pt_PT":"Rapidez é a magnitude da velocidade (escalar); velocidade é a rapidez numa direção específica (vetor). A rapidez média pode diferir da magnitude da velocidade média."}},
  { id: 'dc-physics-0130', deck_id: 'deck-physics', sort_order: 130, front: "Free Fall", back: "Motion under gravity alone, with no air resistance. All objects fall with the same acceleration g ≈ 9.81 m/s² regardless of mass. Galileo disproved the heavier-falls-faster idea." , front_translations: {"es":"Caída Livre","it":"Caduta libera","de":"Freier Fall","fr":"Chute libre","tr":"Serbest Düşme","nl":"Vrije val","ru":"Свободное падение","zh":"自由落体","pt_BR":"Queda Livre","pt_PT":"Queda Livre"}, back_translations: {"es":"Movimiento solo sob a acción de la gravidad, sin resistencia del aire. Todos los objetos caem con a misma aceleración g ≈ 9,8 m/s², independentemente de la masa (descubrimiento de Galileu).","it":"Moto sotto l'effetto della gravite seule, senza resistanza dell'air. Tous i objets tombent con la stesso accelerazione g ≈ 9,8 m/s², quelle che soit il loro masse (decouverte di Galilee).","de":"Bewegung allein unter dem Einfluss der Schwerkraft, ohne Luftwiderstand. Alle Objekte fallen mit der gleichen Beschleunigung g ≈ 9,8 m/s², unabhängig von der Masse (Galileis Erkenntnis).","fr":"Mouvement sous l'effet de la gravité seule, sans résistance de l'air. Tous les objets tombent avec la même accélération g ≈ 9,8 m/s², quelle que soit leur masse (découverte de Galilée).","tr":"Hava direnci olmaksızın yalnızca yerçekimi etkisi altındaki hareket. Tüm cisimler kütlelerine bakılmaksızın aynı ivme g ≈ 9,8 m/s² ile düşer (Galileo'nun keşfi).","nl":"Beweging uitsluitend onder invloed van de zwaartekracht, zonder luchtweerstand. Alle objecten vallen met dezelfde versnelling g ≈ 9,8 m/s², ongeacht de massa (Galilei's inzicht).","ru":"Движение только под действием силы тяжести, без сопротивления воздуха. Все тела падают с одинаковым ускорением g ≈ 9,8 м/с² независимо от массы (открытие Галилея).","zh":"仅在重力作用下的运动，没有空气阻力。所有物体以相同的加速度 g ≈ 9.8 m/s² 下落，与质量无关（伽利略的发现）。","pt_BR":"Movimento apenas sob a ação da gravidade, sem resistência do ar. Todos os objetos caem com a mesma aceleração g ≈ 9,8 m/s², independentemente da massa (descoberta de Galileu).","pt_PT":"Movimento apenas sob a ação da gravidade, sem resistência do ar. Todos os objetos caem com a mesma aceleração g ≈ 9,8 m/s², independentemente da massa (descoberta de Galileu)."}},
  { id: 'dc-physics-0131', deck_id: 'deck-physics', sort_order: 131, front: "Terminal Velocity", back: "The constant speed reached when air resistance equals gravitational force (net force = 0). Depends on shape, cross-sectional area, and mass. Skydiver reaches ~55 m/s in spread-eagle position." , front_translations: {"es":"Velocidad Terminal","it":"Velocita terminale","de":"Endgeschwindigkeit","fr":"Vitesse terminale","tr":"Sınır Hızı","nl":"Eindsnelheid","ru":"Предельная скорость","zh":"终端速度","pt_BR":"Velocidade Terminal","pt_PT":"Velocidade Terminal"}, back_translations: {"es":"La velocidad constante alcançada cuando a resistencia del aire iguala a fuerza gravitacional (fuerza resultante = 0). Depende de la masa, de la área de la seción transversal y del coeficiente de arrasto.","it":"La vitesse costante atteinte quando la resistanza dell'air egale la force gravitationnelle (force nette = 0). Depend della masse, della seczione transversale e del coefficient di trainee.","de":"Die konstante Geschwindigkeit, die erreicht wird, wenn der Luftwiderstand gleich der Gravitationskraft ist (Nettokraft = 0). Hängt von Masse, Querschnittsfläche und Widerstandsbeiwert ab.","fr":"La vitesse constante atteinte lorsque la résistance de l'air égale la force gravitationnelle (force nette = 0). Dépend de la masse, de la section transversale et du coefficient de traînée.","tr":"Hava direncinin yerçekimi kuvvetine eşit olduğu durumda ulaşılan sabit hız (net kuvvet = 0). Kütle, kesit alanı ve sürüklenme katsayısına bağlıdır.","nl":"De constante snelheid die wordt bereikt wanneer de luchtweerstand gelijk is aan de zwaartekracht (nettokracht = 0). Hangt af van massa, dwarsdoorsnede en weerstandscoëfficiënt.","ru":"Постоянная скорость, достигаемая, когда сила сопротивления воздуха равна силе тяжести (результирующая сила = 0). Зависит от массы, площади поперечного сечения и коэффициента сопротивления.","zh":"当空气阻力等于重力时（合力为零）达到的恒定速度。取决于质量、横截面积和阻力系数。","pt_BR":"A velocidade constante alcançada quando a resistência do ar iguala a força gravitacional (força resultante = 0). Depende da massa, da área da seção transversal e do coeficiente de arrasto.","pt_PT":"A velocidade constante atingida quando a resistência do ar iguala a força gravitacional (força resultante = 0). Depende da massa, da área da secção transversal e do coeficiente de arrasto."}},
  { id: 'dc-physics-0132', deck_id: 'deck-physics', sort_order: 132, front: "Elastic Potential Energy", back: "PE_spring = ½kx². Energy stored in a compressed or stretched spring equals half the spring constant times the square of the displacement from equilibrium." , front_translations: {"es":"Energía Potencial Elástica","it":"Energie potenziale elastico","de":"Elastische potentielle Energie","fr":"Énergie potentielle élastique","tr":"Elastik Potansiyel Enerji","nl":"Elastische potentiële energie","ru":"Упругая потенциальная энергия","zh":"弹性势能","pt_BR":"Energia Potencial Elástica","pt_PT":"Energia Potencial Elástica"}, back_translations: {"es":"EP_mola = ½kx². La energía almacenada en una mola comprimida o esticada es igual a la metade de la constante elástica veces el cuadrado del deslocamento en relación con el equilíbrio.","it":"EP_ressort = ½kx². L'energia stockee in un ressort comprime o etire e egale alla moitie della costante di raidore multipliee per il carre del deplacement per rapport all'equilibrio.","de":"PE_Feder = ½kx². Die in einer zusammengedrückten oder gedehnten Feder gespeicherte Energie ist gleich der Hälfte der Federkonstante mal dem Quadrat der Auslenkung aus der Gleichgewichtslage.","fr":"EP_ressort = ½kx². L'énergie stockée dans un ressort comprimé ou étiré est égale à la moitié de la constante de raideur multipliée par le carré du déplacement par rapport à l'équilibre.","tr":"PE_yay = ½kx². Sıkıştırılmış veya gerilmiş bir yayda depolanan enerji, yay sabitinin yarısı çarpı denge konumundan uzaklaşmanın karesidir.","nl":"PE_veer = ½kx². De energie opgeslagen in een samengedrukte of uitgerekte veer is gelijk aan de helft van de veerconstante maal het kwadraat van de verplaatsing vanuit de evenwichtspositie.","ru":"PE_пружины = ½kx². Энергия, запасённая в сжатой или растянутой пружине, равна половине жёсткости пружины, умноженной на квадрат смещения от положения равновесия.","zh":"PE_弹簧 = ½kx²。压缩或拉伸弹簧中储存的能量等于弹簧常数的一半乘以偏离平衡位置的位移的平方。","pt_BR":"EP_mola = ½kx². A energia armazenada em uma mola comprimida ou esticada é igual à metade da constante elástica vezes o quadrado do deslocamento em relação ao equilíbrio.","pt_PT":"EP_mola = ½kx². A energia armazenada numa mola comprimida ou esticada é igual a metade da constante elástica vezes o quadrado do deslocamento em relação ao equilíbrio."}},
  { id: 'dc-physics-0133', deck_id: 'deck-physics', sort_order: 133, front: "Mechanical Advantage", back: "MA = output force / input force. Simple machines (levers, pulleys, inclined planes) amplify force at the expense of distance moved. Energy is always conserved overall." , front_translations: {"es":"Vantaje Mecánica","it":"Avantage meccanico","de":"Mechanischer Vorteil","fr":"Avantage mécanique","tr":"Mekanik Avantaj","nl":"Mechanisch voordeel","ru":"Механическое преимущество","zh":"机械利益","pt_BR":"Vantagem Mecânica","pt_PT":"Vantagem Mecânica"}, back_translations: {"es":"VM = fuerza de saída / fuerza de entrada. Máquinas simples (alavancas, polias, planos inclinados) multiplicam a fuerza a la custa de la distancia, conservando el trabajo.","it":"AM = force di sortie / force d'entree. I machines simples (leviers, poulies, plans inclines) multiplient la force al detriment della distanza, en conservant il travail.","de":"MA = Ausgangskraft / Eingangskraft. Einfache Maschinen (Hebel, Flaschenzüge, schiefe Ebenen) vervielfachen die Kraft auf Kosten der Strecke und erhalten dabei die Arbeit.","fr":"AM = force de sortie / force d'entrée. Les machines simples (leviers, poulies, plans inclinés) multiplient la force au détriment de la distance, en conservant le travail.","tr":"MA = çıkış kuvveti / giriş kuvveti. Basit makineler (kaldıraçlar, makaralar, eğik düzlemler) mesafe pahasına kuvveti çoğaltır ve işi korumuş olur.","nl":"MV = uitgangskracht / ingangskracht. Eenvoudige machines (hefbomen, katrollen, hellende vlakken) vermenigvuldigen de kracht ten koste van de afstand, waarbij de arbeid behouden blijft.","ru":"MA = выходная сила / входная сила. Простые механизмы (рычаги, блоки, наклонные плоскости) увеличивают силу за счёт расстояния, сохраняя работу.","zh":"MA = 输出力 / 输入力。简单机械（杠杆、滑轮、斜面）以牺牲距离为代价来放大力，从而保持功不变。","pt_BR":"VM = força de saída / força de entrada. Máquinas simples (alavancas, polias, planos inclinados) multiplicam a força à custa da distância, conservando o trabalho.","pt_PT":"VM = força de saída / força de entrada. Máquinas simples (alavancas, polias, planos inclinados) multiplicam a força à custa da distância, conservando o trabalho."}},
  { id: 'dc-physics-0134', deck_id: 'deck-physics', sort_order: 134, front: "Inclined Plane", back: "The component of gravity along the incline is mg·sinθ; the normal force is mg·cosθ. Net acceleration = g(sinθ - μcosθ). A longer ramp reduces the required force." , front_translations: {"es":"Plano Inclinado","it":"Plan incline","de":"Schiefe Ebene","fr":"Plan incliné","tr":"Eğik Düzlem","nl":"Hellend vlak","ru":"Наклонная плоскость","zh":"斜面","pt_BR":"Plano Inclinado","pt_PT":"Plano Inclinado"}, back_translations: {"es":"La componente de la gravidad a lo ancho de la inclinación es mg·senθ; a fuerza normal es mg·cosθ. El atrito en planos inclinados depende de la fuerza normal y del coeficiente de atrito.","it":"La composante della gravite il long dell'inclinaison e mg·sinθ ; la force normale e mg·cosθ. Il frottement su un plan incline depend della force normale e del coefficient di frottement.","de":"Die Komponente der Schwerkraft entlang der Neigung ist mg·sinθ; die Normalkraft ist mg·cosθ. Die Reibung auf der schiefen Ebene hängt von der Normalkraft und dem Reibungskoeffizienten ab.","fr":"La composante de la gravité le long de l'inclinaison est mg·sinθ ; la force normale est mg·cosθ. Le frottement sur un plan incliné dépend de la force normale et du coefficient de frottement.","tr":"Eğim boyunca yerçekimi bileşeni mg·sinθ; normal kuvvet mg·cosθ'dir. Eğik düzlemlerde sürtünme, normal kuvvete ve sürtünme katsayısına bağlıdır.","nl":"De component van de zwaartekracht langs het hellend vlak is mg·sinθ; de normaalkracht is mg·cosθ. Wrijving op hellende vlakken hangt af van de normaalkracht en de wrijvingscoëfficiënt.","ru":"Составляющая силы тяжести вдоль наклонной плоскости равна mg·sinθ; нормальная сила равна mg·cosθ. Трение на наклонной плоскости зависит от нормальной силы и коэффициента трения.","zh":"沿斜面方向的重力分量为 mg·sinθ；法向力为 mg·cosθ。斜面上的摩擦力取决于法向力和摩擦系数。","pt_BR":"A componente da gravidade ao longo da inclinação é mg·senθ; a força normal é mg·cosθ. O atrito em planos inclinados depende da força normal e do coeficiente de atrito.","pt_PT":"A componente da gravidade ao longo da inclinação é mg·senθ; a força normal é mg·cosθ. O atrito em planos inclinados depende da força normal e do coeficiente de atrito."}},
  { id: 'dc-physics-0135', deck_id: 'deck-physics', sort_order: 135, front: "Center of Mass", back: "x_cm = Σmᵢxᵢ/Σmᵢ. The point where the total mass of a system can be considered concentrated. External forces accelerate the center of mass as if all mass were there." , front_translations: {"es":"Centro de Masa","it":"Centre di massa","de":"Massenmittelpunkt","fr":"Centre de masse","tr":"Kütle Merkezi","nl":"Zwaartepunt","ru":"Центр масс","zh":"质心","pt_BR":"Centro de Massa","pt_PT":"Centro de Massa"}, back_translations: {"es":"x_cm = Σmᵢxᵢ/Σmᵢ. El punto donde a masa total de un sistema puede ser considerada concentrada. El centro de masa obedece a la segunda ley de Newton para todo el sistema.","it":"x_cm = Σmᵢxᵢ/Σmᵢ. Il point où la masse totale di un sistema può etre consideree come concentree. Il centre di masse obeit alla secondo loi di Newton per l'ensemble del sistema.","de":"x_cm = Σmᵢxᵢ/Σmᵢ. Der Punkt, an dem die Gesamtmasse eines Systems als konzentriert betrachtet werden kann. Der Massenmittelpunkt folgt dem zweiten Newtonschen Gesetz für das gesamte System.","fr":"x_cm = Σmᵢxᵢ/Σmᵢ. Le point où la masse totale d'un système peut être considérée comme concentrée. Le centre de masse obéit à la deuxième loi de Newton pour l'ensemble du système.","tr":"x_cm = Σmᵢxᵢ/Σmᵢ. Bir sistemin toplam kütlesinin yoğunlaşmış kabul edilebileceği nokta. Kütle merkezi, tüm sistem için Newton'un ikinci yasasına uyar.","nl":"x_cm = Σmᵢxᵢ/Σmᵢ. Het punt waar de totale massa van een systeem als geconcentreerd kan worden beschouwd. Het zwaartepunt volgt de tweede wet van Newton voor het gehele systeem.","ru":"x_cm = Σmᵢxᵢ/Σmᵢ. Точка, в которой можно считать сосредоточенной всю массу системы. Центр масс подчиняется второму закону Ньютона для всей системы.","zh":"x_cm = Σmᵢxᵢ/Σmᵢ。系统总质量可被视为集中的点。质心遵循牛顿第二定律，适用于整个系统。","pt_BR":"x_cm = Σmᵢxᵢ/Σmᵢ. O ponto onde a massa total de um sistema pode ser considerada concentrada. O centro de massa obedece à segunda lei de Newton para todo o sistema.","pt_PT":"x_cm = Σmᵢxᵢ/Σmᵢ. O ponto onde a massa total de um sistema pode ser considerada concentrada. O centro de massa obedece à segunda lei de Newton para todo o sistema."}},
  { id: 'dc-physics-0136', deck_id: 'deck-physics', sort_order: 136, front: "Rolling Without Slipping", back: "For a rolling object, v_cm = ωR and the contact point has zero velocity. Total KE = ½mv² + ½Iω². Moment of inertia determines how much energy goes into rotation." , front_translations: {"es":"Rolamento sin Deslizamento","it":"Roulemento senzha glissemento","de":"Rollen ohne Gleiten","fr":"Roulement sans glissement","tr":"Kaymadan Yuvarlanma","nl":"Rollen zonder glijden","ru":"Качение без проскальзывания","zh":"无滑动滚动","pt_BR":"Rolamento sem Deslizamento","pt_PT":"Rolamento sem Deslizamento"}, back_translations: {"es":"Para un objeto en rolamento, v_cm = ωR y el punto de contato tiene velocidad zero. EC total = ½mv² + ½Iω². La condición de rolamento conecta el movimiento translacional y rotacional.","it":"Per un objet en roulement, v_cm = ωR e il point di contact ha una vitesse nulle. EC totale = ½mv² + ½Iω². La condizione di roulement relie il mouvement di translazione e di rotazione.","de":"Für ein rollendes Objekt gilt v_cm = ωR und der Kontaktpunkt hat die Geschwindigkeit null. Gesamte KE = ½mv² + ½Iω². Die Rollbedingung verknüpft translatorische und rotatorische Bewegung.","fr":"Pour un objet en roulement, v_cm = ωR et le point de contact a une vitesse nulle. EC totale = ½mv² + ½Iω². La condition de roulement relie le mouvement de translation et de rotation.","tr":"Yuvarlanan bir cisim için v_cm = ωR ve temas noktasının hızı sıfırdır. Toplam KE = ½mv² + ½Iω². Yuvarlanma koşulu, öteleme ve dönme hareketini birbirine bağlar.","nl":"Voor een rollend voorwerp geldt v_cm = ωR en het contactpunt heeft snelheid nul. Totale KE = ½mv² + ½Iω². De rolvoorwaarde verbindt translatie- en rotatiebeweging.","ru":"Для катящегося тела v_cm = ωR, и точка контакта имеет нулевую скорость. Полная КЭ = ½mv² + ½Iω². Условие качения связывает поступательное и вращательное движение.","zh":"对于滚动物体，v_cm = ωR，接触点速度为零。总动能 = ½mv² + ½Iω²。滚动条件将平动和转动联系起来。","pt_BR":"Para um objeto em rolamento, v_cm = ωR e o ponto de contato tem velocidade zero. EC total = ½mv² + ½Iω². A condição de rolamento conecta o movimento translacional e rotacional.","pt_PT":"Para um objeto em rolamento, v_cm = ωR e o ponto de contacto tem velocidade zero. EC total = ½mv² + ½Iω². A condição de rolamento liga o movimento translacional e rotacional."}},
  { id: 'dc-physics-0137', deck_id: 'deck-physics', sort_order: 137, front: "Gyroscopic Precession", back: "A spinning gyroscope's rotation axis moves perpendicular to the applied torque, rather than tilting as expected. Explains why bicycles self-balance and how gyrocompasses work." , front_translations: {"es":"Precesión Giroscópica","it":"Precessione gyrossocopico","de":"Gyroskopische Präzession","fr":"Précession gyroscopique","tr":"Jiroskopik Presesyon","nl":"Gyroscopische precessie","ru":"Гироскопическая прецессия","zh":"陀螺进动","pt_BR":"Precessão Giroscópica","pt_PT":"Precessão Giroscópica"}, back_translations: {"es":"El eixo de rotación de un giroscópio en rotación move-se perpendicularmente al torque aplicado, traçando un cone. Taxa de precesión Ω = τ/(Iω), inversamente proporcional a la velocidad de rotación.","it":"L'axe di rotazione di un gyroscope en rotazione se deplace perpendiculairement al couple applique, trazant un conon. Il taux di precession Ω = τ/(Iω), inversement proportionnel alla vitesse di rotazione.","de":"Die Rotationsachse eines rotierenden Kreisels bewegt sich senkrecht zum angreifenden Drehmoment und beschreibt einen Kegel. Präzessionsrate Ω = τ/(Iω), umgekehrt proportional zur Drehgeschwindigkeit.","fr":"L'axe de rotation d'un gyroscope en rotation se déplace perpendiculairement au couple appliqué, traçant un cône. Le taux de précession Ω = τ/(Iω), inversement proportionnel à la vitesse de rotation.","tr":"Dönen bir jiroskobun dönme ekseni, uygulanan torka dik yönde hareket ederek bir koni çizer. Presesyon hızı Ω = τ/(Iω), dönme hızıyla ters orantılıdır.","nl":"De rotatieas van een draaiende gyroscoop beweegt loodrecht op het uitgeoefende koppel en beschrijft een kegel. Precessiesnelheid Ω = τ/(Iω), omgekeerd evenredig met de draaisnelheid.","ru":"Ось вращения вращающегося гироскопа движется перпендикулярно приложенному моменту, описывая конус. Скорость прецессии Ω = τ/(Iω), обратно пропорциональна скорости вращения.","zh":"旋转陀螺仪的转轴沿垂直于外加力矩的方向运动，描绘出一个锥形。进动速率 Ω = τ/(Iω)，与自转速度成反比。","pt_BR":"O eixo de rotação de um giroscópio em rotação move-se perpendicularmente ao torque aplicado, traçando um cone. Taxa de precessão Ω = τ/(Iω), inversamente proporcional à velocidade de rotação.","pt_PT":"O eixo de rotação de um giroscópio em rotação move-se perpendicularmente ao momento de força aplicado, traçando um cone. Taxa de precessão Ω = τ/(Iω), inversamente proporcional à velocidade de rotação."}},
  { id: 'dc-physics-0138', deck_id: 'deck-physics', sort_order: 138, front: "Mach Number", back: "Ma = v/v_sound. The ratio of an object's speed to the local speed of sound. Ma < 1 is subsonic; Ma > 1 is supersonic. v_sound ≈ 343 m/s in air at 20°C." , front_translations: {"es":"Número de Mach","it":"Nombre di Mach","de":"Mach-Zahl","fr":"Nombre de Mach","tr":"Mach Sayısı","nl":"Machgetal","ru":"Число Маха","zh":"马赫数","pt_BR":"Número de Mach","pt_PT":"Número de Mach"}, back_translations: {"es":"Ma = v/v_sonido. La razão entre a velocidad de un objeto y a velocidad local del sonido. Ma < 1 subsonico, Ma = 1 transonico, Ma > 1 supersonico, Ma > 5 hipersonico.","it":"Ma = v/v_son. Il rapport tra la vitesse di un objet e la vitesse locale del il suo. Ma < 1 subsonico, Ma = 1 transsonico, Ma > 1 supersonico, Ma > 5 hypersonico.","de":"Ma = v/v_Schall. Das Verhältnis der Geschwindigkeit eines Objekts zur lokalen Schallgeschwindigkeit. Ma < 1 Unterschall, Ma = 1 transsonisch, Ma > 1 Überschall, Ma > 5 Hyperschall.","fr":"Ma = v/v_son. Le rapport entre la vitesse d'un objet et la vitesse locale du son. Ma < 1 subsonique, Ma = 1 transsonique, Ma > 1 supersonique, Ma > 5 hypersonique.","tr":"Ma = v/v_ses. Bir cismin hızının yerel ses hızına oranı. Ma < 1 sesaltı, Ma = 1 transonik, Ma > 1 sesüstü, Ma > 5 hipersonik.","nl":"Ma = v/v_geluid. De verhouding van de snelheid van een object tot de lokale geluidssnelheid. Ma < 1 subsonisch, Ma = 1 transsonisch, Ma > 1 supersonisch, Ma > 5 hypersonisch.","ru":"Ma = v/v_звука. Отношение скорости объекта к местной скорости звука. Ma < 1 — дозвуковая, Ma = 1 — трансзвуковая, Ma > 1 — сверхзвуковая, Ma > 5 — гиперзвуковая.","zh":"Ma = v/v_声音。物体速度与当地声速的比值。Ma < 1 亚音速，Ma = 1 跨音速，Ma > 1 超音速，Ma > 5 高超音速。","pt_BR":"Ma = v/v_som. A razão entre a velocidade de um objeto e a velocidade local do som. Ma < 1 subsônico, Ma = 1 transônico, Ma > 1 supersônico, Ma > 5 hipersônico.","pt_PT":"Ma = v/v_som. A razão entre a velocidade de um objeto e a velocidade local do som. Ma < 1 subsónico, Ma = 1 transónico, Ma > 1 supersónico, Ma > 5 hipersónico."}},
  { id: 'dc-physics-0139', deck_id: 'deck-physics', sort_order: 139, front: "Shock Wave", back: "Formed when an object exceeds the speed of sound, creating a conical pressure wave. Heard as a sonic boom. The half-angle of the cone is arcsin(1/Ma)." , front_translations: {"es":"Onda de Choque","it":"Onde di choc","de":"Stoßwelle","fr":"Onde de choc","tr":"Şok Dalgası","nl":"Schokgolf","ru":"Ударная волна","zh":"激波","pt_BR":"Onda de Choque","pt_PT":"Onda de Choque"}, back_translations: {"es":"Formada cuando un objeto excede a velocidad del sonido, creando una onda de presión conica. El semiangulo del cone satisfaz senθ = v_sonido/v_objeto.","it":"Formee lorsqu'un objet depasse la vitesse del il suo, creant una onde di pression conico. Il demi-angle del conon satisfait sinθ = v_son/v_objet.","de":"Entsteht, wenn ein Objekt die Schallgeschwindigkeit überschreitet und eine kegelförmige Druckwelle erzeugt. Der halbe Öffnungswinkel des Kegels erfüllt sinθ = v_Schall/v_Objekt.","fr":"Formée lorsqu'un objet dépasse la vitesse du son, créant une onde de pression conique. Le demi-angle du cône satisfait sinθ = v_son/v_objet.","tr":"Bir cisim ses hızını aştığında oluşan konik basınç dalgası. Koninin yarı açısı sinθ = v_ses/v_cisim koşulunu sağlar.","nl":"Ontstaat wanneer een object de geluidssnelheid overschrijdt en een conische drukgolf creëert. De halve hoek van de kegel voldoet aan sinθ = v_geluid/v_object.","ru":"Образуется, когда объект превышает скорость звука, создавая коническую волну давления. Половинный угол конуса удовлетворяет условию sinθ = v_звука/v_объекта.","zh":"当物体超过声速时形成锥形压力波。锥体的半角满足 sinθ = v_声音/v_物体。","pt_BR":"Formada quando um objeto excede a velocidade do som, criando uma onda de pressão cônica. O semiângulo do cone satisfaz senθ = v_som/v_objeto.","pt_PT":"Formada quando um objeto excede a velocidade do som, criando uma onda de pressão cónica. O semiângulo do cone satisfaz senθ = v_som/v_objeto."}},
  { id: 'dc-physics-0140', deck_id: 'deck-physics', sort_order: 140, front: "Dielectric Material", back: "An insulating material placed between capacitor plates that increases capacitance by a factor equal to its dielectric constant κ: C = κC₀. Reduces the electric field within the material." , front_translations: {"es":"Material Dielétrico","it":"Matàriau dielettrico","de":"Dielektrisches Material","fr":"Matériau diélectrique","tr":"Dielektrik Malzeme","nl":"Diëlektrisch materiaal","ru":"Диэлектрический материал","zh":"电介质材料","pt_BR":"Material Dielétrico","pt_PT":"Material Dielétrico"}, back_translations: {"es":"Un material isolante colocado entre las placas de un capacitor que aumenta a capacitancia por un fator κ (constante dielétrica). Ele reduce el campo eléctrico dentro del capacitor.","it":"Un materiau isolant place tra i plaques di un condensatore che augmente la capacite di un factore κ (costante dielettrico). Il reduit il champ electrico all'interiore del condensatore.","de":"Ein Isoliermaterial, das zwischen die Platten eines Kondensators eingebracht wird und die Kapazität um den Faktor κ (Dielektrizitätskonstante) erhöht. Es verringert das elektrische Feld im Kondensator.","fr":"Un matériau isolant placé entre les plaques d'un condensateur qui augmente la capacité d'un facteur κ (constante diélectrique). Il réduit le champ électrique à l'intérieur du condensateur.","tr":"Kapasitör plakaları arasına yerleştirilen ve kapasitansı κ (dielektrik sabiti) katına çıkaran yalıtkan malzeme. Kapasitör içindeki elektrik alanını azaltır.","nl":"Een isolerend materiaal dat tussen de platen van een condensator wordt geplaatst en de capaciteit met een factor κ (diëlektrische constante) verhoogt. Het vermindert het elektrische veld in de condensator.","ru":"Изолирующий материал, помещённый между обкладками конденсатора, который увеличивает ёмкость в κ раз (диэлектрическая постоянная). Он уменьшает электрическое поле внутри конденсатора.","zh":"放置在电容器极板之间的绝缘材料，使电容增大 κ 倍（介电常数）。它降低了电容器内部的电场。","pt_BR":"Um material isolante colocado entre as placas de um capacitor que aumenta a capacitância por um fator κ (constante dielétrica). Ele reduz o campo elétrico dentro do capacitor.","pt_PT":"Um material isolante colocado entre as placas de um condensador que aumenta a capacitância por um fator κ (constante dielétrica). Reduz o campo elétrico dentro do condensador."}},
  { id: 'dc-physics-0141', deck_id: 'deck-physics', sort_order: 141, front: "RC Circuit Time Constant", back: "τ = RC. In an RC circuit, the time constant τ is the time to charge to ~63.2% of final voltage (or discharge to ~36.8%). V(t) = V₀(1 - e^(-t/τ)) for charging." , front_translations: {"es":"Constante de Tiempo del Circuito RC","it":"Costante di temps del circuito RC","de":"RC-Schaltung Zeitkonstante","fr":"Constante de temps du circuit RC","tr":"RC Devresi Zaman Sabiti","nl":"RC-circuit tijdconstante","ru":"Постоянная времени RC-цепи","zh":"RC电路时间常数","pt_BR":"Constante de Tempo do Circuito RC","pt_PT":"Constante de Tempo do Circuito RC"}, back_translations: {"es":"τ = RC. En un circuito RC, a constante de tiempo τ es el tiempo para carregar hasta ~63,2% de la tensão máxima o descarregar hasta ~36,8%. Após 5τ, el proceso está esencialmente completo.","it":"τ = RC. In un circuit RC, la costante di temps τ e il temps necessario per charger à ~63,2 % della tension maximale o se decharger à ~36,8 %. Apres 5τ, il processo e essentiellement termine.","de":"τ = RC. In einem RC-Schaltkreis ist die Zeitkonstante τ die Zeit, um auf ~63,2 % der maximalen Spannung aufzuladen oder auf ~36,8 % zu entladen. Nach 5τ ist der Vorgang im Wesentlichen abgeschlossen.","fr":"τ = RC. Dans un circuit RC, la constante de temps τ est le temps nécessaire pour charger à ~63,2 % de la tension maximale ou se décharger à ~36,8 %. Après 5τ, le processus est essentiellement terminé.","tr":"τ = RC. Bir RC devresinde zaman sabiti τ, maksimum voltajın ~%63,2'sine şarj olma veya ~%36,8'ine deşarj olma süresidir. 5τ sonra süreç esasen tamamlanır.","nl":"τ = RC. In een RC-circuit is de tijdconstante τ de tijd om op te laden tot ~63,2% van de maximale spanning of te ontladen tot ~36,8%. Na 5τ is het proces in wezen voltooid.","ru":"τ = RC. В RC-цепи постоянная времени τ — это время зарядки до ~63,2 % от максимального напряжения или разрядки до ~36,8 %. После 5τ процесс практически завершён.","zh":"τ = RC。在RC电路中，时间常数τ是充电到最大电压的约63.2%或放电到约36.8%所需的时间。经过5τ后，过程基本完成。","pt_BR":"τ = RC. Em um circuito RC, a constante de tempo τ é o tempo para carregar até ~63,2% da tensão máxima ou descarregar até ~36,8%. Após 5τ, o processo está essencialmente completo.","pt_PT":"τ = RC. Num circuito RC, a constante de tempo τ é o tempo para carregar até ~63,2% da tensão máxima ou descarregar até ~36,8%. Após 5τ, o processo está essencialmente concluído."}},
  { id: 'dc-physics-0142', deck_id: 'deck-physics', sort_order: 142, front: "Alternating Current (AC)", back: "Electric current that reverses direction periodically. Described by V(t) = V_max·sin(ωt). RMS voltage V_rms = V_max/√2. Standard household current is 50 or 60 Hz." , front_translations: {"es":"Corrente Alternada (CA)","it":"Courant alternativo (CA)","de":"Wechselstrom (AC)","fr":"Courant alternatif (CA)","tr":"Alternatif Akım (AA)","nl":"Wisselstroom (AC)","ru":"Переменный ток (AC)","zh":"交流电 (AC)","pt_BR":"Corrente Alternada (CA)","pt_PT":"Corrente Alternada (CA)"}, back_translations: {"es":"Corrente eléctrica que inverte periodicamente a dirección. Descrita por V(t) = V_máx·sen(ωt). Tensão eficaz = V_máx/√2. Usada en la distribución de energía porque transformadores pueden alterar a tensão.","it":"Courant electrico che inverse periodiquement la sua direczione. Decrit per V(t) = V_max·sin(ωt). Tension efficace = V_max/√2. Utilise in la distribuzione d'energia car i transformatori possono modifier la tension.","de":"Elektrischer Strom, der periodisch die Richtung wechselt. Beschrieben durch V(t) = V_max·sin(ωt). Effektivspannung = V_max/√2. Wird in der Stromverteilung verwendet, da Transformatoren die Spannung ändern können.","fr":"Courant électrique qui inverse périodiquement sa direction. Décrit par V(t) = V_max·sin(ωt). Tension efficace = V_max/√2. Utilisé dans la distribution d'énergie car les transformateurs peuvent modifier la tension.","tr":"Periyodik olarak yön değiştiren elektrik akımı. V(t) = V_maks·sin(ωt) ile tanımlanır. Etkin gerilim = V_maks/√2. Transformatörlerin gerilimi değiştirebilmesi nedeniyle güç dağıtımında kullanılır.","nl":"Elektrische stroom die periodiek van richting verandert. Beschreven door V(t) = V_max·sin(ωt). Effectieve spanning = V_max/√2. Gebruikt in stroomverdeling omdat transformatoren de spanning kunnen wijzigen.","ru":"Электрический ток, периодически меняющий направление. Описывается формулой V(t) = V_max·sin(ωt). Действующее напряжение = V_max/√2. Используется в электроснабжении, так как трансформаторы могут изменять напряжение.","zh":"周期性改变方向的电流。用 V(t) = V_max·sin(ωt) 描述。有效电压 = V_max/√2。用于电力输配，因为变压器可以改变电压。","pt_BR":"Corrente elétrica que inverte periodicamente a direção. Descrita por V(t) = V_máx·sen(ωt). Tensão eficaz = V_máx/√2. Usada na distribuição de energia porque transformadores podem alterar a tensão.","pt_PT":"Corrente elétrica que inverte periodicamente a direção. Descrita por V(t) = V_máx·sen(ωt). Tensão eficaz = V_máx/√2. Utilizada na distribuição de energia porque os transformadores podem alterar a tensão."}},
  { id: 'dc-physics-0143', deck_id: 'deck-physics', sort_order: 143, front: "Impedance", back: "Z = √(R² + (X_L - X_C)²). The total opposition to AC current, combining resistance and reactance. Reactance of an inductor X_L = ωL; of a capacitor X_C = 1/(ωC)." , front_translations: {"es":"Impedancia","it":"Impedanza","de":"Impedanz","fr":"Impédance","tr":"Empedans","nl":"Impedantie","ru":"Импеданс","zh":"阻抗","pt_BR":"Impedância","pt_PT":"Impedância"}, back_translations: {"es":"Z = √(R² + (X_L - X_C)²). La oposición total a la corrente alternada, combinando resistencia (R), reatancia indutiva (X_L = ωL) y reatancia capacitiva (X_C = 1/ωC).","it":"Z = √(R² + (X_L - X_C)²). L'opposizione totale al courant alternatif, combinant la resistanza (R), la reactanza inductive (X_L = ωL) e la reactanza capacitive (X_C = 1/ωC).","de":"Z = √(R² + (X_L - X_C)²). Der gesamte Widerstand gegen Wechselstrom, der ohmschen Widerstand (R), induktiven Blindwiderstand (X_L = ωL) und kapazitiven Blindwiderstand (X_C = 1/ωC) kombiniert.","fr":"Z = √(R² + (X_L - X_C)²). L'opposition totale au courant alternatif, combinant la résistance (R), la réactance inductive (X_L = ωL) et la réactance capacitive (X_C = 1/ωC).","tr":"Z = √(R² + (X_L - X_C)²). Direnci (R), indüktif reaktansı (X_L = ωL) ve kapasitif reaktansı (X_C = 1/ωC) birleştiren, alternatif akıma karşı toplam direnç.","nl":"Z = √(R² + (X_L - X_C)²). De totale weerstand tegen wisselstroom, die resistantie (R), inductieve reactantie (X_L = ωL) en capacitieve reactantie (X_C = 1/ωC) combineert.","ru":"Z = √(R² + (X_L - X_C)²). Полное сопротивление переменному току, объединяющее активное сопротивление (R), индуктивное реактивное сопротивление (X_L = ωL) и ёмкостное реактивное сопротивление (X_C = 1/ωC).","zh":"Z = √(R² + (X_L - X_C)²)。对交流电流的总阻碍，结合了电阻 (R)、感抗 (X_L = ωL) 和容抗 (X_C = 1/ωC)。","pt_BR":"Z = √(R² + (X_L - X_C)²). A oposição total à corrente alternada, combinando resistência (R), reatância indutiva (X_L = ωL) e reatância capacitiva (X_C = 1/ωC).","pt_PT":"Z = √(R² + (X_L - X_C)²). A oposição total à corrente alternada, combinando resistência (R), reatância indutiva (X_L = ωL) e reatância capacitiva (X_C = 1/ωC)."}},
  { id: 'dc-physics-0144', deck_id: 'deck-physics', sort_order: 144, front: "Coulomb (Unit)", back: "The SI unit of electric charge. One coulomb is the charge of approximately 6.24×10¹⁸ electrons. Elementary charge e = 1.602×10⁻¹⁹ C (charge of one proton or electron)." , front_translations: {"es":"Coulomb (Unidad)","it":"Coulomb (Unite)","de":"Coulomb (Einheit)","fr":"Coulomb (Unité)","tr":"Coulomb (Birim)","nl":"Coulomb (Eenheid)","ru":"Кулон (единица измерения)","zh":"库仑（单位）","pt_BR":"Coulomb (Unidade)","pt_PT":"Coulomb (Unidade)"}, back_translations: {"es":"La unidad SI de carga eléctrica. Un coulomb es a carga de aproximadamente 6,24×10¹⁸ protones. En circuitos, corrente (ampères) = coulombs por según.","it":"L'unite SI di charge electrico. Un coulomb e la charge d'environ 6,24×10¹⁸ protons. In i circuits, il courant (amperes) = coulombs per seconde.","de":"Die SI-Einheit der elektrischen Ladung. Ein Coulomb ist die Ladung von etwa 6,24×10¹⁸ Protonen. In Stromkreisen gilt: Strom (Ampere) = Coulomb pro Sekunde.","fr":"L'unité SI de charge électrique. Un coulomb est la charge d'environ 6,24×10¹⁸ protons. Dans les circuits, le courant (ampères) = coulombs par seconde.","tr":"SI elektrik yükü birimidir. Bir coulomb, yaklaşık 6,24×10¹⁸ protonun yüküdür. Devrelerde akım (amper) = saniyedeki coulomb sayısıdır.","nl":"De SI-eenheid van elektrische lading. Eén coulomb is de lading van ongeveer 6,24×10¹⁸ protonen. In circuits geldt: stroom (ampère) = coulombs per seconde.","ru":"Единица измерения электрического заряда в системе СИ. Один кулон — это заряд примерно 6,24×10¹⁸ протонов. В цепях сила тока (амперы) = кулоны в секунду.","zh":"国际单位制中的电荷单位。一库仑约等于 6.24×10¹⁸ 个质子的电荷。在电路中，电流（安培）= 库仑每秒。","pt_BR":"A unidade SI de carga elétrica. Um coulomb é a carga de aproximadamente 6,24×10¹⁸ prótons. Em circuitos, corrente (ampères) = coulombs por segundo.","pt_PT":"A unidade SI de carga elétrica. Um coulomb é a carga de aproximadamente 6,24×10¹⁸ protões. Em circuitos, corrente (amperes) = coulombs por segundo."}},
  { id: 'dc-physics-0145', deck_id: 'deck-physics', sort_order: 145, front: "Gauss's Law", back: "∮E·dA = Q_enc/ε₀. The total electric flux through a closed surface equals the enclosed charge divided by the permittivity of free space. Useful for calculating E in symmetric charge distributions." , front_translations: {"es":"Ley de Gauss","it":"Legge di Gauss","de":"Gaußsches Gesetz","fr":"Loi de Gauss","tr":"Gauss Yasası","nl":"Wet van Gauss","ru":"Закон Гаусса","zh":"高斯定律","pt_BR":"Lei de Gauss","pt_PT":"Lei de Gauss"}, back_translations: {"es":"∮Y·dA = Q_enc/ε₀. El flujo eléctrico total a través de una superficie fechada es igual a la carga encerrada dividida por la permissividad del espacio livre.","it":"∮E·dA = Q_enc/ε₀. Il flux electrico total attraverso una surface fermee e egal alla charge enfermee divisee per la permittivite del vide.","de":"∮E·dA = Q_eingeschlossen/ε₀. Der gesamte elektrische Fluss durch eine geschlossene Oberfläche ist gleich der eingeschlossenen Ladung geteilt durch die Permittivität des freien Raums.","fr":"∮E·dA = Q_enc/ε₀. Le flux électrique total à travers une surface fermée est égal à la charge enfermée divisée par la permittivité du vide.","tr":"∮E·dA = Q_iç/ε₀. Kapalı bir yüzeyden geçen toplam elektrik akısı, çevrelenen yükün serbest uzayın dielektrik geçirgenliğine bölümüne eşittir.","nl":"∮E·dA = Q_omsloten/ε₀. De totale elektrische flux door een gesloten oppervlak is gelijk aan de omsloten lading gedeeld door de permittiviteit van de vrije ruimte.","ru":"∮E·dA = Q_замкн/ε₀. Полный электрический поток через замкнутую поверхность равен заключённому заряду, делённому на диэлектрическую проницаемость вакуума.","zh":"∮E·dA = Q_内/ε₀。通过封闭曲面的总电通量等于所包围的电荷除以真空介电常数。","pt_BR":"∮E·dA = Q_enc/ε₀. O fluxo elétrico total através de uma superfície fechada é igual à carga encerrada dividida pela permissividade do espaço livre.","pt_PT":"∮E·dA = Q_enc/ε₀. O fluxo elétrico total através de uma superfície fechada é igual à carga encerrada dividida pela permitividade do espaço livre."}},
  { id: 'dc-physics-0146', deck_id: 'deck-physics', sort_order: 146, front: "Ampere's Law", back: "∮B·dl = μ₀I_enc. The line integral of B around a closed path equals the permeability of free space times the enclosed current. Useful for calculating B in symmetric current distributions." , front_translations: {"es":"Ley de Ampère","it":"Loi d'Ampere","de":"Ampèresches Gesetz","fr":"Loi d'Ampère","tr":"Ampère Yasası","nl":"Wet van Ampère","ru":"Закон Ампера","zh":"安培定律","pt_BR":"Lei de Ampère","pt_PT":"Lei de Ampère"}, back_translations: {"es":"∮B·dl = μ₀I_enc. La integral de línea de B a lo ancho de un caminho fechado es igual a la permeabilidad del espacio livre veces a corrente encerrada.","it":"∮B·dl = μ₀I_enc. L'integrale curviligne di B il long di un chemin ferme e egale alla permeabilite del vide multipliee per il courant enferme.","de":"∮B·dl = μ₀I_eingeschlossen. Das Linienintegral von B entlang eines geschlossenen Pfades ist gleich der Permeabilität des freien Raums mal dem eingeschlossenen Strom.","fr":"∮B·dl = μ₀I_enc. L'intégrale curviligne de B le long d'un chemin fermé est égale à la perméabilité du vide multipliée par le courant enfermé.","tr":"∮B·dl = μ₀I_iç. B'nin kapalı bir yol boyunca çizgisel integrali, serbest uzayın manyetik geçirgenliği çarpı çevrelenen akıma eşittir.","nl":"∮B·dl = μ₀I_omsloten. De lijnintegraal van B langs een gesloten pad is gelijk aan de permeabiliteit van de vrije ruimte maal de omsloten stroom.","ru":"∮B·dl = μ₀I_замкн. Криволинейный интеграл B по замкнутому контуру равен магнитной проницаемости вакуума, умноженной на охваченный ток.","zh":"∮B·dl = μ₀I_内。B沿闭合路径的线积分等于真空磁导率乘以所包围的电流。","pt_BR":"∮B·dl = μ₀I_enc. A integral de linha de B ao longo de um caminho fechado é igual à permeabilidade do espaço livre vezes a corrente encerrada.","pt_PT":"∮B·dl = μ₀I_enc. O integral de linha de B ao longo de um caminho fechado é igual à permeabilidade do espaço livre vezes a corrente encerrada."}},
  { id: 'dc-physics-0147', deck_id: 'deck-physics', sort_order: 147, front: "Photon Momentum", back: "p = h/λ = E/c. Although massless, photons carry momentum. This momentum causes radiation pressure and was confirmed by Compton scattering experiments." , front_translations: {"es":"Momento del Fóton","it":"Quantite di movimento del photon","de":"Photonenimpuls","fr":"Quantité de mouvement du photon","tr":"Foton Momentumu","nl":"Fotonimpuls","ru":"Импульс фотона","zh":"光子动量","pt_BR":"Momento do Fóton","pt_PT":"Momento do Fotão"}, back_translations: {"es":"p = h/λ = Y/c. Aunque sin masa, los fótons carregam momento. Esse momento causa presión de radiación y es demonstrado en el efecto Compton.","it":"p = h/λ = E/c. Bien che senza masse, i photons possedent una quantite di mouvement. Cette quantite di mouvement provoque la pression di radiazione e e demontree per l'effetto Compton.","de":"p = h/λ = E/c. Obwohl masselos, tragen Photonen einen Impuls. Dieser Impuls verursacht Strahlungsdruck und wird im Compton-Effekt nachgewiesen.","fr":"p = h/λ = E/c. Bien que sans masse, les photons possèdent une quantité de mouvement. Cette quantité de mouvement provoque la pression de radiation et est démontrée par l'effet Compton.","tr":"p = h/λ = E/c. Kütlesiz olmalarına rağmen fotonlar momentum taşır. Bu momentum, ışınım basıncına neden olur ve Compton etkisinde gösterilir.","nl":"p = h/λ = E/c. Hoewel massaloos, dragen fotonen impuls. Deze impuls veroorzaakt stralingsdruk en wordt aangetoond in het Compton-effect.","ru":"p = h/λ = E/c. Несмотря на отсутствие массы, фотоны обладают импульсом. Этот импульс вызывает давление излучения и проявляется в эффекте Комптона.","zh":"p = h/λ = E/c。虽然没有质量，光子仍然携带动量。这种动量产生辐射压力，并在康普顿效应中得到证实。","pt_BR":"p = h/λ = E/c. Embora sem massa, os fótons carregam momento. Esse momento causa pressão de radiação e é demonstrado no efeito Compton.","pt_PT":"p = h/λ = E/c. Embora sem massa, os fotões transportam momento. Este momento causa pressão de radiação e é demonstrado no efeito Compton."}},
  { id: 'dc-physics-0148', deck_id: 'deck-physics', sort_order: 148, front: "Blackbody Radiation", back: "An ideal body absorbs all incident radiation and emits a characteristic spectrum depending only on temperature. Peak wavelength: λ_max = b/T (Wien's Law), b = 2.898×10⁻³ m·K." , front_translations: {"es":"Radiación de Cuerpo Negro","it":"Rayonnemento del corps noir","de":"Schwarzkörperstrahlung","fr":"Rayonnement du corps noir","tr":"Karacisim Işıması","nl":"Zwarte-lichaamstraling","ru":"Излучение абсолютно чёрного тела","zh":"黑体辐射","pt_BR":"Radiação de Corpo Negro","pt_PT":"Radiação de Corpo Negro"}, back_translations: {"es":"Un cuerpo ideal que absorbe toda a radiación incidente y emite un espectro característico que depende solo de la temperatura. La ley de Planck descreve esse espectro y resolveu a catástrofe ultravioleta.","it":"Un corps ideal che absorbe tutto rayonnement incident e emet un spectre caracteristico dependant uniquement della temperature. La loi di Planck decrit questo spectre e ha resolu la catastrophe ultraviolette.","de":"Ein idealer Körper, der alle einfallende Strahlung absorbiert und ein charakteristisches Spektrum emittiert, das nur von der Temperatur abhängt. Das Plancksche Strahlungsgesetz beschreibt dieses Spektrum und löste die Ultraviolettkatastrophe.","fr":"Un corps idéal qui absorbe tout rayonnement incident et émet un spectre caractéristique dépendant uniquement de la température. La loi de Planck décrit ce spectre et a résolu la catastrophe ultraviolette.","tr":"Tüm gelen ışınımı absorbe eden ve yalnızca sıcaklığa bağlı karakteristik bir spektrum yayan ideal bir cisim. Planck yasası bu spektrumu tanımlar ve morötesi felaketi çözmüştür.","nl":"Een ideaal lichaam dat alle invallende straling absorbeert en een karakteristiek spectrum uitzendt dat alleen van de temperatuur afhangt. De wet van Planck beschrijft dit spectrum en loste de ultravioletcatastrofe op.","ru":"Идеальное тело, поглощающее всё падающее излучение и испускающее характерный спектр, зависящий только от температуры. Закон Планка описывает этот спектр и разрешил ультрафиолетовую катастрофу.","zh":"一种吸收所有入射辐射并发出仅取决于温度的特征光谱的理想物体。普朗克定律描述了该光谱，并解决了紫外灾变问题。","pt_BR":"Um corpo ideal que absorve toda a radiação incidente e emite um espectro característico que depende apenas da temperatura. A lei de Planck descreve esse espectro e resolveu a catástrofe ultravioleta.","pt_PT":"Um corpo ideal que absorve toda a radiação incidente e emite um espectro característico que depende apenas da temperatura. A lei de Planck descreve este espectro e resolveu a catástrofe ultravioleta."}},
  { id: 'dc-physics-0149', deck_id: 'deck-physics', sort_order: 149, front: "Stefan-Boltzmann Law", back: "P = σAT⁴. Total power radiated by a blackbody is proportional to the fourth power of its absolute temperature. σ = 5.67×10⁻⁸ W/(m²·K⁴)." , front_translations: {"es":"Ley de Stefan-Boltzmann","it":"Legge di Stefan-Boltzmann","de":"Stefan-Boltzmann-Gesetz","fr":"Loi de Stefan-Boltzmann","tr":"Stefan-Boltzmann Yasası","nl":"Wet van Stefan-Boltzmann","ru":"Закон Стефана — Больцмана","zh":"斯特藩-玻尔兹曼定律","pt_BR":"Lei de Stefan-Boltzmann","pt_PT":"Lei de Stefan-Boltzmann"}, back_translations: {"es":"P = σAT⁴. La potencia total irradiada por un cuerpo negro es proporcional a la quarta potencia de la su temperatura absoluta. σ ≈ 5,67×10⁻⁸ W/(m²·K⁴).","it":"P = σAT⁴. La puissanza totale rayonnee per un corps noir e proportionnelle alla quatrieme puissanza della sua temperature absolue. σ ≈ 5,67×10⁻⁸ W/(m²·K⁴).","de":"P = σAT⁴. Die gesamte von einem Schwarzkörper abgestrahlte Leistung ist proportional zur vierten Potenz seiner absoluten Temperatur. σ ≈ 5,67×10⁻⁸ W/(m²·K⁴).","fr":"P = σAT⁴. La puissance totale rayonnée par un corps noir est proportionnelle à la quatrième puissance de sa température absolue. σ ≈ 5,67×10⁻⁸ W/(m²·K⁴).","tr":"P = σAT⁴. Bir karacisim tarafından yayılan toplam güç, mutlak sıcaklığının dördüncü kuvvetiyle orantılıdır. σ ≈ 5,67×10⁻⁸ W/(m²·K⁴).","nl":"P = σAT⁴. Het totale vermogen uitgestraald door een zwart lichaam is evenredig met de vierde macht van zijn absolute temperatuur. σ ≈ 5,67×10⁻⁸ W/(m²·K⁴).","ru":"P = σAT⁴. Полная мощность излучения абсолютно чёрного тела пропорциональна четвёртой степени его абсолютной температуры. σ ≈ 5,67×10⁻⁸ Вт/(м²·К⁴).","zh":"P = σAT⁴。黑体辐射的总功率与其绝对温度的四次方成正比。σ ≈ 5.67×10⁻⁸ W/(m²·K⁴)。","pt_BR":"P = σAT⁴. A potência total irradiada por um corpo negro é proporcional à quarta potência da sua temperatura absoluta. σ ≈ 5,67×10⁻⁸ W/(m²·K⁴).","pt_PT":"P = σAT⁴. A potência total irradiada por um corpo negro é proporcional à quarta potência da sua temperatura absoluta. σ ≈ 5,67×10⁻⁸ W/(m²·K⁴)."}},
  { id: 'dc-physics-0150', deck_id: 'deck-physics', sort_order: 150, front: "Hubble's Law", back: "v = H₀d. Distant galaxies recede from us at a speed proportional to their distance. H₀ ≈ 70 km/s/Mpc. Key evidence for the expanding universe and the Big Bang model." , front_translations: {"es":"Ley de Hubble","it":"Legge di Hubble","de":"Hubble-Gesetz","fr":"Loi de Hubble","tr":"Hubble Yasası","nl":"Wet van Hubble","ru":"Закон Хаббла","zh":"哈勃定律","pt_BR":"Lei de Hubble","pt_PT":"Lei de Hubble"}, back_translations: {"es":"v = H₀d. Galáxias distantes se afastam de nós a una velocidad proporcional a la su distancia, evidencia del universo en expansão. H₀ ≈ 70 km/s/Mpc.","it":"v = H₀d. I galaxies lointaines s'eloignent di nous à una vitesse proportionnelle al loro distanza, preuve dell'expansion dell'univers. H₀ ≈ 70 km/s/Mpc.","de":"v = H₀d. Entfernte Galaxien entfernen sich von uns mit einer Geschwindigkeit proportional zu ihrer Entfernung, ein Beleg für das expandierende Universum. H₀ ≈ 70 km/s/Mpc.","fr":"v = H₀d. Les galaxies lointaines s'éloignent de nous à une vitesse proportionnelle à leur distance, preuve de l'expansion de l'univers. H₀ ≈ 70 km/s/Mpc.","tr":"v = H₀d. Uzak galaksiler, mesafeleriyle orantılı bir hızla bizden uzaklaşır; bu, genişleyen evrenin kanıtıdır. H₀ ≈ 70 km/s/Mpc.","nl":"v = H₀d. Verre sterrenstelsels bewegen van ons weg met een snelheid evenredig aan hun afstand, bewijs voor het uitdijende heelal. H₀ ≈ 70 km/s/Mpc.","ru":"v = H₀d. Далёкие галактики удаляются от нас со скоростью, пропорциональной их расстоянию, что свидетельствует о расширении Вселенной. H₀ ≈ 70 км/с/Мпк.","zh":"v = H₀d。遥远的星系以与其距离成正比的速度远离我们，这是宇宙膨胀的证据。H₀ ≈ 70 km/s/Mpc。","pt_BR":"v = H₀d. Galáxias distantes se afastam de nós a uma velocidade proporcional à sua distância, evidência do universo em expansão. H₀ ≈ 70 km/s/Mpc.","pt_PT":"v = H₀d. Galáxias distantes afastam-se de nós a uma velocidade proporcional à sua distância, evidência do universo em expansão. H₀ ≈ 70 km/s/Mpc."}},
];
